{
  "name": "OmniPDF - AI-Powered Document Tools",
  "description": "A comprehensive suite of PDF and document management tools, featuring AI-powered summarization, OCR, and conversion capabilities.",
  "requestFramePermissions": ["camera"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import { HashRouter } from 'react-router-dom';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <HashRouter>
      <App />
    </HashRouter>
  </React.StrictMode>
);

export interface Tool {
  id: string;
  name: string;
  description: string;
  icon: React.ReactNode;
  category: 'convert' | 'optimize' | 'edit' | 'security' | 'ai';
  color: string;
}

export interface FileState {
  file: File;
  preview?: string;
  status: 'idle' | 'processing' | 'completed' | 'error';
  progress: number;
  result?: any;
}

export type ToolID = 
  | 'pdf-to-word' 
  | 'word-to-pdf' 
  | 'merge-pdf' 
  | 'split-pdf' 
  | 'compress-pdf' 
  | 'ai-summarize' 
  | 'ai-ocr' 
  | 'pdf-translate';

import { GoogleGenAI } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const summarizeDocument = async (text: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Please summarize the following document text, extracting the most important points and action items: \n\n${text}`,
    config: {
      temperature: 0.7,
      topP: 0.95,
      topK: 40,
    }
  });
  return response.text;
};

export const performOCR = async (base64Image: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: "Extract all text from this document image. Preserve formatting as much as possible." }
      ]
    }
  });
  return response.text;
};

export const translateText = async (text: string, targetLanguage: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following text to ${targetLanguage}. Maintain the tone and structure: \n\n${text}`,
  });
  return response.text;
};

import React from 'react';
import { Link } from 'react-router-dom';
import { Tool } from '../types';

interface ToolCardProps {
  tool: Tool;
}

export const ToolCard: React.FC<ToolCardProps> = ({ tool }) => {
  return (
    <Link 
      to={`/tool/${tool.id}`}
      className="group bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 flex flex-col items-center text-center relative overflow-hidden"
    >
      <div className={`mb-4 p-4 rounded-xl ${tool.color} text-white group-hover:scale-110 transition-transform duration-300`}>
        {tool.icon}
      </div>
      <h3 className="text-lg font-bold text-gray-900 mb-2">{tool.name}</h3>
      <p className="text-sm text-gray-500 line-clamp-2">{tool.description}</p>

      {/* Decorative background circle */}
      <div className={`absolute -right-4 -bottom-4 w-24 h-24 rounded-full opacity-5 group-hover:scale-150 transition-transform duration-700 ${tool.color}`} />
    </Link>
