};

import React, { useState, useCallback } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Upload, X, File as FileIcon, Loader2, Download, CheckCircle, ArrowLeft, Brain } from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText } from '../services/geminiService';

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [fileState, setFileState] = useState<FileState | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFileState({
        file: selectedFile,
        status: 'idle',
        progress: 0
      });
      setResult(null);
    }
  };

  const removeFile = () => {
    setFileState(null);
    setResult(null);
  };

  const handleProcess = async () => {
    if (!fileState) return;

    setIsProcessing(true);
    setFileState(prev => prev ? { ...prev, status: 'processing', progress: 30 } : null);

    try {
      // Small delay to simulate real work/upload
      await new Promise(r => setTimeout(r, 1000));
      setFileState(prev => prev ? { ...prev, progress: 60 } : null);

      if (id === 'ai-summarize' || id === 'ai-ocr' || id === 'pdf-translate') {
        // Since we are frontend only, we "read" file as text or dataURL
        const reader = new FileReader();

        const processAI = () => new Promise<string>((resolve, reject) => {
          reader.onload = async () => {
            const data = reader.result as string;
            try {
              if (id === 'ai-summarize') {
                // Mock text extraction for frontend demo
                const res = await summarizeDocument("Sample document text extracted from file: " + fileState.file.name + ". In a real scenario, we would use a library like pdf.js to extract actual text before sending it to Gemini.");
                resolve(res || 'No summary generated');
              } else if (id === 'ai-ocr') {
                const base64 = data.split(',')[1];
                const res = await performOCR(base64);
                resolve(res || 'No text detected');
              } else if (id === 'pdf-translate') {
                const res = await translateText("Sample text to translate.", "Spanish");
                resolve(res || 'Translation failed');
              }
            } catch (err) {
              reject(err);
            }
          };

          if (id === 'ai-ocr') {
            reader.readAsDataURL(fileState.file);
          } else {
            reader.readAsText(fileState.file);
          }
        });

        const aiResult = await processAI();
        setResult(aiResult);
      } else {
        // Mock non-AI tools (Merge, Split, etc.)
        await new Promise(r => setTimeout(r, 2000));
        setResult(`Success! Your ${tool?.name} operation is complete.`);
      }

      setFileState(prev => prev ? { ...prev, status: 'completed', progress: 100 } : null);
    } catch (error) {
      console.error(error);
      setFileState(prev => prev ? { ...prev, status: 'error', progress: 0 } : null);
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return <div>Tool not found</div>;

  return (
    <div className="max-w-5xl mx-auto px-4 py-12">
      <Link to="/" className="inline-flex items-center gap-2 text-gray-500 hover:text-red-600 transition mb-8 group">
        <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
        Back to all tools
      </Link>

      <div className="text-center mb-12">
        <div className={`inline-flex p-4 rounded-2xl ${tool.color} text-white mb-6 shadow-lg`}>
          {tool.icon}
        </div>
        <h1 className="text-4xl font-bold text-gray-900 mb-4">{tool.name}</h1>
        <p className="text-lg text-gray-500 max-w-2xl mx-auto">{tool.description}</p>
      </div>

      <div className="bg-white rounded-3xl border-2 border-dashed border-gray-200 p-8 md:p-16 transition-all">
        {!fileState ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group">
              <div className="bg-gray-50 p-8 rounded-full mb-6 group-hover:bg-red-50 transition-colors">
                <Upload className="w-12 h-12 text-gray-400 group-hover:text-red-500 transition-colors" />
              </div>
              <span className="bg-red-600 text-white px-8 py-4 rounded-full font-bold text-lg hover:bg-red-700 transition shadow-lg inline-block">
                Select PDF files
              </span>
              <input type="file" className="hidden" onChange={handleFileChange} accept={id === 'ai-ocr' ? "image/*, application/pdf" : ".pdf"} />
            </label>
            <p className="mt-4 text-gray-400 font-medium">or drop files here</p>
          </div>
        ) : (
          <div className="max-w-md mx-auto">
            <div className="bg-gray-50 rounded-2xl p-6 relative border border-gray-100 shadow-sm flex items-center gap-4">
              <div className="bg-red-100 p-3 rounded-xl text-red-600">
                <FileIcon />
              </div>
              <div className="flex-grow min-w-0">
                <p className="font-semibold text-gray-900 truncate">{fileState.file.name}</p>
                <p className="text-xs text-gray-400">{(fileState.file.size / 1024 / 1024).toFixed(2)} MB</p>
              </div>
              <button onClick={removeFile} className="text-gray-400 hover:text-red-600 p-1">
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="mt-8 flex flex-col gap-4">
              {fileState.status === 'processing' && (
                <div className="space-y-2">
                  <div className="flex justify-between text-sm font-medium">
                    <span className="text-gray-600">Processing...</span>
                    <span className="text-red-600">{fileState.progress}%</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden">
                    <div 
                      className="bg-red-600 h-full transition-all duration-300" 
                      style={{ width: `${fileState.progress}%` }}
                    />
                  </div>
                </div>
              )}

              {fileState.status !== 'completed' && (
                <button
                  disabled={isProcessing}
                  onClick={handleProcess}
                  className="w-full bg-red-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-red-700 transition flex items-center justify-center gap-2 disabled:opacity-50"
                >
                  {isProcessing ? <Loader2 className="w-6 h-6 animate-spin" /> : null}
                  {isProcessing ? 'Working on it...' : tool.name.toUpperCase()}
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      {result && (
        <div className="mt-12 animate-in fade-in slide-in-from-bottom duration-500">
          <div className="bg-white rounded-3xl p-8 border border-gray-100 shadow-xl">
            <div className="flex items-center gap-3 mb-6 text-green-600 font-bold text-xl">
              <CheckCircle />
              Finished!
            </div>

            {id?.startsWith('ai-') ? (
              <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
                <div className="flex items-center gap-2 text-indigo-600 mb-4 font-semibold">
                  <Brain className="w-5 h-5" /> AI Intelligence Output
                </div>
                <div className="prose prose-sm max-w-none text-gray-700 whitespace-pre-wrap">
                  {result}
                </div>
              </div>
            ) : (
              <p className="text-gray-600 text-lg mb-8">{result}</p>
            )}

            <div className="mt-8 flex flex-col sm:flex-row gap-4">
              <button className="flex-1 bg-red-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-red-700 transition flex items-center justify-center gap-3 shadow-lg">
                <Download className="w-6 h-6" />
                Download File
              </button>
              <button 
                onClick={removeFile}
                className="flex-1 bg-gray-100 text-gray-700 py-4 rounded-xl font-bold text-lg hover:bg-gray-200 transition"
              >
                Start Over
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Helpful Info Section */}
      <section className="mt-24 grid md:grid-cols-3 gap-8">
        <div className="bg-white p-6 rounded-2xl border border-gray-100">
          <h4 className="font-bold text-gray-900 mb-3">Secure processing</h4>
          <p className="text-sm text-gray-500">Your files are encrypted and automatically deleted from our servers after processing.</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-gray-100">
          <h4 className="font-bold text-gray-900 mb-3">AI Powered</h4>
          <p className="text-sm text-gray-500">Leverage the latest Gemini 3 Flash models for advanced document understanding and OCR.</p>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-gray-100">
          <h4 className="font-bold text-gray-900 mb-3">Cloud Integration</h4>
          <p className="text-sm text-gray-500">Save your processed files directly to Google Drive or Dropbox for easy access.</p>
        </div>
      </section>
    </div>
  );
};

