import React, { useState, useCallback } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Upload, X, File as FileIcon, Loader2, Download, CheckCircle, ArrowLeft, Brain, Zap, Gauge } from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText } from '../services/geminiService';

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [fileState, setFileState] = useState<FileState | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [compressionLevel, setCompressionLevel] = useState<number>(2); // 1: Extreme, 2: Recommended, 3: Less

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFileState({
        file: selectedFile,
        status: 'idle',
        progress: 0
      });
      setResult(null);
    }
  };

  const removeFile = () => {
    setFileState(null);
    setResult(null);
  };

  const handleProcess = async () => {
    if (!fileState) return;

    setIsProcessing(true);
    setFileState(prev => prev ? { ...prev, status: 'processing', progress: 30 } : null);

    try {
      // Small delay to simulate real work/upload
      await new Promise(r => setTimeout(r, 1500));
      setFileState(prev => prev ? { ...prev, progress: 70 } : null);

      if (id === 'ai-summarize' || id === 'ai-ocr' || id === 'pdf-translate') {
        const reader = new FileReader();

        const processAI = () => new Promise<string>((resolve, reject) => {
          reader.onload = async () => {
            const data = reader.result as string;
            try {
              if (id === 'ai-summarize') {
                const res = await summarizeDocument("Sample document text for summarization simulation.");
                resolve(res || 'No summary generated');
              } else if (id === 'ai-ocr') {
                const base64 = data.split(',')[1];
                const res = await performOCR(base64);
                resolve(res || 'No text detected');
              } else if (id === 'pdf-translate') {
                const res = await translateText("Sample text for translation.", "Spanish");
                resolve(res || 'Translation failed');
              }
            } catch (err) {
              reject(err);
            }
          };

          if (id === 'ai-ocr') {
            reader.readAsDataURL(fileState.file);
          } else {
            reader.readAsText(fileState.file);
          }
        });

        const aiResult = await processAI();
        setResult(aiResult);
      } else if (id === 'compress-pdf') {
        const reductionMap = { 1: '75%', 2: '40%', 3: '15%' };
        const qualityMap = { 1: 'Basic', 2: 'Good', 3: 'High' };
        setResult(`Success! Your file has been compressed by approximately ${reductionMap[compressionLevel as keyof typeof reductionMap]} while maintaining ${qualityMap[compressionLevel as keyof typeof qualityMap]} quality.`);
      } else {
        await new Promise(r => setTimeout(r, 1000));
        setResult(`Success! Your ${tool?.name} operation is complete.`);
      }

      setFileState(prev => prev ? { ...prev, status: 'completed', progress: 100 } : null);
    } catch (error) {
      console.error(error);
      setFileState(prev => prev ? { ...prev, status: 'error', progress: 0 } : null);
    } finally {
      setIsProcessing(false);
    }
  };

  const getCompressionLabel = () => {
    if (compressionLevel === 1) return { title: "Extreme Compression", desc: "Less quality, high compression" };
    if (compressionLevel === 2) return { title: "Recommended Compression", desc: "Good quality, good compression" };
    return { title: "Less Compression", desc: "High quality, less compression" };
  };

  if (!tool) return <div>Tool not found</div>;

  return (
    <div className="max-w-5xl mx-auto px-4 py-12">
      <Link to="/" className="inline-flex items-center gap-2 text-gray-500 hover:text-red-600 transition mb-8 group">
        <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
        Back to all tools
      </Link>

      <div className="text-center mb-12">
        <div className={`inline-flex p-4 rounded-2xl ${tool.color} text-white mb-6 shadow-lg`}>
          {tool.icon}
        </div>
        <h1 className="text-4xl font-bold text-gray-900 mb-4">{tool.name}</h1>
        <p className="text-lg text-gray-500 max-w-2xl mx-auto">{tool.description}</p>
      </div>

      <div className="bg-white rounded-3xl border-2 border-dashed border-gray-200 p-8 md:p-16 transition-all">
        {!fileState ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group">
              <div className="bg-gray-50 p-8 rounded-full mb-6 group-hover:bg-red-50 transition-colors">
                <Upload className="w-12 h-12 text-gray-400 group-hover:text-red-500 transition-colors" />
              </div>
              <span className="bg-red-600 text-white px-8 py-4 rounded-full font-bold text-lg hover:bg-red-700 transition shadow-lg inline-block">
                Select PDF files
              </span>
              <input type="file" className="hidden" onChange={handleFileChange} accept={id === 'ai-ocr' ? "image/*, application/pdf" : ".pdf"} />
            </label>
            <p className="mt-4 text-gray-400 font-medium">or drop files here</p>
          </div>
        ) : (
          <div className="max-w-xl mx-auto">
            <div className="bg-gray-50 rounded-2xl p-6 relative border border-gray-100 shadow-sm flex items-center gap-4 mb-8">
              <div className="bg-red-100 p-3 rounded-xl text-red-600">
                <FileIcon />
              </div>
              <div className="flex-grow min-w-0">
                <p className="font-semibold text-gray-900 truncate">{fileState.file.name}</p>
                <p className="text-xs text-gray-400">{(fileState.file.size / 1024 / 1024).toFixed(2)} MB</p>
              </div>
              <button onClick={removeFile} className="text-gray-400 hover:text-red-600 p-1" disabled={isProcessing}>
                <X className="w-5 h-5" />
              </button>
            </div>

            {/* Dynamic Slider for Compression */}
            {id === 'compress-pdf' && fileState.status === 'idle' && (
              <div className="mb-10 p-6 bg-red-50 rounded-2xl border border-red-100">
                <div className="flex items-center gap-2 text-red-700 font-bold mb-6">
                  <Gauge className="w-5 h-5" />
                  Compression Level
                </div>

                <div className="px-4">
                  <input
                    type="range"
                    min="1"
                    max="3"
                    step="1"
                    value={compressionLevel}
                    onChange={(e) => setCompressionLevel(parseInt(e.target.value))}
                    className="w-full h-2 bg-red-200 rounded-lg appearance-none cursor-pointer accent-red-600"
                  />
                  <div className="flex justify-between mt-4">
                    <div className={`text-center flex-1 transition-opacity ${compressionLevel === 1 ? 'opacity-100' : 'opacity-40'}`}>
                      <p className="text-xs font-bold text-red-800">EXTREME</p>
                    </div>
                    <div className={`text-center flex-1 transition-opacity ${compressionLevel === 2 ? 'opacity-100' : 'opacity-40'}`}>
                      <p className="text-xs font-bold text-red-800">RECOMMENDED</p>
                    </div>
                    <div className={`text-center flex-1 transition-opacity ${compressionLevel === 3 ? 'opacity-100' : 'opacity-40'}`}>
                      <p className="text-xs font-bold text-red-800">LESS</p>
                    </div>
                  </div>
                </div>

                <div className="mt-8 pt-6 border-t border-red-200 text-center">
                  <h4 className="font-bold text-red-900 text-lg">{getCompressionLabel().title}</h4>
                  <p className="text-red-700/70 text-sm">{getCompressionLabel().desc}</p>
                </div>
              </div>
            )}

            <div className="flex flex-col gap-4">
              {fileState.status === 'processing' && (
                <div className="space-y-2 mb-4">
                  <div className="flex justify-between text-sm font-medium">
                    <span className="text-gray-600">Working magic...</span>
                    <span className="text-red-600">{fileState.progress}%</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden">
                    <div 
                      className="bg-red-600 h-full transition-all duration-300" 
                      style={{ width: `${fileState.progress}%` }}
                    />
                  </div>
                </div>
              )}

              {fileState.status !== 'completed' && (
                <button
                  disabled={isProcessing}
                  onClick={handleProcess}
                  className="w-full bg-red-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-red-700 transition flex items-center justify-center gap-2 disabled:opacity-50 shadow-lg shadow-red-200"
                >
                  {isProcessing ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-5 h-5 fill-current" />}
                  {isProcessing ? 'COMPRESSING...' : `COMPRESS PDF`}
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      {result && (
        <div className="mt-12 animate-in fade-in slide-in-from-bottom duration-500">
          <div className="bg-white rounded-3xl p-8 border border-gray-100 shadow-xl">
            <div className="flex items-center gap-3 mb-6 text-green-600 font-bold text-xl">
              <CheckCircle />
              Processing Complete
            </div>

            {id?.startsWith('ai-') ? (
              <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
                <div className="flex items-center gap-2 text-indigo-600 mb-4 font-semibold">
                  <Brain className="w-5 h-5" /> AI Intelligence Output
                </div>
                <div className="prose prose-sm max-w-none text-gray-700 whitespace-pre-wrap">
                  {result}
                </div>
              </div>
            ) : (
              <p className="text-gray-600 text-lg mb-8 leading-relaxed">{result}</p>
            )}

            <div className="mt-8 flex flex-col sm:flex-row gap-4">
              <button className="flex-1 bg-red-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-red-700 transition flex items-center justify-center gap-3 shadow-lg shadow-red-100">
