              </div>
            ) : (
              <div className="bg-red-50 p-6 rounded-2xl border border-red-100 mb-8">
                <p className="text-gray-800 text-lg leading-relaxed">{result}</p>
              </div>
            )}

            <div className="flex flex-col sm:flex-row gap-4">
              <button className="flex-1 bg-red-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-red-700 transition flex items-center justify-center gap-3 shadow-lg shadow-red-100">
                <Download className="w-6 h-6" />
