import React, { useState, useCallback } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Upload, X, File as FileIcon, Loader2, Download, CheckCircle, ArrowLeft, Brain, Zap, Gauge, Globe } from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText } from '../services/geminiService';

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese", "Japanese", "Hindi", "Arabic", "Portuguese", "Russian", "Italian", "Korean", "Dutch"
];

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [fileState, setFileState] = useState<FileState | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [compressionLevel, setCompressionLevel] = useState<number>(2); // 1: Extreme, 2: Recommended, 3: Less
  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [isDragging, setIsDragging] = useState(false);

  const processSelectedFile = (selectedFile: File) => {
    // Basic validation for file types based on tool
    const isImage = selectedFile.type.startsWith('image/');
    const isPDF = selectedFile.type === 'application/pdf';

    if (id === 'ai-ocr') {
      if (!isImage && !isPDF) {
        alert("Please upload a PDF or an image for OCR.");
        return;
      }
    } else {
      if (!isPDF) {
        alert("Please upload a PDF file.");
        return;
      }
    }

    setFileState({
      file: selectedFile,
      status: 'idle',
      progress: 0
    });
    setResult(null);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      processSelectedFile(selectedFile);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);

    const droppedFile = e.dataTransfer.files?.[0];
    if (droppedFile) {
      processSelectedFile(droppedFile);
    }
  };

  const removeFile = () => {
    setFileState(null);
    setResult(null);
  };

  const formatSize = (bytes: number) => {
    return (bytes / 1024 / 1024).toFixed(2) + ' MB';
  };

  const handleProcess = async () => {
    if (!fileState) return;

    setIsProcessing(true);
    setFileState(prev => prev ? { ...prev, status: 'processing', progress: 30 } : null);

    try {
      await new Promise(r => setTimeout(r, 1500));
      setFileState(prev => prev ? { ...prev, progress: 70 } : null);

      if (id === 'ai-summarize' || id === 'ai-ocr' || id === 'pdf-translate') {
        const reader = new FileReader();

        const processAI = () => new Promise<string>((resolve, reject) => {
          reader.onload = async () => {
            const data = reader.result as string;
            try {
              if (id === 'ai-summarize') {
                const res = await summarizeDocument(`Document content from ${fileState.file.name}. This is a simulated text content for the summarization tool.`);
                resolve(res || 'No summary generated');
              } else if (id === 'ai-ocr') {
                const base64 = data.split(',')[1];
                const res = await performOCR(base64);
                resolve(res || 'No text detected');
              } else if (id === 'pdf-translate') {
                const res = await translateText(`This is the content of the document named "${fileState.file.name}". Please translate this into ${targetLanguage}.`, targetLanguage);
