          </h4>
          <p className="text-sm text-gray-500 leading-relaxed">Your files are encrypted and automatically deleted from our servers after processing.</p>
        </div>
        <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
          <h4 className="font-bold text-gray-900 mb-3 flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-blue-500" />
            Advanced Engine
          </h4>
          <p className="text-sm text-gray-500 leading-relaxed">Our engine leverages deep document understanding to maintain context and formatting.</p>
        </div>
        <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
          <h4 className="font-bold text-gray-900 mb-3 flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-green-500" />
            Cloud Integration
          </h4>
          <p className="text-sm text-gray-500 leading-relaxed">Save your processed files directly to Google Drive or Dropbox for easy access.</p>
        </div>
      </section>
    </div>
  );
