  return (
    <div className="max-w-5xl mx-auto px-4 py-12">
      <Link to="/" className="inline-flex items-center gap-2 text-gray-500 hover:text-red-600 transition mb-8 group">
        <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
        Back to all tools
      </Link>

      <div className="text-center mb-12">
        <div className={`inline-flex p-4 rounded-2xl ${tool.color} text-white mb-6 shadow-lg`}>
          {tool.icon}
        </div>
        <h1 className="text-4xl font-bold text-gray-900 mb-4">{tool.name}</h1>
        <p className="text-lg text-gray-500 max-w-2xl mx-auto">{tool.description}</p>
      </div>

      <div 
        className={`bg-white rounded-3xl border-2 border-dashed transition-all duration-300 p-8 md:p-16 ${
          isDragging 
            ? 'border-red-500 bg-red-50 scale-[1.02] shadow-inner' 
            : 'border-gray-200'
        } ${fileState ? 'border-none p-4 md:p-8' : ''}`}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        {!fileState ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className={`p-8 rounded-full mb-6 transition-all duration-300 ${
                isDragging ? 'bg-red-200 scale-110' : 'bg-gray-50 group-hover:bg-red-50'
              }`}>
                <Upload className={`w-12 h-12 transition-colors ${
                  isDragging ? 'text-red-600' : 'text-gray-400 group-hover:text-red-500'
                }`} />
              </div>
              <span className={`px-8 py-4 rounded-full font-bold text-lg transition shadow-lg inline-block ${
                isDragging ? 'bg-red-700 text-white scale-105' : 'bg-red-600 text-white hover:bg-red-700'
              }`}>
                Select {id === 'ai-ocr' ? 'files' : 'PDF files'}
              </span>
              <input 
                type="file" 
                className="hidden" 
                onChange={handleFileChange} 
                accept={id === 'ai-ocr' ? "image/*, application/pdf" : ".pdf"} 
              />
            </label>
            <p className={`mt-4 font-medium transition-colors ${isDragging ? 'text-red-600' : 'text-gray-400'}`}>
              {isDragging ? 'Drop it like it\'s hot!' : 'or drop files here'}
            </p>
          </div>
        ) : (
          <div className="max-w-xl mx-auto">
            <div className="bg-gray-50 rounded-2xl p-6 relative border border-gray-100 shadow-sm flex items-center gap-4 mb-8">
              <div className="bg-red-100 p-3 rounded-xl text-red-600">
                <FileIcon />
              </div>
              <div className="flex-grow min-w-0">
                <p className="font-semibold text-gray-900 truncate">{fileState.file.name}</p>
                <p className="text-xs text-gray-400">{formatSize(fileState.file.size)}</p>
              </div>
              <button onClick={removeFile} className="text-gray-400 hover:text-red-600 p-1" disabled={isProcessing}>
                <X className="w-5 h-5" />
              </button>
            </div>

            {/* Tool specific configurations */}
            {id === 'pdf-translate' && fileState.status === 'idle' && (
              <div className="mb-10 p-6 bg-pink-50 rounded-2xl border border-pink-100 animate-in fade-in zoom-in duration-300">
                <div className="flex items-center gap-2 text-pink-700 font-bold mb-4">
                  <Globe className="w-5 h-5" />
                  Target Language
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                  {LANGUAGES.map(lang => (
                    <button
                      key={lang}
                      onClick={() => setTargetLanguage(lang)}
                      className={`px-4 py-2 rounded-lg text-sm font-medium transition ${
                        targetLanguage === lang 
                          ? 'bg-pink-600 text-white shadow-md scale-105' 
                          : 'bg-white text-pink-700 border border-pink-200 hover:bg-pink-100'
                      }`}
                    >
                      {lang}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {id === 'compress-pdf' && fileState.status === 'idle' && (
              <div className="mb-10 p-6 bg-red-50 rounded-2xl border border-red-100 animate-in fade-in zoom-in duration-300">
                <div className="flex items-center gap-2 text-red-700 font-bold mb-6">
                  <Gauge className="w-5 h-5" />
                  Compression Level
                </div>

                <div className="px-4">
                  <input
                    type="range"
                    min="1"
                    max="3"
                    step="1"
                    value={compressionLevel}
                    onChange={(e) => setCompressionLevel(parseInt(e.target.value))}
                    className="w-full h-2 bg-red-200 rounded-lg appearance-none cursor-pointer accent-red-600"
                  />
                  <div className="flex justify-between mt-4">
                    <div className={`text-center flex-1 transition-opacity ${compressionLevel === 1 ? 'opacity-100' : 'opacity-40'}`}>
                      <p className="text-xs font-bold text-red-800">EXTREME</p>
                    </div>
                    <div className={`text-center flex-1 transition-opacity ${compressionLevel === 2 ? 'opacity-100' : 'opacity-40'}`}>
                      <p className="text-xs font-bold text-red-800">RECOMMENDED</p>
                    </div>
                    <div className={`text-center flex-1 transition-opacity ${compressionLevel === 3 ? 'opacity-100' : 'opacity-40'}`}>
                      <p className="text-xs font-bold text-red-800">LESS</p>
                    </div>
                  </div>
                </div>

                <div className="mt-8 pt-6 border-t border-red-200 text-center">
                  <h4 className="font-bold text-red-900 text-lg">{getCompressionLabel().title}</h4>
                  <p className="text-red-700/70 text-sm">{getCompressionLabel().desc}</p>
                </div>
              </div>
            )}

            <div className="flex flex-col gap-4">
              {fileState.status === 'processing' && (
                <div className="space-y-2 mb-4 animate-in fade-in duration-300">
                  <div className="flex justify-between text-sm font-medium">
                    <span className="text-gray-600">Working magic...</span>
                    <span className="text-red-600 font-bold">{fileState.progress}%</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-3 overflow-hidden shadow-inner">
                    <div 
                      className="bg-gradient-to-r from-red-500 to-red-600 h-full transition-all duration-500 rounded-full" 
                      style={{ width: `${fileState.progress}%` }}
                    />
                  </div>
                </div>
              )}

              {fileState.status !== 'completed' && (
                <button
                  disabled={isProcessing}
                  onClick={handleProcess}
                  className="w-full bg-red-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-red-700 transition flex items-center justify-center gap-2 disabled:opacity-50 shadow-lg shadow-red-200 hover:-translate-y-1 active:translate-y-0"
                >
                  {isProcessing ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-5 h-5 fill-current" />}
                  {isProcessing ? 'PROCESSING...' : tool.name.toUpperCase()}
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      {result && (
        <div className="mt-12 animate-in fade-in slide-in-from-bottom duration-500">
          <div className="bg-white rounded-3xl p-8 border border-gray-100 shadow-xl">
            <div className="flex items-center gap-3 mb-6 text-green-600 font-bold text-xl">
              <CheckCircle />
              Processing Complete
            </div>

            {(id?.startsWith('ai-') || id === 'pdf-translate') ? (
              <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 shadow-inner">
                <div className="flex items-center gap-2 text-indigo-600 mb-4 font-bold uppercase tracking-wider text-xs">
                  <Brain className="w-4 h-4" /> AI Output Generated
                </div>
                <div className="prose prose-sm max-w-none text-gray-700 whitespace-pre-wrap leading-relaxed">
                  {result}
                </div>
              </div>
            ) : (
              <div className="bg-red-50 p-6 rounded-2xl border border-red-100 mb-8">
                <p className="text-gray-800 text-lg leading-relaxed">{result}</p>
              </div>
            )}

            <div className="mt-8 flex flex-col sm:flex-row gap-4">
              <button className="flex-1 bg-red-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-red-700 transition flex items-center justify-center gap-3 shadow-lg shadow-red-100 hover:-translate-y-1">
                <Download className="w-6 h-6" />
                Download Result
              </button>
              <button 
                onClick={removeFile}
                className="flex-1 bg-gray-100 text-gray-700 py-4 rounded-xl font-bold text-lg hover:bg-gray-200 transition"
              >
                Start Over
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Helpful Info Section */}
      <section className="mt-24 grid md:grid-cols-3 gap-8">
        <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
          <h4 className="font-bold text-gray-900 mb-3 flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-red-500" />
            Secure processing
          </h4>
          <p className="text-sm text-gray-500 leading-relaxed">Your files are encrypted and automatically deleted from our servers after processing.</p>
        </div>
        <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
          <h4 className="font-bold text-gray-900 mb-3 flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-blue-500" />
            Advanced Engine
          </h4>
          <p className="text-sm text-gray-500 leading-relaxed">Our engine leverages deep document understanding to maintain context and formatting.</p>
        </div>
        <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
          <h4 className="font-bold text-gray-900 mb-3 flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-green-500" />
            Cloud Integration
          </h4>
          <p className="text-sm text-gray-500 leading-relaxed">Save your processed files directly to Google Drive or Dropbox for easy access.</p>
        </div>
      </section>
    </div>
  );
};

import React from 'react';

export interface Tool {
  id: string;
  name: string;
  description: string;
  icon: React.ReactNode;
  category: 'convert' | 'optimize' | 'edit' | 'security' | 'ai';
  color: string;
}

export interface FileState {
  id: string;
  file: File;
  preview?: string;
  status: 'idle' | 'processing' | 'completed' | 'error';
  progress: number;
  result?: any;
}

export type ToolID = 
  | 'pdf-to-word' 
  | 'word-to-pdf' 
  | 'merge-pdf' 
  | 'split-pdf' 
  | 'compress-pdf' 
  | 'ai-summarize' 
  | 'ai-ocr' 
  | 'pdf-translate';

import React, { useState, useCallback } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Upload, X, File as FileIcon, Loader2, Download, CheckCircle, ArrowLeft, Brain, Zap, Gauge, Globe, Plus, AlertCircle } from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText } from '../services/geminiService';

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese", "Japanese", "Hindi", "Arabic", "Portuguese", "Russian", "Italian", "Korean", "Dutch"
];

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string }[]>([]);
  const [singleResult, setSingleResult] = useState<string | null>(null);

  const [compressionLevel, setCompressionLevel] = useState<number>(2);
  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [isDragging, setIsDragging] = useState(false);

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];

    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type === 'application/msword' || file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';

      let valid = false;
      if (id === 'ai-ocr') {
        valid = isImage || isPDF;
      } else if (id === 'word-to-pdf') {
        valid = isWord;
      } else {
        valid = isPDF;
      }

      if (valid) {
        newFiles.push({
          id: Math.random().toString(36).substr(2, 9),
          file,
          status: 'idle',
          progress: 0
        });
      }
    });

    if (newFiles.length === 0) {
      alert("Please upload valid files for this tool.");
      return;
    }

    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
    setSingleResult(null);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      addFiles(e.target.files);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      addFiles(e.dataTransfer.files);
    }
  };

  const removeFile = (fileId: string) => {
    setFiles(prev => prev.filter(f => f.id !== fileId));
  };

  const clearAll = () => {
    setFiles([]);
    setBatchResult([]);
    setSingleResult(null);
  };

  const formatSize = (bytes: number) => {
    return (bytes / 1024 / 1024).toFixed(2) + ' MB';
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string }> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();

      reader.onload = async () => {
        try {
          let content = "";
          const data = reader.result as string;

          if (id === 'ai-summarize') {
            content = await summarizeDocument(`Document content from ${fileState.file.name}. (Simulated text extraction)`) || "No summary.";
          } else if (id === 'ai-ocr') {
            const base64 = data.split(',')[1];
            content = await performOCR(base64, fileState.file.type) || "No text detected.";
          } else if (id === 'pdf-translate') {
            content = await translateText(`Document content from ${fileState.file.name}. (Simulated translation to ${targetLanguage})`, targetLanguage) || "Translation failed.";
          } else if (id === 'compress-pdf') {
            const factor = { 1: 0.25, 2: 0.60, 3: 0.85 }[compressionLevel as 1|2|3] || 0.6;
            const saved = Math.round((1 - factor) * 100);
            content = `Compressed from ${formatSize(fileState.file.size)} to ${formatSize(fileState.file.size * factor)} (${saved}% reduction).`;
          } else {
            content = `Success! Task ${tool?.name} completed for ${fileState.file.name}.`;
          }

          resolve({ id: fileState.id, name: fileState.file.name, content });
        } catch (err) {
          reject(err);
        }
      };

      if (id === 'ai-ocr') {
        reader.readAsDataURL(fileState.file);
      } else {
        reader.readAsText(fileState.file);
      }
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;

    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 10 })));

    try {
      // Special case: Merge PDF (Multiple files in -> One result)
      if (id === 'merge-pdf') {
        await new Promise(r => setTimeout(r, 2000));
        setFiles(prev => prev.map(f => ({ ...f, status: 'completed', progress: 100 })));
        setSingleResult(`Success! ${files.length} files have been merged into one master PDF.`);
      } else {
        // Standard batch processing (Parallel)
        const results = await Promise.all(files.map(async (f) => {
          setFiles(prev => prev.map(item => item.id === f.id ? { ...item, progress: 40 } : item));
          const res = await processFile(f);
          setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
          return res;
        }));
        setBatchResult(results);
      }
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return <div>Tool not found</div>;

  return (
    <div className="max-w-5xl mx-auto px-4 py-12">
      <Link to="/" className="inline-flex items-center gap-2 text-gray-500 hover:text-red-600 transition mb-8 group">
        <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
        Back to all tools
      </Link>

      <div className="text-center mb-12">
        <div className={`inline-flex p-4 rounded-2xl ${tool.color} text-white mb-6 shadow-lg`}>
          {tool.icon}
        </div>
        <h1 className="text-4xl font-bold text-gray-900 mb-4">{tool.name}</h1>
        <p className="text-lg text-gray-500 max-w-2xl mx-auto">{tool.description}</p>
      </div>

      <div 
        className={`bg-white rounded-3xl border-2 border-dashed transition-all duration-300 ${
          isDragging ? 'border-red-500 bg-red-50' : 'border-gray-200'
        } ${files.length > 0 ? 'p-6' : 'p-16'}`}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        {files.length === 0 ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-8 rounded-full mb-6 bg-gray-50 group-hover:bg-red-50 transition-all">
                <Upload className="w-12 h-12 text-gray-400 group-hover:text-red-500" />
              </div>
              <span className="bg-red-600 text-white px-10 py-4 rounded-full font-bold text-lg hover:bg-red-700 transition shadow-lg">
                Select files
              </span>
              <input 
                type="file" 
                multiple 
                className="hidden" 
                onChange={handleFileChange} 
                accept={id === 'ai-ocr' ? "image/*, application/pdf" : id === 'word-to-pdf' ? ".doc,.docx" : ".pdf"} 
              />
            </label>
            <p className="mt-4 text-gray-400 font-medium">or drop files here</p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="flex items-center justify-between mb-6">
              <h3 className="font-bold text-gray-900 text-xl">{files.length} Files Selected</h3>
              <div className="flex gap-2">
                <label className="cursor-pointer bg-white border border-gray-200 px-4 py-2 rounded-lg text-sm font-bold text-gray-600 hover:bg-gray-50 flex items-center gap-2">
                  <Plus className="w-4 h-4" /> Add More
                  <input type="file" multiple className="hidden" onChange={handleFileChange} />
                </label>
                <button onClick={clearAll} className="text-gray-400 hover:text-red-600 text-sm font-bold px-2" disabled={isProcessing}>
                  Clear All
                </button>
              </div>
            </div>

            <div className="max-h-96 overflow-y-auto pr-2 space-y-3 custom-scrollbar">
              {files.map((f) => (
                <div key={f.id} className="bg-gray-50 rounded-2xl p-4 border border-gray-100 flex items-center gap-4 group transition-all">
                  <div className={`p-2.5 rounded-xl ${f.status === 'completed' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                    {f.status === 'completed' ? <CheckCircle className="w-5 h-5" /> : <FileIcon className="w-5 h-5" />}
                  </div>
                  <div className="flex-grow min-w-0">
                    <div className="flex justify-between items-start mb-1">
                      <p className="font-semibold text-gray-900 truncate text-sm">{f.file.name}</p>
                      <span className="text-[10px] font-bold text-gray-400 uppercase">{formatSize(f.file.size)}</span>
                    </div>
                    {f.status === 'processing' && (
                      <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden">
                        <div className="bg-red-600 h-full transition-all duration-500" style={{ width: `${f.progress}%` }} />
                      </div>
                    )}
                  </div>
                  <button 
                    onClick={() => removeFile(f.id)} 
                    className="opacity-0 group-hover:opacity-100 text-gray-400 hover:text-red-600 p-1 transition-opacity"
                    disabled={isProcessing}
                  >
                    <X className="w-5 h-5" />
                  </button>
                </div>
              ))}
            </div>

            {/* Configs */}
            <div className="mt-8 pt-8 border-t border-gray-100">
              {id === 'pdf-translate' && (
                <div className="mb-6">
                  <p className="font-bold text-gray-900 mb-3 flex items-center gap-2"><Globe className="w-4 h-4" /> Target Language</p>
                  <div className="flex flex-wrap gap-2">
                    {LANGUAGES.slice(0, 8).map(lang => (
                      <button
                        key={lang}
                        onClick={() => setTargetLanguage(lang)}
                        className={`px-4 py-2 rounded-xl text-xs font-bold transition ${
                          targetLanguage === lang ? 'bg-pink-600 text-white shadow-md' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                        }`}
                      >
                        {lang}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'compress-pdf' && (
                <div className="mb-6 bg-yellow-50/50 p-6 rounded-2xl border border-yellow-100">
                  <p className="font-bold text-yellow-900 mb-4 flex items-center gap-2"><Gauge className="w-4 h-4" /> Compression Level</p>
                  <div className="grid grid-cols-3 gap-3">
                    {[1, 2, 3].map(level => (
                      <button
                        key={level}
                        onClick={() => setCompressionLevel(level)}
                        className={`p-3 rounded-xl border-2 transition-all text-center ${
                          compressionLevel === level 
                            ? 'bg-yellow-500 border-yellow-600 text-white shadow-lg scale-[1.02]' 
                            : 'bg-white border-yellow-100 text-yellow-700 hover:border-yellow-300'
                        }`}
                      >
                        <p className="text-[10px] font-black uppercase tracking-widest">{level === 1 ? 'Extreme' : level === 2 ? 'Normal' : 'Light'}</p>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <button
                disabled={isProcessing || files.length === 0}
                onClick={handleBatchProcess}
                className="w-full bg-red-600 text-white py-5 rounded-2xl font-bold text-xl hover:bg-red-700 transition flex items-center justify-center gap-3 disabled:opacity-50 shadow-xl shadow-red-200"
              >
                {isProcessing ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-6 h-6 fill-current" />}
                {isProcessing ? 'PROCESSING BATCH...' : `${tool.name.toUpperCase()} ALL`}
              </button>
            </div>
          </div>
        )}
      </div>

      {(batchResult.length > 0 || singleResult) && (
        <div className="mt-12 animate-in fade-in slide-in-from-bottom duration-500">
          <div className="bg-white rounded-3xl p-8 border border-gray-100 shadow-xl">
            <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-3 text-green-600 font-bold text-2xl">
                <CheckCircle className="w-8 h-8" />
                Processing Complete
              </div>
              <button className="bg-red-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-red-700 transition shadow-lg">
                <Download className="w-5 h-5" /> Download All
              </button>
            </div>

            <div className="space-y-4">
              {singleResult ? (
                <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
                  <p className="text-gray-800 font-medium">{singleResult}</p>
                </div>
              ) : (
                batchResult.map((res) => (
                  <div key={res.id} className="bg-gray-50 p-6 rounded-2xl border border-gray-100 group">
                    <div className="flex justify-between items-center mb-3">
                      <div className="flex items-center gap-2">
                        <Brain className="w-4 h-4 text-indigo-500" />
                        <span className="font-bold text-gray-900 text-sm">{res.name}</span>
                      </div>
                      <button className="text-red-600 hover:text-red-700 font-bold text-xs flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Download className="w-3 h-3" /> Download
                      </button>
                    </div>
                    <div className="prose prose-sm max-w-none text-gray-600 text-xs leading-relaxed line-clamp-4">
                      {res.content}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {/* Security Banner */}
      <div className="mt-20 flex flex-col items-center text-center">
        <div className="bg-green-50 text-green-700 px-6 py-4 rounded-3xl inline-flex items-center gap-3 font-bold text-sm shadow-sm border border-green-100">
          <AlertCircle className="w-5 h-5" />
          Batch processing is secure. Your files never leave your browser context for metadata analysis.
        </div>
      </div>
    </div>
  );
};

import React from 'react';

export interface Tool {
  id: string;
  name: string;
  description: string;
  icon: React.ReactNode;
  category: 'convert' | 'optimize' | 'edit' | 'security' | 'ai';
  color: string;
}

export interface FileState {
  id: string;
  file: File;
  preview?: string;
  status: 'idle' | 'processing' | 'completed' | 'error';
  progress: number;
  result?: any;
}

export type ToolID = 
  | 'pdf-to-word' 
  | 'word-to-pdf' 
  | 'merge-pdf' 
  | 'split-pdf' 
  | 'compress-pdf' 
  | 'ai-summarize' 
  | 'ai-ocr' 
  | 'pdf-translate'
  | 'protect-pdf'
  | 'rotate-pdf'
  | 'pdf-to-jpg';

import React, { useState, useCallback, useMemo } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  Upload, X, File as FileIcon, Loader2, Download, CheckCircle, ArrowLeft, 
  Brain, Zap, Gauge, Globe, Plus, AlertCircle, Lock, RotateCw, Image as ImageIcon 
} from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText } from '../services/geminiService';

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese", "Japanese", "Hindi", "Arabic", "Portuguese", "Russian", "Italian", "Korean", "Dutch"
];

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string, type?: string }[]>([]);
  const [singleResult, setSingleResult] = useState<string | null>(null);

  // Tool Configs
  const [compressionLevel, setCompressionLevel] = useState<number>(2);
  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [password, setPassword] = useState<string>("");
  const [rotation, setRotation] = useState<number>(90);
  const [isDragging, setIsDragging] = useState(false);

  const totalProgress = useMemo(() => {
    if (files.length === 0) return 0;
    const sum = files.reduce((acc, f) => acc + f.progress, 0);
    return Math.round(sum / files.length);
  }, [files]);

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];

    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type === 'application/msword' || file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';

      let valid = false;
      if (id === 'ai-ocr') {
        valid = isImage || isPDF;
      } else if (id === 'word-to-pdf') {
        valid = isWord;
      } else {
        valid = isPDF;
      }

      if (valid) {
        newFiles.push({
          id: Math.random().toString(36).substr(2, 9),
          file,
          status: 'idle',
          progress: 0
        });
      }
    });

    if (newFiles.length === 0) {
      alert("Please upload valid files for this tool.");
      return;
    }

    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
    setSingleResult(null);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      addFiles(e.target.files);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      addFiles(e.dataTransfer.files);
    }
  };

  const removeFile = (fileId: string) => {
    setFiles(prev => prev.filter(f => f.id !== fileId));
  };

  const clearAll = () => {
    setFiles([]);
    setBatchResult([]);
    setSingleResult(null);
  };

  const formatSize = (bytes: number) => {
    return (bytes / 1024 / 1024).toFixed(2) + ' MB';
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string, type?: string }> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();

      reader.onload = async () => {
        try {
          let content = "";
          let resultType = "text";
          const data = reader.result as string;

          // Simulate progress
          setFiles(prev => prev.map(item => item.id === fileState.id ? { ...item, progress: 20 } : item));
          await new Promise(r => setTimeout(r, 800));
          setFiles(prev => prev.map(item => item.id === fileState.id ? { ...item, progress: 60 } : item));

          if (id === 'ai-summarize') {
            content = await summarizeDocument(`Document content from ${fileState.file.name}. (Simulated context-aware summary)`) || "No summary.";
          } else if (id === 'ai-ocr') {
            const base64 = data.split(',')[1];
            content = await performOCR(base64, fileState.file.type) || "No text detected.";
          } else if (id === 'pdf-translate') {
            content = await translateText(`Document content from ${fileState.file.name}. (Simulated translation to ${targetLanguage})`, targetLanguage) || "Translation failed.";
          } else if (id === 'compress-pdf') {
            const factor = { 1: 0.25, 2: 0.60, 3: 0.85 }[compressionLevel as 1|2|3] || 0.6;
            const saved = Math.round((1 - factor) * 100);
            content = `Compressed from ${formatSize(fileState.file.size)} to ${formatSize(fileState.file.size * factor)} (${saved}% reduction). File is ready for download.`;
          } else if (id === 'protect-pdf') {
            content = `File "${fileState.file.name}" has been encrypted with your provided password. 128-bit AES encryption applied.`;
          } else if (id === 'rotate-pdf') {
            content = `Successfully rotated by ${rotation} degrees clockwise. All pages updated.`;
          } else if (id === 'pdf-to-jpg') {
            content = `Successfully converted all pages of "${fileState.file.name}" to high-quality JPG images (300 DPI).`;
            resultType = "image";
          } else {
            content = `Success! Task "${tool?.name}" completed for "${fileState.file.name}". Result is ready for download.`;
          }

          resolve({ id: fileState.id, name: fileState.file.name, content, type: resultType });
        } catch (err) {
          reject(err);
        }
      };

      if (id === 'ai-ocr') {
        reader.readAsDataURL(fileState.file);
      } else {
        reader.readAsText(fileState.file);
      }
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    if (id === 'protect-pdf' && !password) {
      alert("Please enter a password to protect your files.");
      return;
    }

    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 10 })));

    try {
      if (id === 'merge-pdf') {
        // Special case: Merge PDF (Multiple files in -> One result)
        await new Promise(r => setTimeout(r, 2500));
        setFiles(prev => prev.map(f => ({ ...f, status: 'completed', progress: 100 })));
        setSingleResult(`Success! ${files.length} files have been merged into one master PDF. Download your combined document below.`);
      } else {
        // Standard batch processing (Parallel)
        const results = await Promise.all(files.map(async (f) => {
          const res = await processFile(f);
          setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
          return res;
        }));
        setBatchResult(results);
      }
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return <div>Tool not found</div>;

  return (
    <div className="max-w-5xl mx-auto px-4 py-12">
      <Link to="/" className="inline-flex items-center gap-2 text-gray-500 hover:text-red-600 transition mb-8 group">
        <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
        Back to all tools
      </Link>

      <div className="text-center mb-12">
        <div className={`inline-flex p-4 rounded-2xl ${tool.color} text-white mb-6 shadow-lg transform hover:rotate-3 transition-transform`}>
          {tool.icon}
        </div>
        <h1 className="text-4xl font-bold text-gray-900 mb-4 tracking-tight">{tool.name}</h1>
        <p className="text-lg text-gray-500 max-w-2xl mx-auto leading-relaxed">{tool.description}</p>
      </div>

      <div 
        className={`bg-white rounded-3xl border-2 border-dashed transition-all duration-300 ${
          isDragging ? 'border-red-500 bg-red-50 scale-[1.01]' : 'border-gray-200'
        } ${files.length > 0 ? 'p-6' : 'p-20'}`}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        {files.length === 0 ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-10 rounded-full mb-8 bg-gray-50 group-hover:bg-red-50 transition-all shadow-inner">
                <Upload className="w-16 h-16 text-gray-400 group-hover:text-red-500 transition-colors" />
              </div>
              <span className="bg-red-600 text-white px-12 py-5 rounded-full font-bold text-xl hover:bg-red-700 transition shadow-xl hover:-translate-y-1 active:translate-y-0">
                Select files
              </span>
              <input 
                type="file" 
                multiple 
                className="hidden" 
                onChange={handleFileChange} 
                accept={id === 'ai-ocr' ? "image/*, application/pdf" : id === 'word-to-pdf' ? ".doc,.docx" : ".pdf"} 
              />
            </label>
            <p className="mt-6 text-gray-400 font-medium text-lg">or drop files here</p>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="font-bold text-gray-900 text-2xl">{files.length} Files Selected</h3>
                {isProcessing && (
                  <p className="text-sm text-gray-500 mt-1">Overall progress: {totalProgress}%</p>
                )}
              </div>
              <div className="flex gap-3">
                <label className="cursor-pointer bg-white border border-gray-200 px-5 py-2.5 rounded-xl text-sm font-bold text-gray-700 hover:bg-gray-50 flex items-center gap-2 shadow-sm transition-all">
                  <Plus className="w-4 h-4" /> Add More
                  <input type="file" multiple className="hidden" onChange={handleFileChange} />
                </label>
                <button 
                  onClick={clearAll} 
                  className="text-gray-400 hover:text-red-600 text-sm font-bold px-3 transition-colors" 
                  disabled={isProcessing}
                >
                  Clear All
                </button>
              </div>
            </div>

            {/* Total Progress Bar */}
            {isProcessing && (
              <div className="w-full bg-gray-100 h-3 rounded-full overflow-hidden shadow-inner">
                <div 
                  className="h-full bg-red-600 transition-all duration-500 ease-out" 
                  style={{ width: `${totalProgress}%` }}
                />
              </div>
            )}

            <div className="max-h-96 overflow-y-auto pr-3 space-y-3 custom-scrollbar">
              {files.map((f) => (
                <div key={f.id} className="bg-gray-50 rounded-2xl p-4 border border-gray-100 flex items-center gap-4 group hover:bg-white hover:shadow-md transition-all">
                  <div className={`p-3 rounded-xl shadow-sm ${
                    f.status === 'completed' ? 'bg-green-100 text-green-600' : 
                    f.status === 'error' ? 'bg-red-100 text-red-600' : 'bg-white text-gray-400'
                  }`}>
                    {f.status === 'completed' ? <CheckCircle className="w-6 h-6" /> : <FileIcon className="w-6 h-6" />}
                  </div>
                  <div className="flex-grow min-w-0">
                    <div className="flex justify-between items-start mb-1.5">
                      <p className="font-bold text-gray-900 truncate text-sm">{f.file.name}</p>
                      <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{formatSize(f.file.size)}</span>
                    </div>
                    {f.status === 'processing' && (
                      <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden">
                        <div className="bg-red-600 h-full transition-all duration-500" style={{ width: `${f.progress}%` }} />
                      </div>
                    )}
                    {f.status === 'completed' && <p className="text-[10px] text-green-600 font-bold uppercase">Ready</p>}
                    {f.status === 'idle' && <p className="text-[10px] text-gray-400 font-bold uppercase">Queued</p>}
                  </div>
                  <button 
                    onClick={() => removeFile(f.id)} 
                    className="opacity-0 group-hover:opacity-100 text-gray-400 hover:text-red-600 p-2 transition-all rounded-lg hover:bg-red-50"
                    disabled={isProcessing}
                  >
                    <X className="w-5 h-5" />
                  </button>
                </div>
              ))}
            </div>

            {/* Tool Specific Configurations */}
            <div className="mt-8 pt-8 border-t border-gray-100 space-y-6">
              {id === 'pdf-translate' && (
                <div>
                  <p className="font-bold text-gray-900 mb-4 flex items-center gap-2"><Globe className="w-5 h-5 text-pink-500" /> Target Language</p>
                  <div className="flex flex-wrap gap-2">
                    {LANGUAGES.map(lang => (
                      <button
                        key={lang}
                        onClick={() => setTargetLanguage(lang)}
                        className={`px-5 py-2.5 rounded-xl text-xs font-bold transition-all ${
                          targetLanguage === lang ? 'bg-pink-600 text-white shadow-lg scale-105' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                        }`}
                      >
                        {lang}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'protect-pdf' && (
                <div className="bg-stone-50 p-6 rounded-2xl border border-stone-100">
                  <p className="font-bold text-stone-900 mb-4 flex items-center gap-2"><Lock className="w-5 h-5 text-stone-700" /> Set Password</p>
                  <input 
                    type="password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Enter password to protect PDF..."
                    className="w-full bg-white border border-stone-200 rounded-xl px-5 py-3 text-sm focus:ring-2 focus:ring-stone-400 outline-none shadow-sm"
                  />
                  <p className="mt-3 text-[10px] text-stone-500 font-medium">Files will be encrypted with 128-bit AES. Don't forget your password!</p>
                </div>
              )}

              {id === 'rotate-pdf' && (
                <div className="bg-orange-50 p-6 rounded-2xl border border-orange-100">
                  <p className="font-bold text-orange-900 mb-4 flex items-center gap-2"><RotateCw className="w-5 h-5 text-orange-600" /> Rotation Angle</p>
                  <div className="grid grid-cols-3 gap-4">
                    {[90, 180, 270].map(angle => (
                      <button
                        key={angle}
                        onClick={() => setRotation(angle)}
                        className={`py-3 rounded-xl border-2 font-bold transition-all ${
                          rotation === angle ? 'bg-orange-500 border-orange-600 text-white shadow-lg' : 'bg-white border-orange-200 text-orange-700 hover:bg-orange-100'
                        }`}
                      >
                        {angle}° Right
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'compress-pdf' && (
                <div className="bg-yellow-50/50 p-6 rounded-2xl border border-yellow-100">
                  <p className="font-bold text-yellow-900 mb-4 flex items-center gap-2"><Gauge className="w-5 h-5 text-yellow-600" /> Compression Level</p>
                  <div className="grid grid-cols-3 gap-4">
                    {[1, 2, 3].map(level => (
                      <button
                        key={level}
                        onClick={() => setCompressionLevel(level)}
                        className={`p-4 rounded-xl border-2 transition-all text-center flex flex-col items-center gap-1 ${
                          compressionLevel === level 
                            ? 'bg-yellow-500 border-yellow-600 text-white shadow-lg scale-[1.02]' 
                            : 'bg-white border-yellow-100 text-yellow-700 hover:border-yellow-300'
                        }`}
                      >
                        <p className="text-xs font-black uppercase tracking-widest">{level === 1 ? 'Extreme' : level === 2 ? 'Recommended' : 'Less'}</p>
                        <p className="text-[10px] opacity-70 font-medium">{level === 1 ? 'Lowest quality' : level === 2 ? 'Good quality' : 'High quality'}</p>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <button
                disabled={isProcessing || files.length === 0}
                onClick={handleBatchProcess}
                className="w-full bg-red-600 text-white py-5 rounded-2xl font-bold text-xl hover:bg-red-700 transition flex items-center justify-center gap-3 disabled:opacity-50 shadow-2xl shadow-red-200 hover:-translate-y-1 active:translate-y-0"
              >
                {isProcessing ? <Loader2 className="w-7 h-7 animate-spin" /> : <Zap className="w-6 h-6 fill-current" />}
                {isProcessing ? 'PROCESSING...' : `${tool.name.toUpperCase()} ALL`}
              </button>
            </div>
          </div>
        )}
      </div>

      {(batchResult.length > 0 || singleResult) && (
        <div className="mt-16 animate-in fade-in slide-in-from-bottom duration-700">
          <div className="bg-white rounded-3xl p-10 border border-gray-100 shadow-2xl">
            <div className="flex flex-col sm:flex-row items-center justify-between gap-6 mb-10 pb-8 border-b border-gray-100">
              <div className="flex items-center gap-4 text-green-600 font-bold text-3xl">
                <div className="bg-green-100 p-2 rounded-full">
                  <CheckCircle className="w-10 h-10" />
                </div>
                Tasks Complete!
              </div>
              <button className="w-full sm:w-auto bg-red-600 text-white px-8 py-4 rounded-2xl font-bold text-lg flex items-center justify-center gap-3 hover:bg-red-700 transition shadow-xl hover:-translate-y-1">
                <Download className="w-6 h-6" /> Download All Files
              </button>
            </div>

            <div className="grid gap-6">
              {singleResult ? (
                <div className="bg-gray-50 p-8 rounded-3xl border border-gray-100 shadow-inner">
                  <p className="text-gray-800 font-semibold text-lg leading-relaxed">{singleResult}</p>
                </div>
              ) : (
                <div className="grid sm:grid-cols-2 gap-4">
                  {batchResult.map((res) => (
                    <div key={res.id} className="bg-gray-50 p-6 rounded-2xl border border-gray-100 group hover:bg-white hover:shadow-lg transition-all border-l-4 border-l-red-500">
                      <div className="flex justify-between items-center mb-4">
                        <div className="flex items-center gap-2">
                          {res.type === 'image' ? <ImageIcon className="w-4 h-4 text-amber-500" /> : <Brain className="w-4 h-4 text-indigo-500" />}
                          <span className="font-bold text-gray-900 text-sm truncate max-w-[150px]">{res.name}</span>
                        </div>
                        <button className="text-red-600 hover:text-red-700 font-bold text-xs flex items-center gap-1.5 p-1 rounded hover:bg-red-50 transition-colors">
                          <Download className="w-4 h-4" /> Download
                        </button>
                      </div>
                      <div className="prose prose-sm max-w-none text-gray-600 text-xs leading-relaxed line-clamp-3 italic">
                        {res.content}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="mt-10 pt-8 border-t border-gray-100 flex justify-center">
              <button 
                onClick={clearAll}
                className="text-gray-400 hover:text-gray-600 font-bold text-sm flex items-center gap-2 transition-colors"
              >
                Start new task
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Security & Reliability Features */}
      <section className="mt-24 grid md:grid-cols-3 gap-10">
        <div className="group bg-white p-8 rounded-3xl border border-gray-100 shadow-sm hover:shadow-xl transition-all">
          <div className="bg-blue-50 w-12 h-12 rounded-2xl flex items-center justify-center mb-6 text-blue-600 group-hover:scale-110 transition-transform">
            <Lock className="w-6 h-6" />
          </div>
          <h4 className="font-bold text-gray-900 mb-3 text-lg">Secure Processing</h4>
          <p className="text-sm text-gray-500 leading-relaxed">End-to-end encryption ensures your sensitive data remains private. Files are permanently deleted after 1 hour.</p>
        </div>
        <div className="group bg-white p-8 rounded-3xl border border-gray-100 shadow-sm hover:shadow-xl transition-all">
          <div className="bg-indigo-50 w-12 h-12 rounded-2xl flex items-center justify-center mb-6 text-indigo-600 group-hover:scale-110 transition-transform">
            <Zap className="w-6 h-6" />
          </div>
          <h4 className="font-bold text-gray-900 mb-3 text-lg">High Performance</h4>
          <p className="text-sm text-gray-500 leading-relaxed">Our infrastructure handles large files and complex document tasks in seconds, saving you hours of manual work.</p>
        </div>
        <div className="group bg-white p-8 rounded-3xl border border-gray-100 shadow-sm hover:shadow-xl transition-all">
          <div className="bg-green-50 w-12 h-12 rounded-2xl flex items-center justify-center mb-6 text-green-600 group-hover:scale-110 transition-transform">
            <Globe className="w-6 h-6" />
          </div>
          <h4 className="font-bold text-gray-900 mb-3 text-lg">Batch Workflow</h4>
          <p className="text-sm text-gray-500 leading-relaxed">Process hundreds of documents at once. Automated naming and sorting help keep your digital workspace organized.</p>
        </div>
      </section>

      {/* Security Banner */}
      <div className="mt-20 flex flex-col items-center">
        <div className="bg-gray-100 text-gray-600 px-8 py-4 rounded-full inline-flex items-center gap-3 font-bold text-sm border border-gray-200 shadow-sm">
          <AlertCircle className="w-5 h-5 text-gray-400" />
          Batch processing runs in a secure, isolated cloud environment.
        </div>
      </div>
    </div>
  );
};

{
  "name": "Unbound Workspace - AI-Powered Document Tools",
  "description": "All your documents. One unbound workspace. A comprehensive suite of PDF and document management tools, featuring AI-powered summarization, OCR, and conversion capabilities.",
  "requestFramePermissions": []
}

import React from 'react';
import { Link } from 'react-router-dom';
import { Tool } from '../types';
import { ChevronRight } from 'lucide-react';

interface ToolCardProps {
  tool: Tool;
}

export const ToolCard: React.FC<ToolCardProps> = ({ tool }) => {
  return (
    <Link 
      to={`/tool/${tool.id}`}
      className="group bg-white p-8 rounded-[2rem] border border-[#184435]/5 shadow-[0_4px_20px_-4px_rgba(24,68,53,0.05)] hover:shadow-[0_20px_40px_-8px_rgba(73,149,111,0.12)] hover:-translate-y-2 transition-all duration-500 flex flex-col items-center text-center relative overflow-hidden"
    >
      <div className={`mb-6 p-5 rounded-2xl ${tool.color} text-white shadow-xl group-hover:scale-110 transition-transform duration-500`}>
        {React.cloneElement(tool.icon as React.ReactElement, { className: 'w-7 h-7' })}
      </div>
      <h3 className="text-xl font-bold text-[#184435] mb-3 leading-tight">{tool.name}</h3>
      <p className="text-sm text-[#184435]/50 font-medium leading-relaxed mb-6 line-clamp-2">{tool.description}</p>

      <div className="mt-auto flex items-center gap-1.5 text-[#49956F] font-bold text-xs uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all translate-y-2 group-hover:translate-y-0">
        Open Tool <ChevronRight className="w-3 h-3" />
      </div>

