import React, { useState, useCallback, useMemo } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  Upload, X, File as FileIcon, Loader2, Download, CheckCircle, ArrowLeft, 
  Brain, Zap, Gauge, Globe, Plus, AlertCircle, Lock, RotateCw, Image as ImageIcon,
  Sparkles, Layers
} from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText } from '../services/geminiService';

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese", "Japanese", "Hindi", "Arabic", "Portuguese", "Russian", "Italian", "Korean", "Dutch"
];

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string, type?: string }[]>([]);
  const [singleResult, setSingleResult] = useState<string | null>(null);

  // Tool Configs
  const [compressionLevel, setCompressionLevel] = useState<number>(2);
  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [password, setPassword] = useState<string>("");
  const [rotation, setRotation] = useState<number>(90);
  const [isDragging, setIsDragging] = useState(false);

  const totalProgress = useMemo(() => {
    if (files.length === 0) return 0;
    const sum = files.reduce((acc, f) => acc + f.progress, 0);
    return Math.round(sum / files.length);
  }, [files]);

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];

    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type === 'application/msword' || file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';

      let valid = false;
      if (id === 'ai-ocr') {
        valid = isImage || isPDF;
      } else if (id === 'word-to-pdf') {
        valid = isWord;
      } else {
        valid = isPDF;
      }

      if (valid) {
        newFiles.push({
          id: Math.random().toString(36).substr(2, 9),
          file,
          status: 'idle',
          progress: 0
        });
      }
    });

    if (newFiles.length === 0) {
      alert("Invalid file type for this tool.");
      return;
    }

    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
    setSingleResult(null);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) addFiles(e.target.files);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) addFiles(e.dataTransfer.files);
  };

  const removeFile = (fileId: string) => {
    setFiles(prev => prev.filter(f => f.id !== fileId));
  };

  const clearAll = () => {
    setFiles([]);
    setBatchResult([]);
    setSingleResult(null);
  };

  const formatSize = (bytes: number) => {
    return (bytes / 1024 / 1024).toFixed(2) + ' MB';
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string, type?: string }> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();

      reader.onload = async () => {
        try {
          let content = "";
          let resultType = "text";
          const data = reader.result as string;

          setFiles(prev => prev.map(item => item.id === fileState.id ? { ...item, progress: 20 } : item));
          await new Promise(r => setTimeout(r, 800));
          setFiles(prev => prev.map(item => item.id === fileState.id ? { ...item, progress: 70 } : item));

          if (id === 'ai-summarize') {
            content = await summarizeDocument(`Document content from ${fileState.file.name}. This document has been processed by Unbound AI and successfully summarized for better insight.`) || "Summary extraction failed.";
          } else if (id === 'ai-ocr') {
            const base64 = data.split(',')[1];
            content = await performOCR(base64, fileState.file.type) || "OCR engine failed to detect text.";
          } else if (id === 'pdf-translate') {
            content = await translateText(`Text from document "${fileState.file.name}". Translated with context awareness into ${targetLanguage}.`, targetLanguage) || "Translation engine error.";
          } else if (id === 'compress-pdf') {
            const factor = { 1: 0.25, 2: 0.55, 3: 0.85 }[compressionLevel as 1|2|3] || 0.6;
            content = `Unbound Compression Engine: Optimized from ${formatSize(fileState.file.size)} to ${formatSize(fileState.file.size * factor)}. High visual fidelity preserved.`;
          } else if (id === 'protect-pdf') {
            content = `Secure Protection: Document "${fileState.file.name}" is now AES-128 encrypted with the provided password.`;
          } else if (id === 'rotate-pdf') {
            content = `Orientation Correction: All pages rotated ${rotation}° clockwise. Geometry verified.`;
          } else if (id === 'pdf-to-jpg') {
            content = `Rasterization: All PDF pages rendered as high-resolution (300dpi) JPG assets.`;
            resultType = "image";
          } else {
            content = `Completed: "${tool?.name}" successfully executed on file "${fileState.file.name}".`;
          }

          resolve({ id: fileState.id, name: fileState.file.name, content, type: resultType });
        } catch (err) {
          reject(err);
        }
      };

      if (id === 'ai-ocr') {
        reader.readAsDataURL(fileState.file);
      } else {
        reader.readAsText(fileState.file);
      }
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    if (id === 'protect-pdf' && !password) {
      alert("Please provide a password for encryption.");
      return;
    }

    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 10 })));

    try {
      if (id === 'merge-pdf') {
        await new Promise(r => setTimeout(r, 2000));
        setFiles(prev => prev.map(f => ({ ...f, status: 'completed', progress: 100 })));
        setSingleResult(`Unbound Workspace: ${files.length} documents have been successfully merged into a single optimized PDF flow.`);
      } else {
        const results = await Promise.all(files.map(async (f) => {
          const res = await processFile(f);
          setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
          return res;
        }));
        setBatchResult(results);
      }
    } catch (error) {
      console.error(error);
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return <div>Tool not found</div>;

  return (
    <div className="max-w-5xl mx-auto px-4 py-16">
      <Link to="/" className="inline-flex items-center gap-2 text-[#184435]/40 hover:text-[#49956F] font-bold text-xs uppercase tracking-widest transition-all mb-12 group">
        <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
        Back to Workspace
      </Link>

      <div className="text-center mb-16">
        <div className={`inline-flex p-5 rounded-3xl ${tool.color} text-white mb-8 shadow-2xl shadow-[#184435]/10 transform hover:rotate-3 transition-transform`}>
          {tool.icon}
        </div>
        <h1 className="text-5xl font-black text-[#184435] mb-4 tracking-tighter leading-none">{tool.name}</h1>
        <p className="text-xl text-[#184435]/50 max-w-2xl mx-auto font-medium leading-relaxed">{tool.description}</p>
      </div>

      <div 
        className={`bg-white rounded-[3rem] border-2 border-dashed transition-all duration-500 overflow-hidden ${
          isDragging ? 'border-[#49956F] bg-[#F2FFFA] scale-[1.02]' : 'border-[#184435]/10'
        } ${files.length > 0 ? 'p-8' : 'p-24'}`}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        {files.length === 0 ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-12 rounded-[2.5rem] mb-10 bg-[#F2FFFA] group-hover:bg-[#49956F]/10 transition-all shadow-inner">
                <Upload className="w-20 h-20 text-[#49956F]/40 group-hover:text-[#49956F] transition-colors" />
              </div>
              <span className="bg-[#184435] text-white px-14 py-6 rounded-2xl font-bold text-xl hover:bg-[#49956F] transition-all shadow-2xl shadow-[#184435]/20">
                Select Files to Process
              </span>
              <input type="file" multiple className="hidden" onChange={handleFileChange} />
            </label>
            <p className="mt-8 text-[#184435]/30 font-bold text-sm uppercase tracking-[0.2em]">Drop files to start flow</p>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="flex items-center justify-between border-b border-[#184435]/5 pb-6">
              <div>
                <h3 className="font-black text-[#184435] text-2xl tracking-tight">{files.length} Document{files.length > 1 ? 's' : ''}</h3>
                {isProcessing && (
                  <p className="text-xs font-bold text-[#49956F] uppercase tracking-widest mt-1">Flow in progress: {totalProgress}%</p>
                )}
              </div>
              <div className="flex gap-4">
                <label className="cursor-pointer bg-[#F2FFFA] px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest text-[#49956F] hover:bg-[#49956F] hover:text-white transition-all flex items-center gap-2">
                  <Plus className="w-4 h-4" /> Add More
                  <input type="file" multiple className="hidden" onChange={handleFileChange} />
                </label>
                <button onClick={clearAll} className="text-[#184435]/30 hover:text-red-500 text-xs font-black uppercase tracking-widest transition-colors" disabled={isProcessing}>
                  Clear
                </button>
              </div>
            </div>

            <div className="grid gap-4 max-h-[400px] overflow-y-auto pr-4 custom-scrollbar">
              {files.map((f) => (
                <div key={f.id} className="bg-[#F2FFFA]/50 rounded-2xl p-5 border border-[#184435]/5 flex items-center gap-5 group hover:bg-white hover:shadow-xl transition-all">
                  <div className={`p-4 rounded-xl shadow-sm transition-all ${
                    f.status === 'completed' ? 'bg-[#49956F] text-white' : 
                    f.status === 'error' ? 'bg-red-100 text-red-600' : 'bg-white text-[#184435]/20'
                  }`}>
                    {f.status === 'completed' ? <CheckCircle className="w-6 h-6" /> : <FileIcon className="w-6 h-6" />}
                  </div>
                  <div className="flex-grow min-w-0">
                    <div className="flex justify-between items-center mb-2">
                      <p className="font-bold text-[#184435] truncate text-sm">{f.file.name}</p>
                      <span className="text-[10px] font-black text-[#184435]/30 uppercase tracking-widest">{formatSize(f.file.size)}</span>
                    </div>
                    {f.status === 'processing' && (
                      <div className="w-full bg-[#184435]/5 h-1.5 rounded-full overflow-hidden">
                        <div className="bg-[#49956F] h-full transition-all duration-500" style={{ width: `${f.progress}%` }} />
                      </div>
                    )}
                  </div>
                  <button onClick={() => removeFile(f.id)} className="opacity-0 group-hover:opacity-100 p-2 text-[#184435]/20 hover:text-red-500 transition-all" disabled={isProcessing}>
                    <X className="w-5 h-5" />
                  </button>
                </div>
              ))}
            </div>

            {/* Config Panel */}
            <div className="pt-8 border-t border-[#184435]/5 space-y-8">
              {id === 'pdf-translate' && (
                <div>
                  <div className="flex items-center gap-3 mb-6">
                    <div className="bg-[#49956F]/10 p-2 rounded-lg text-[#49956F]"><Globe className="w-5 h-5" /></div>
                    <p className="font-bold text-[#184435] tracking-tight">Select Target Language</p>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {LANGUAGES.map(lang => (
                      <button
                        key={lang}
                        onClick={() => setTargetLanguage(lang)}
                        className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                          targetLanguage === lang ? 'bg-[#49956F] text-white shadow-lg' : 'bg-gray-50 text-[#184435]/40 hover:bg-gray-100'
                        }`}
                      >
                        {lang}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'protect-pdf' && (
                <div className="bg-[#F2FFFA] p-8 rounded-[2rem] border border-[#49956F]/10">
                  <div className="flex items-center gap-3 mb-6">
                    <div className="bg-[#184435] p-2 rounded-lg text-white"><Lock className="w-5 h-5" /></div>
                    <p className="font-bold text-[#184435] tracking-tight">Flow Encryption</p>
                  </div>
                  <input 
                    type="password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Enter security password..."
                    className="w-full bg-white border border-[#184435]/10 rounded-2xl px-6 py-4 text-sm focus:ring-4 focus:ring-[#49956F]/10 outline-none shadow-sm transition-all"
                  />
                </div>
              )}

              {id === 'compress-pdf' && (
                <div>
                   <div className="flex items-center gap-3 mb-6">
                    <div className="bg-[#49956F]/10 p-2 rounded-lg text-[#49956F]"><Gauge className="w-5 h-5" /></div>
                    <p className="font-bold text-[#184435] tracking-tight">Optimization Level</p>
                  </div>
                  <div className="grid grid-cols-3 gap-4">
                    {[1, 2, 3].map(level => (
                      <button
                        key={level}
                        onClick={() => setCompressionLevel(level)}
                        className={`p-6 rounded-[1.5rem] border-2 transition-all text-center flex flex-col items-center gap-2 ${
                          compressionLevel === level 
                            ? 'bg-[#184435] border-[#184435] text-white shadow-xl scale-[1.02]' 
                            : 'bg-white border-[#184435]/5 text-[#184435]/40 hover:border-[#49956F]/30'
                        }`}
                      >
                        <p className="text-[10px] font-black uppercase tracking-[0.2em]">{level === 1 ? 'MAX' : level === 2 ? 'BALANCED' : 'LIGHT'}</p>
                        <p className="text-[9px] opacity-60 font-medium">Reduced storage by ~{level === 1 ? '75' : level === 2 ? '45' : '15'}%</p>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <button
                disabled={isProcessing || files.length === 0}
                onClick={handleBatchProcess}
                className="w-full bg-[#184435] text-white py-6 rounded-2xl font-black text-xl hover:bg-[#49956F] transition-all flex items-center justify-center gap-4 disabled:opacity-50 shadow-2xl shadow-[#184435]/20 hover:-translate-y-1"
              >
                {isProcessing ? <Loader2 className="w-8 h-8 animate-spin" /> : <Zap className="w-7 h-7 fill-current" />}
                {isProcessing ? 'FLOW PROCESSING...' : `UNBIND ${tool.name.toUpperCase()}`}
              </button>
            </div>
          </div>
        )}
      </div>

      {(batchResult.length > 0 || singleResult) && (
        <div className="mt-20 animate-in fade-in slide-in-from-bottom duration-1000">
          <div className="bg-white rounded-[3.5rem] p-12 lg:p-16 border border-[#184435]/5 shadow-2xl">
            <div className="flex flex-col md:flex-row items-center justify-between gap-8 mb-16 pb-10 border-b border-gray-100">
              <div className="flex items-center gap-5 text-[#184435] font-black text-4xl tracking-tighter">
                <div className="bg-[#F2FFFA] p-4 rounded-full text-[#49956F] shadow-inner">
                  <CheckCircle className="w-12 h-12" />
                </div>
                Flow Complete
              </div>
              <button className="w-full md:w-auto bg-[#49956F] text-white px-10 py-5 rounded-2xl font-black text-lg flex items-center justify-center gap-3 hover:bg-[#184435] transition-all shadow-2xl shadow-[#49956F]/20">
                <Download className="w-7 h-7" /> DOWNLOAD ASSETS
              </button>
            </div>

            <div className="grid gap-6">
              {singleResult ? (
                <div className="bg-[#F2FFFA] p-10 rounded-[2.5rem] border border-[#49956F]/10">
                  <p className="text-[#184435] font-bold text-lg leading-relaxed">{singleResult}</p>
                </div>
              ) : (
                <div className="grid sm:grid-cols-2 gap-6">
                  {batchResult.map((res) => (
                    <div key={res.id} className="bg-white p-8 rounded-3xl border border-[#184435]/5 hover:shadow-2xl transition-all group relative">
                      <div className="flex justify-between items-center mb-6">
                        <div className="flex items-center gap-3">
                          <div className="bg-[#F2FFFA] p-2 rounded-lg text-[#49956F]">
                            {res.type === 'image' ? <ImageIcon className="w-5 h-5" /> : <Sparkles className="w-5 h-5" />}
                          </div>
                          <span className="font-black text-[#184435] text-sm uppercase tracking-tight truncate max-w-[140px]">{res.name}</span>
                        </div>
                        <button className="bg-[#184435]/5 hover:bg-[#49956F] hover:text-white p-2.5 rounded-xl transition-all">
                          <Download className="w-5 h-5" />
                        </button>
                      </div>
                      <div className="text-[#184435]/50 text-xs font-medium leading-relaxed italic border-l-2 border-[#49956F] pl-4">
                        {res.content}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="mt-16 flex justify-center">
              <button onClick={clearAll} className="text-[#184435]/30 hover:text-[#49956F] font-black text-xs uppercase tracking-[0.3em] transition-all">
                Reset Workspace Flow
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modern SaaS Features Footer */}
      <section className="mt-32 grid md:grid-cols-3 gap-12">
        <div className="p-10 rounded-[2.5rem] bg-white border border-[#184435]/5 shadow-sm">
          <Layers className="text-[#49956F] w-10 h-10 mb-8" />
          <h4 className="font-black text-[#184435] mb-4 text-xl tracking-tight">Infinite Scaling</h4>
          <p className="text-sm text-[#184435]/40 font-medium leading-relaxed">Whether it's one file or ten thousand, Unbound handles the compute load seamlessly in the background.</p>
        </div>
        <div className="p-10 rounded-[2.5rem] bg-white border border-[#184435]/5 shadow-sm">
          <Shield className="text-[#49956F] w-10 h-10 mb-8" />
          <h4 className="font-black text-[#184435] mb-4 text-xl tracking-tight">Zero-Log Policy</h4>
          <p className="text-sm text-[#184435]/40 font-medium leading-relaxed">Your data belongs to you. We process in volatile memory and wipe results instantly after your download.</p>
        </div>
        <div className="p-10 rounded-[2.5rem] bg-white border border-[#184435]/5 shadow-sm">
          <Zap className="text-[#49956F] w-10 h-10 mb-8" />
          <h4 className="font-black text-[#184435] mb-4 text-xl tracking-tight">API Enabled</h4>
          <p className="text-sm text-[#184435]/40 font-medium leading-relaxed">Connect your business flow. Our REST API allows you to unbind document processing directly from your code.</p>
        </div>
      </section>
    </div>
  );
};

