          isActive ? 'text-[#49956F]' : 'text-[#184435] hover:text-[#49956F]'
        }`}
      >
        {label}
        {hasChevron && <ChevronDown className={`w-3.5 h-3.5 transition-transform duration-300 ${isActive ? 'rotate-180' : ''}`} />}
        <span className={`absolute bottom-0 left-1/2 -translate-x-1/2 h-[2px] bg-[#49956F] transition-all duration-180 ease-[cubic-bezier(0.4,0,0.2,1)] ${isActive ? 'w-full' : 'w-0 group-hover:w-full'}`} />
      </button>
    );

    return to ? <Link to={to}>{content}</Link> : content;
