import React, { useState, useMemo } from 'react';
import { TOOLS } from '../constants';
import { ToolCard } from './ToolCard';
import { 
  ChevronLeft, ChevronRight, Search, LayoutGrid, 
  Repeat, Zap, Shield, BrainCircuit, SlidersHorizontal 
} from 'lucide-react';

export const AllCapabilities: React.FC = () => {
  const [currentPage, setCurrentPage] = useState(1);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const itemsPerPage = 12;

  const categories = [
    { id: 'all', label: 'All Tools', icon: <LayoutGrid className="w-4 h-4" /> },
    { id: 'convert', label: 'Convert', icon: <Repeat className="w-4 h-4" /> },
    { id: 'optimize', label: 'Optimize', icon: <Zap className="w-4 h-4" /> },
    { id: 'edit', label: 'Edit', icon: <SlidersHorizontal className="w-4 h-4" /> },
    { id: 'security', label: 'Security', icon: <Shield className="w-4 h-4" /> },
    { id: 'ai', label: 'AI Suite', icon: <BrainCircuit className="w-4 h-4" /> },
  ];

  const filteredTools = useMemo(() => {
    return TOOLS.filter(tool => {
      const matchesSearch = tool.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           tool.description.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'all' || tool.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory]);

  const totalPages = Math.ceil(filteredTools.length / itemsPerPage);
  const currentTools = filteredTools.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const handlePageChange = (page: number) => {
    setCurrentPage(page);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="bg-[#F2FFFA] dark:bg-[#0A1F18] min-h-screen py-20 transition-colors duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header Section */}
        <div className="text-center mb-16 animate-fade-in-up">
          <h1 className="text-5xl md:text-6xl font-black text-[#184435] dark:text-[#E6FFF5] mb-6 tracking-tighter">
            Document <span className="text-[#49956F]">Unbound</span>
          </h1>
          <p className="text-xl text-[#184435]/50 dark:text-[#E6FFF5]/50 font-medium max-w-2xl mx-auto">
            Explore our complete suite of 50+ intelligent document tools. Built for speed, security, and global scale.
          </p>
        </div>

        {/* Filter & Search Bar */}
        <div className="flex flex-col lg:flex-row gap-6 mb-12 animate-fade-in-up delay-100">
          <div className="flex-grow relative group">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-[#184435]/30 dark:text-[#E6FFF5]/30 group-focus-within:text-[#49956F] transition-colors" />
            <input 
              type="text"
              placeholder="Search capabilities (e.g. OCR, Merge, Translate)..."
              value={searchQuery}
              onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
              className="w-full bg-white dark:bg-[#122B22] border border-[#184435]/5 dark:border-white/5 rounded-2xl py-5 pl-14 pr-6 text-[#184435] dark:text-[#E6FFF5] font-bold text-sm focus:ring-4 focus:ring-[#49956F]/5 dark:focus:ring-[#49956F]/10 focus:border-[#49956F]/20 dark:focus:border-[#49956F]/40 transition-all shadow-sm outline-none"
            />
          </div>
          <div className="flex flex-wrap gap-2">
            {categories.map((cat) => (
              <button
                key={cat.id}
                onClick={() => { setSelectedCategory(cat.id); setCurrentPage(1); }}
                className={`flex items-center gap-2 px-6 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                  selectedCategory === cat.id 
                  ? 'bg-[#184435] dark:bg-[#49956F] text-white shadow-xl' 
                  : 'bg-white dark:bg-[#122B22] text-[#184435]/40 dark:text-[#E6FFF5]/40 border border-[#184435]/5 dark:border-white/5 hover:bg-gray-50 dark:hover:bg-[#1a382d]'
                }`}
              >
                {cat.icon}
                {cat.label}
              </button>
            ))}
          </div>
        </div>

        {/* Grid Display */}
        {currentTools.length > 0 ? (
          <>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8 mb-16">
              {currentTools.map((tool, idx) => (
                <div key={tool.id} className="animate-fade-in-up opacity-0" style={{ animationDelay: `${idx * 40}ms` }}>
                  <ToolCard tool={tool} />
                </div>
              ))}
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex justify-center items-center gap-3 animate-fade-in-up">
                <button 
                  disabled={currentPage === 1}
                  onClick={() => handlePageChange(currentPage - 1)}
                  className="p-4 rounded-xl bg-white dark:bg-[#122B22] border border-[#184435]/5 dark:border-white/5 text-[#184435] dark:text-[#E6FFF5] disabled:opacity-30 hover:bg-[#F2FFFA] dark:hover:bg-[#1a382d] transition-all"
                >
                  <ChevronLeft className="w-5 h-5" />
                </button>

                <div className="flex gap-2">
                  {Array.from({ length: totalPages }).map((_, i) => (
                    <button
                      key={i}
                      onClick={() => handlePageChange(i + 1)}
                      className={`w-12 h-12 rounded-xl text-sm font-black transition-all ${
                        currentPage === i + 1 
                        ? 'bg-[#49956F] text-white shadow-lg shadow-[#49956F]/20 scale-110' 
                        : 'bg-white dark:bg-[#122B22] text-[#184435]/40 dark:text-[#E6FFF5]/40 hover:bg-gray-50 dark:hover:bg-[#1a382d]'
                      }`}
                    >
                      {i + 1}
                    </button>
                  ))}
                </div>

                <button 
                  disabled={currentPage === totalPages}
                  onClick={() => handlePageChange(currentPage + 1)}
                  className="p-4 rounded-xl bg-white dark:bg-[#122B22] border border-[#184435]/5 dark:border-white/5 text-[#184435] dark:text-[#E6FFF5] disabled:opacity-30 hover:bg-[#F2FFFA] dark:hover:bg-[#1a382d] transition-all"
                >
                  <ChevronRight className="w-5 h-5" />
                </button>
              </div>
            )}
          </>
        ) : (
          <div className="text-center py-24 bg-white dark:bg-[#122B22] rounded-[3rem] border border-dashed border-[#184435]/10 dark:border-white/10 animate-fade-in-up">
            <div className="inline-flex p-8 rounded-full bg-[#F2FFFA] dark:bg-black/20 text-[#49956F] mb-6">
              <Search className="w-12 h-12" />
            </div>
            <h3 className="text-2xl font-bold text-[#184435] dark:text-[#E6FFF5] mb-2">No matching tools found</h3>
            <p className="text-[#184435]/40 dark:text-white/20 font-medium">Try adjusting your search or filters to explore other capabilities.</p>
            <button 
              onClick={() => { setSearchQuery(''); setSelectedCategory('all'); }}
              className="mt-8 text-[#49956F] font-black text-xs uppercase tracking-widest hover:underline"
            >
              Clear all filters
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { 
  Layers, Heart, Menu, X, Globe, ShieldCheck, Zap, ChevronDown, 
  FileText, Files, Scissors, RotateCw, Lock, ScanText, 
  FileUp, FileImage, Languages, FileStack, LayoutGrid, Shield,
  Monitor, BrainCircuit, Repeat, Unlock, ShieldAlert, PenTool,
  Wrench, Sun, Moon
} from 'lucide-react';
import { TOOLS } from '../constants';

export const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [activeMenu, setActiveMenu] = useState<'convert' | 'all' | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark') ? 'dark' : 'light';
    }
    return 'light';
  });
  const menuRef = useRef<HTMLDivElement>(null);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setActiveMenu(null);
      }
    };
    window.addEventListener('scroll', handleScroll);
    window.addEventListener('click', handleClickOutside);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('click', handleClickOutside);
    };
  }, []);

  useEffect(() => {
    setActiveMenu(null);
    setIsMobileMenuOpen(false);
  }, [location.pathname]);

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    if (newTheme === 'dark') {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  };

  const DropdownItem = ({ to, label, icon: Icon }: { to: string, label: string, icon: any }) => (
    <Link 
      to={to} 
