      </button>
    );
    return to ? <Link to={to}>{content}</Link> : content;
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-[#5FB79A] selection:text-white dark:bg-obsidian">
      <header 
        ref={menuRef}
        className={`fixed top-0 left-0 right-0 z-[100] bg-white dark:bg-obsidian transition-soft ${
          scrolled ? 'shadow-[0_8px_24px_rgba(0,0,0,0.05)] dark:border-b dark:border-obsidian-border py-2' : 'py-4'
        }`}
