              <span className="text-xl font-black text-[#184435] dark:text-mint-soft tracking-tight">Unbound</span>
            </Link>

            <nav className="hidden lg:flex items-center gap-4">
              <NavButton label="MERGE PDF" to="/tool/merge-pdf" />
