              <Link to="/signup" className="bg-[#184435] dark:bg-mint-accent text-white px-7 py-3 rounded-xl text-[11px] font-black uppercase tracking-widest hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft shadow-md active:opacity-90">Sign Up</Link>
