          <h1 className="text-5xl font-black text-[#184435] dark:text-mint-soft mb-6 tracking-tighter">
            Full <span className="text-[#49956F] dark:text-mint-accent">Capability</span> Suite
          </h1>
          <p className="text-lg text-[#184435]/50 dark:text-mint-muted font-medium max-w-2xl mx-auto">
            Discover the specialized tools driving the next generation of intelligent document management.
          </p>
        </div>

        <div className="flex flex-col lg:flex-row gap-6 mb-12 animate-fade-in-up-soft delay-100">
          <div className="flex-grow relative group">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-[#184435]/30 dark:text-mint-dim group-focus-within:text-mint-accent transition-soft" />
            <input 
              type="text"
              placeholder="Search tools..."
              value={searchQuery}
              onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
              className="w-full bg-white dark:bg-obsidian-surface border border-[#184435]/5 dark:border-obsidian-border rounded-2xl py-4 pl-14 pr-6 text-[#184435] dark:text-mint-soft font-bold text-sm focus:border-mint-accent/40 outline-none transition-soft shadow-sm"
            />
          </div>
          <div className="flex flex-wrap gap-2">
            {categories.map((cat) => (
              <button
                key={cat.id}
                onClick={() => { setSelectedCategory(cat.id); setCurrentPage(1); }}
                className={`flex items-center gap-2 px-5 py-3 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-soft ${
                  selectedCategory === cat.id 
                  ? 'bg-[#184435] dark:bg-mint-accent text-white shadow-md' 
                  : 'bg-white dark:bg-obsidian-surface text-[#184435]/40 dark:text-mint-muted border border-gray-50 dark:border-obsidian-border hover:brightness-105'
                }`}
              >
                {cat.icon} {cat.label}
              </button>
            ))}
          </div>
        </div>

        {currentTools.length > 0 ? (
          <>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mb-16">
              {currentTools.map((tool, idx) => (
                <div key={tool.id} className="animate-fade-in-up-soft opacity-0" style={{ animationDelay: `${idx * 40}ms` }}>
                  <ToolCard tool={tool} />
                </div>
              ))}
            </div>

            {totalPages > 1 && (
              <div className="flex justify-center items-center gap-3">
                <button 
                  disabled={currentPage === 1}
                  onClick={() => handlePageChange(currentPage - 1)}
                  className="p-4 rounded-xl bg-white dark:bg-obsidian-surface text-[#184435] dark:text-mint-soft disabled:opacity-30 transition-soft border border-gray-50 dark:border-obsidian-border"
                >
                  <ChevronLeft className="w-5 h-5" />
                </button>
                <div className="flex gap-2">
                  {Array.from({ length: totalPages }).map((_, i) => (
                    <button
                      key={i}
                      onClick={() => handlePageChange(i + 1)}
                      className={`w-12 h-12 rounded-xl text-sm font-black transition-soft ${
                        currentPage === i + 1 
                        ? 'bg-mint-accent text-white shadow-lg' 
                        : 'bg-white dark:bg-obsidian-surface text-mint-muted hover:text-mint-soft'
                      }`}
                    >
                      {i + 1}
                    </button>
                  ))}
                </div>
                <button 
                  disabled={currentPage === totalPages}
                  onClick={() => handlePageChange(currentPage + 1)}
                  className="p-4 rounded-xl bg-white dark:bg-obsidian-surface text-[#184435] dark:text-mint-soft disabled:opacity-30 transition-soft border border-gray-50 dark:border-obsidian-border"
                >
                  <ChevronRight className="w-5 h-5" />
                </button>
              </div>
            )}
          </>
        ) : (
          <div className="text-center py-20 bg-white dark:bg-obsidian-surface rounded-[3rem] border border-dashed border-[#184435]/10 dark:border-obsidian-border animate-fade-in-up-soft">
            <div className="p-8 rounded-full bg-[#F2FFFA] dark:bg-obsidian-elevated text-mint-accent inline-block mb-6">
