            <p className="text-mint-dim font-medium text-sm">Try broadening your search or switching categories.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Link, useLocation } from 'react-router-dom';
