        className={`relative flex items-center gap-1.5 px-3 py-2 text-[13px] font-black uppercase tracking-wider transition-soft group ${
          isActive ? 'text-[#49956F] dark:text-mint-accent' : 'text-[#184435] dark:text-mint-soft hover:text-[#49956F] dark:hover:text-mint-accent'
        }`}
      >
        {label}
        {hasChevron && <ChevronDown className={`w-3.5 h-3.5 transition-soft ${isActive ? 'rotate-180' : ''}`} />}
        <span className={`absolute bottom-0 left-1/2 -translate-x-1/2 h-[1px] bg-[#49956F] dark:bg-mint-accent transition-soft ${isActive ? 'w-full' : 'w-0 group-hover:w-full'}`} />
      </button>
    );
    return to ? <Link to={to}>{content}</Link> : content;
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-[#5FB79A] selection:text-white dark:bg-obsidian">
      <header 
        ref={menuRef}
        className={`fixed top-0 left-0 right-0 z-[100] bg-white dark:bg-obsidian transition-soft ${
          scrolled ? 'shadow-[0_8px_24px_rgba(0,0,0,0.05)] dark:border-b dark:border-obsidian-border py-2' : 'py-4'
        }`}
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between">
            <Link to="/" className="flex items-center gap-2.5 group shrink-0 active:opacity-80 transition-soft">
              <div className="bg-[#184435] dark:bg-mint-accent p-2 rounded-xl group-hover:rotate-3 transition-soft">
                <Layers className="text-white w-5 h-5" />
              </div>
              <span className="text-xl font-black text-[#184435] dark:text-mint-soft tracking-tight">Unbound</span>
            </Link>

            <nav className="hidden lg:flex items-center gap-4">
