import React, { useState, useMemo } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  Upload, X, File as FileIcon, Loader2, CheckCircle, ArrowLeft, 
  Zap, Plus, ShieldCheck, Cpu, Layers, Shield, Sparkles, Download
} from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText, reconstructAsWord } from '../services/geminiService';

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string, type?: string }[]>([]);

  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [isDragging, setIsDragging] = useState(false);

  const totalProgress = useMemo(() => {
    if (files.length === 0) return 0;
    const sum = files.reduce((acc, f) => acc + f.progress, 0);
    return Math.round(sum / files.length);
  }, [files]);

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];
    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type.includes('word');
      if ((id === 'ai-ocr' && (isImage || isPDF)) || (id === 'word-to-pdf' && isWord) || isPDF) {
        newFiles.push({ id: Math.random().toString(36).substr(2, 9), file, status: 'idle', progress: 0 });
      }
    });
    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `unbound_${filename}.txt`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const processFile = async (fileState: FileState) => {
    return new Promise<{ id: string, name: string, content: string }>((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async () => {
        try {
          const base64 = (reader.result as string).split(',')[1];
          let content = "";

          if (id === 'ai-summarize') {
            const text = await performOCR(base64, fileState.file.type);
            content = await summarizeDocument(text) || "";
          } else if (id === 'ai-ocr') {
            content = await performOCR(base64, fileState.file.type) || "";
          } else if (id === 'pdf-to-word') {
            content = await reconstructAsWord(base64, fileState.file.type) || "";
          } else if (id === 'pdf-translate') {
            const text = await performOCR(base64, fileState.file.type);
            content = await translateText(text, targetLanguage) || "";
          } else {
            content = `Processing simulation: ${fileState.file.name} unbundled.`;
          }

          resolve({ id: fileState.id, name: fileState.file.name, content });
        } catch (err) { reject(err); }
      };
      reader.readAsDataURL(fileState.file);
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 10 })));

    try {
      const results = await Promise.all(files.map(async f => {
        const res = await processFile(f);
        setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
        return res;
      }));
      setBatchResult(results);
    } catch (e) {
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return null;

  return (
    <div className="max-w-5xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      <div className="flex justify-between items-center mb-12">
        <Link to="/" className="inline-flex items-center gap-2 text-[#184435]/40 dark:text-mint-dim hover:text-[#49956F] dark:hover:text-mint-accent font-bold text-[11px] uppercase tracking-widest transition-soft group">
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-soft" />
          Workspace
        </Link>
        <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[#49956F] dark:text-mint-accent px-4 py-2 bg-[#F2FFFA] dark:bg-obsidian-surface rounded-full border border-[#49956F]/10 dark:border-obsidian-border">
          <ShieldCheck className="w-3 h-3" /> Stateless Flow
        </div>
      </div>

      <div className="text-center mb-16">
        <div className={`inline-flex p-5 rounded-3xl ${tool.color} text-white mb-8 shadow-lg dark:shadow-none transition-soft group hover:rotate-2`}>
          {tool.icon}
        </div>
        <h1 className="text-5xl font-black text-[#184435] dark:text-mint-soft mb-4 tracking-tighter">{tool.name}</h1>
        <p className="text-xl text-[#184435]/50 dark:text-mint-muted max-w-2xl mx-auto font-medium leading-relaxed">{tool.description}</p>
      </div>

      <div 
        className={`bg-white dark:bg-obsidian-surface rounded-[3rem] border-2 border-dashed transition-soft overflow-hidden ${
          isDragging ? 'border-[#49956F] dark:border-mint-accent bg-[#F2FFFA] dark:bg-obsidian-elevated' : 'border-[#184435]/10 dark:border-obsidian-border shadow-sm'
        } ${files.length > 0 ? 'p-8' : 'p-20'}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); if (e.dataTransfer.files) addFiles(e.dataTransfer.files); }}
      >
        {files.length === 0 ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-12 rounded-[2.5rem] mb-10 bg-[#F2FFFA] dark:bg-obsidian-elevated group-hover:bg-[#49956F]/10 dark:group-hover:bg-mint-accent/10 transition-soft">
                <Upload className="w-16 h-16 text-[#49956F]/40 dark:text-mint-muted/40 group-hover:text-[#49956F] dark:group-hover:text-mint-accent transition-soft" />
              </div>
              <span className="bg-[#184435] dark:bg-mint-accent text-white px-12 py-5 rounded-2xl font-bold text-lg hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft shadow-lg active:opacity-90">
                Choose File
              </span>
              <input type="file" multiple className="hidden" onChange={(e) => e.target.files && addFiles(e.target.files)} />
            </label>
            <p className="mt-8 text-[#184435]/30 dark:text-mint-dim font-bold text-[10px] uppercase tracking-widest">Client-Side Temporary Upload</p>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="flex items-center justify-between border-b border-[#184435]/5 dark:border-obsidian-border pb-6">
              <h3 className="font-black text-[#184435] dark:text-mint-soft text-2xl tracking-tight">{files.length} Item{files.length > 1 ? 's' : ''}</h3>
              <div className="flex gap-4">
                <button onClick={() => setFiles([])} className="text-[#184435]/30 dark:text-mint-dim hover:text-red-500 font-black text-[11px] uppercase tracking-widest transition-soft">Clear All</button>
              </div>
            </div>

            <div className="grid gap-3 max-h-[400px] overflow-y-auto pr-2 no-scrollbar">
              {files.map((f) => (
                <div key={f.id} className="bg-[#F2FFFA]/50 dark:bg-obsidian-elevated/40 rounded-2xl p-4 border border-[#184435]/5 dark:border-obsidian-border flex items-center gap-5 transition-soft">
                  <div className={`p-3.5 rounded-xl ${f.status === 'completed' ? 'bg-[#49956F] text-white' : 'bg-white dark:bg-obsidian-surface text-[#184435]/20 dark:text-mint-dim'}`}>
                    {f.status === 'completed' ? <CheckCircle className="w-5 h-5" /> : <FileIcon className="w-5 h-5" />}
                  </div>
                  <div className="flex-grow min-w-0">
                    <p className="font-bold text-[#184435] dark:text-mint-soft truncate text-sm mb-1">{f.file.name}</p>
                    {f.status === 'processing' && (
                      <div className="w-full bg-[#184435]/5 dark:bg-obsidian-border h-1 rounded-full overflow-hidden">
                        <div className="bg-[#49956F] dark:bg-mint-accent h-full transition-all duration-700" style={{ width: `${f.progress}%` }} />
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>

            {batchResult.length > 0 && (
              <div className="p-6 bg-mint-accent/10 dark:bg-mint-accent/5 rounded-2xl border border-mint-accent/20">
                <div className="flex items-center gap-3 mb-4">
                  <Sparkles className="w-5 h-5 text-mint-accent" />
                  <p className="font-bold text-mint-accent text-sm tracking-tight uppercase tracking-widest">Processing Ready</p>
                </div>
                <div className="space-y-2">
                  {batchResult.map(res => (
                    <button 
                      key={res.id} 
                      onClick={() => handleDownload(res.name, res.content)}
                      className="w-full flex items-center justify-between p-4 bg-white dark:bg-obsidian-elevated rounded-xl hover:brightness-105 transition-soft group"
                    >
                      <span className="text-sm font-bold dark:text-mint-soft truncate max-w-[80%]">{res.name} Result</span>
                      <Download className="w-4 h-4 text-mint-accent group-hover:translate-y-0.5 transition-soft" />
                    </button>
                  ))}
                </div>
              </div>
            )}

            <button
              disabled={isProcessing || files.length === 0}
              onClick={handleBatchProcess}
              className="w-full bg-[#184435] dark:bg-mint-accent text-white py-5 rounded-2xl font-black text-lg hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft flex items-center justify-center gap-3 active:opacity-90 disabled:opacity-30 shadow-lg dark:shadow-none"
            >
              {isProcessing ? <Loader2 className="w-6 h-6 animate-spin" /> : <Zap className="w-6 h-6" />}
              {isProcessing ? 'PROCESSING...' : `PROCESS IN VOLATILE NODE`}
            </button>
          </div>
        )}
      </div>

      <div className="mt-16 p-8 bg-[#F2FFFA] dark:bg-obsidian-elevated/20 rounded-[2.5rem] border border-[#49956F]/10 dark:border-obsidian-border flex items-start gap-6">
        <div className="p-4 bg-white dark:bg-obsidian-surface rounded-2xl shadow-sm">
           <Shield className="w-8 h-8 text-mint-accent" />
        </div>
        <div>
           <h4 className="font-black text-[#184435] dark:text-mint-soft text-lg mb-2">Stateless Privacy Policy</h4>
           <p className="text-sm text-[#184435]/50 dark:text-mint-muted leading-relaxed max-w-2xl">
              This tool uses a 100% database-free architecture. Your files are converted to memory-only blobs, sent through an encrypted tunnel to our inference nodes, and discarded the moment your session ends. 
              <strong> We never store your documents.</strong>
           </p>
        </div>
      </div>

      <section className="mt-32 grid md:grid-cols-3 gap-12 text-center">
        <div className="group">
          <Layers className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">Private Node</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">Processing occurs on private volatile nodes. No logs, no traces, just results.</p>
        </div>
        <div className="group">
          <Cpu className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">RAM-Only</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">Enterprise-grade security standards applied to every byte of document flow.</p>
        </div>
        <div className="group">
          <Zap className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">AI Augmented</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">State-of-the-art multimodal AI ensures precise reconstruction and extraction.</p>
