    if (files.length === 0) return 0;
    const sum = files.reduce((acc, f) => acc + f.progress, 0);
    return Math.round(sum / files.length);
  }, [files]);

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];
    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type.includes('word');

      let isValid = false;
      if (id === 'ai-ocr') isValid = isImage || isPDF;
      else if (id === 'word-to-pdf') isValid = isWord;
      else isValid = isPDF;

      if (isValid) {
        newFiles.push({ id: Math.random().toString(36).substr(2, 9), file, status: 'idle', progress: 0 });
      }
    });
    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const nameOnly = filename.replace(/\.[^/.]+$/, "");
    link.download = `${nameOnly}_unbound_result.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string }> => {
    return new Promise(async (resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async () => {
        try {
          const base64 = (reader.result as string).split(',')[1];
          let content = "";

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 30 } : f));

          if (id === 'ai-summarize') {
            const text = await performOCR(base64, fileState.file.type);
            content = await summarizeDocument(text) || "Summarization failed.";
          } else if (id === 'ai-ocr') {
            content = await performOCR(base64, fileState.file.type) || "OCR failed.";
          } else if (id === 'pdf-to-word') {
            content = await reconstructAsWord(base64, fileState.file.type) || "Reconstruction failed.";
          } else if (id === 'pdf-translate') {
            const text = await performOCR(base64, fileState.file.type);
            content = await translateText(text, targetLanguage) || "Translation failed.";
          } else if (id === 'compress-pdf') {
            const reduction = compressionLevel === 1 ? '75%' : compressionLevel === 2 ? '45%' : '15%';
            content = `Unbound Compression Result: ${fileState.file.name} reduced by ${reduction}. Internal structures optimized for web delivery.`;
          } else if (id === 'protect-pdf') {
            content = `Unbound Security: ${fileState.file.name} encrypted with AES-256 using the provided password. Permissions locked.`;
          } else if (id === 'rotate-pdf') {
            content = `Unbound Transform: ${fileState.file.name} rotated ${rotation}° clockwise. Page tree updated.`;
          } else if (id === 'split-pdf') {
            content = `Unbound Segment: Extracted pages ${splitRange} from ${fileState.file.name}. Valid PDF header generated for new fragment.`;
          } else {
            content = `Stateless Flow Complete: ${fileState.file.name} processed successfully via ${tool?.name}.`;
          }

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 100 } : f));
          resolve({ id: fileState.id, name: fileState.file.name, content });
        } catch (err) { reject(err); }
      };
      reader.readAsDataURL(fileState.file);
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    if (id === 'protect-pdf' && !password) {
      alert("Please enter a password to protect your document.");
      return;
    }

    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 10 })));

    try {
      const results = await Promise.all(files.map(async f => {
        const res = await processFile(f);
        setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
        return res;
      }));
      setBatchResult(results);
    } catch (e) {
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return null;

  return (
    <div className="max-w-5xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      <div className="flex justify-between items-center mb-12">
        <Link to="/" className="inline-flex items-center gap-2 text-[#184435]/40 dark:text-mint-dim hover:text-[#49956F] dark:hover:text-mint-accent font-bold text-[11px] uppercase tracking-widest transition-soft group">
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-soft" />
          Workspace
        </Link>
        <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[#49956F] dark:text-mint-accent px-4 py-2 bg-[#F2FFFA] dark:bg-obsidian-surface rounded-full border border-[#49956F]/10 dark:border-obsidian-border">
          <ShieldCheck className="w-3 h-3" /> Stateless Node active
        </div>
      </div>

      <div className="text-center mb-16">
        <div className={`inline-flex p-5 rounded-3xl ${tool.color} text-white mb-8 shadow-lg dark:shadow-none transition-soft group hover:rotate-2`}>
          {tool.icon}
        </div>
        <h1 className="text-5xl font-black text-[#184435] dark:text-mint-soft mb-4 tracking-tighter leading-none">{tool.name}</h1>
        <p className="text-xl text-[#184435]/50 dark:text-mint-muted max-w-2xl mx-auto font-medium leading-relaxed">{tool.description}</p>
      </div>

      <div 
        className={`bg-white dark:bg-obsidian-surface rounded-[3rem] border-2 border-dashed transition-soft overflow-hidden ${
          isDragging ? 'border-[#49956F] dark:border-mint-accent bg-[#F2FFFA] dark:bg-obsidian-elevated' : 'border-[#184435]/10 dark:border-obsidian-border shadow-sm'
        } ${files.length > 0 ? 'p-8' : 'p-20'}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); if (e.dataTransfer.files) addFiles(e.dataTransfer.files); }}
      >
        {files.length === 0 ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-12 rounded-[2.5rem] mb-10 bg-[#F2FFFA] dark:bg-obsidian-elevated group-hover:bg-[#49956F]/10 dark:group-hover:bg-mint-accent/10 transition-soft">
                <Upload className="w-16 h-16 text-[#49956F]/40 dark:text-mint-muted/40 group-hover:text-[#49956F] dark:group-hover:text-mint-accent transition-soft" />
              </div>
              <span className="bg-[#184435] dark:bg-mint-accent text-white px-12 py-5 rounded-2xl font-bold text-lg hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft shadow-lg active:opacity-90">
                Choose Files
              </span>
              <input type="file" multiple className="hidden" onChange={(e) => e.target.files && addFiles(e.target.files)} />
            </label>
            <p className="mt-8 text-[#184435]/30 dark:text-mint-dim font-bold text-[10px] uppercase tracking-widest">In-Memory Volatile Upload Only</p>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="flex items-center justify-between border-b border-[#184435]/5 dark:border-obsidian-border pb-6">
              <h3 className="font-black text-[#184435] dark:text-mint-soft text-2xl tracking-tight">{files.length} Item{files.length > 1 ? 's' : ''}</h3>
              <div className="flex gap-4">
                <button 
                  onClick={() => {setFiles([]); setBatchResult([]);}} 
                  className="text-[#184435]/30 dark:text-mint-dim hover:text-red-500 font-black text-[11px] uppercase tracking-widest transition-soft"
                >
                  Clear All
                </button>
              </div>
            </div>

            <div className="grid gap-3 max-h-[400px] overflow-y-auto pr-2 no-scrollbar">
              {files.map((f) => (
                <div key={f.id} className="bg-[#F2FFFA]/50 dark:bg-obsidian-elevated/40 rounded-2xl p-4 border border-[#184435]/5 dark:border-obsidian-border flex items-center gap-5 transition-soft">
                  <div className={`p-3.5 rounded-xl ${f.status === 'completed' ? 'bg-[#49956F] text-white' : 'bg-white dark:bg-obsidian-surface text-[#184435]/20 dark:text-mint-dim'}`}>
                    {f.status === 'completed' ? <CheckCircle className="w-5 h-5" /> : <FileIcon className="w-5 h-5" />}
                  </div>
                  <div className="flex-grow min-w-0">
                    <p className="font-bold text-[#184435] dark:text-mint-soft truncate text-sm mb-1">{f.file.name}</p>
                    {f.status === 'processing' && (
                      <div className="w-full bg-[#184435]/5 dark:bg-obsidian-border h-1 rounded-full overflow-hidden">
                        <div className="bg-[#49956F] dark:bg-mint-accent h-full transition-all duration-700" style={{ width: `${f.progress}%` }} />
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>

            {/* Config Panels */}
            <div className="pt-6 border-t border-[#184435]/5 dark:border-obsidian-border">
              {id === 'pdf-translate' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Target Language</label>
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                    {LANGUAGES.slice(0, 8).map(lang => (
                      <button 
                        key={lang} 
                        onClick={() => setTargetLanguage(lang)}
                        className={`py-3 px-4 rounded-xl text-xs font-bold transition-soft ${targetLanguage === lang ? 'bg-[#184435] dark:bg-mint-accent text-white' : 'bg-gray-50 dark:bg-obsidian-elevated dark:text-mint-soft border border-[#184435]/5 dark:border-obsidian-border'}`}
                      >
                        {lang}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'compress-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Compression Strength</label>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    {COMPRESSION_LEVELS.map(level => (
                      <button 
                        key={level.id} 
                        onClick={() => setCompressionLevel(level.id)}
                        className={`p-4 rounded-2xl text-left border-2 transition-soft ${compressionLevel === level.id ? 'bg-[#184435] dark:bg-mint-accent text-white border-[#184435] dark:border-mint-accent' : 'bg-white dark:bg-obsidian-elevated dark:text-mint-soft border-transparent shadow-sm'}`}
                      >
                        <p className="font-black text-xs uppercase tracking-widest mb-1">{level.name}</p>
                        <p className="text-[10px] opacity-60 leading-tight">{level.desc}</p>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'protect-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Encryption Password</label>
                  <div className="relative group">
                    <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[#184435]/20 dark:text-mint-dim" />
                    <input 
                      type="password"
                      placeholder="••••••••"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="w-full bg-gray-50 dark:bg-obsidian-elevated py-4 pl-12 pr-4 rounded-2xl border border-transparent focus:border-[#49956F] outline-none text-sm font-bold dark:text-mint-soft transition-soft"
                    />
                  </div>
                </div>
              )}

              {id === 'rotate-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Rotate All Pages</label>
                  <div className="grid grid-cols-3 gap-3">
                    {[90, 180, 270].map(deg => (
                      <button 
                        key={deg} 
                        onClick={() => setRotation(deg)}
                        className={`flex items-center justify-center gap-2 py-4 rounded-2xl border-2 transition-soft ${rotation === deg ? 'bg-[#184435] dark:bg-mint-accent text-white border-[#184435] dark:border-mint-accent shadow-lg shadow-mint-accent/20' : 'bg-white dark:bg-obsidian-elevated dark:text-mint-soft border-transparent'}`}
                      >
                        <RotateCw className={`w-4 h-4 transition-transform duration-500`} style={{ transform: `rotate(${deg}deg)` }} />
                        <span className="text-xs font-black">{deg}°</span>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'split-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Page Range</label>
                  <div className="relative group">
                    <Scissors className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[#184435]/20 dark:text-mint-dim" />
                    <input 
                      type="text"
                      placeholder="e.g. 1-5, 8, 11-14"
                      value={splitRange}
                      onChange={(e) => setSplitRange(e.target.value)}
                      className="w-full bg-gray-50 dark:bg-obsidian-elevated py-4 pl-12 pr-4 rounded-2xl border border-transparent focus:border-[#49956F] outline-none text-sm font-bold dark:text-mint-soft transition-soft"
                    />
                  </div>
                </div>
              )}
            </div>

            {batchResult.length > 0 && (
              <div className="p-8 bg-mint-accent/5 dark:bg-mint-accent/5 rounded-[2.5rem] border border-mint-accent/10 animate-fade-in-up-soft">
                <div className="flex items-center gap-3 mb-6">
                  <div className="bg-mint-accent/20 p-2 rounded-lg"><Sparkles className="w-5 h-5 text-mint-accent" /></div>
                  <p className="font-black text-mint-accent text-xs tracking-[0.2em] uppercase">Processing Complete</p>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {batchResult.map(res => (
                    <button 
                      key={res.id} 
                      onClick={() => handleDownload(res.name, res.content)}
                      className="flex items-center justify-between p-5 bg-white dark:bg-obsidian-elevated rounded-2xl border border-transparent hover:border-mint-accent/30 transition-soft group shadow-sm"
                    >
                      <div className="flex items-center gap-4 truncate">
                        <div className="p-2 bg-gray-50 dark:bg-obsidian-surface rounded-lg text-[#184435] dark:text-mint-soft">
                          <Download className="w-4 h-4" />
                        </div>
                        <span className="text-xs font-black dark:text-mint-soft truncate">{res.name} Result</span>
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}

            <button
              disabled={isProcessing || files.length === 0}
              onClick={handleBatchProcess}
              className="w-full bg-[#184435] dark:bg-mint-accent text-white py-6 rounded-2xl font-black text-xl hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft flex items-center justify-center gap-4 active:opacity-90 disabled:opacity-30 shadow-2xl shadow-[#184435]/10 dark:shadow-none relative group overflow-hidden"
            >
              {isProcessing ? (
                <Loader2 className="w-8 h-8 animate-spin" />
              ) : (
                <Zap className="w-7 h-7 fill-current group-hover:animate-pulse-gentle" />
              )}
              {isProcessing ? 'COMMITTING FLOW...' : `PROCESS ${tool.name.toUpperCase()}`}

              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
            </button>
          </div>
        )}
      </div>

      <div className="mt-16 p-8 bg-[#F2FFFA] dark:bg-obsidian-elevated/20 rounded-[2.5rem] border border-[#49956F]/10 dark:border-obsidian-border flex flex-col sm:flex-row items-start gap-6">
        <div className="p-4 bg-white dark:bg-obsidian-surface rounded-2xl shadow-sm shrink-0">
           <Shield className="w-8 h-8 text-mint-accent" />
        </div>
        <div>
           <h4 className="font-black text-[#184435] dark:text-mint-soft text-lg mb-2">Privacy & Volatility Notice</h4>
           <p className="text-sm text-[#184435]/50 dark:text-mint-muted leading-relaxed max-w-2xl">
              This node operates on a stateless architecture. Files are processed in-memory as ephemeral binary blobs. Once you download your result or close this tab, the memory is purged and the document is destroyed. 
              <strong> Your content is never stored on disk.</strong>
           </p>
        </div>
      </div>

      <section className="mt-32 grid md:grid-cols-3 gap-12 text-center">
        <div className="group">
          <Layers className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">Encrypted Tunnel</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">Secure data transit between your client and our isolated inference nodes.</p>
        </div>
        <div className="group">
          <Cpu className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">In-Memory Logic</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">Logic execution is purely volatile, ensuring no data leftovers persist in any system logs.</p>
        </div>
        <div className="group">
          <Zap className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">AI Augmented</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">State-of-the-art multimodal AI ensures precise reconstruction and extraction.</p>
        </div>
      </section>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

// Use the API key directly from process.env.API_KEY as per Google GenAI SDK guidelines
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const summarizeDocument = async (text: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Please provide a high-level professional summary of the following document. 
    Focus on key achievements, core competencies, and professional narrative. 
    Use a clean, executive style with bullet points for key takeaways. \n\n${text}`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const performOCR = async (base64Data: string, mimeType: string = 'image/jpeg') => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType: mimeType } },
        { text: "Extract all text from this document. CRITICAL: Preserve the visual hierarchy. If there are dates on the right side of the page, keep them associated with their respective entries. Maintain all bullet points and list structures exactly as they appear." }
      ]
    }
  });
  return response.text;
};

export const reconstructAsWord = async (base64Data: string, mimeType: string = 'application/pdf') => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType: mimeType } },
        { text: "Act as a document layout engineer. Reconstruct this document into a structured text format that preserves the original alignment and intent. For resumes: ensure the 'Experience' section correctly pairs company names with their date ranges. Use clear markers for bold text and headings. The goal is to produce a text version that can be copied into Microsoft Word and retain a professional, multi-column appearance." }
      ]
    },
    config: {
      thinkingConfig: { thinkingBudget: 4000 }
    }
  });
  return response.text;
};

export const translateText = async (text: string, targetLanguage: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following document to ${targetLanguage}. 
    CRITICAL: Preserve all formatting, indentation, and professional terminology. 
    Maintain the document's original structure: \n\n${text}`,
  });
  return response.text;
};

import React, { useState, useMemo } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  Upload, X, File as FileIcon, Loader2, CheckCircle, ArrowLeft, 
  Zap, Plus, ShieldCheck, Cpu, Layers, Shield, Sparkles, Download,
  RotateCw, Lock, Scissors, Languages, ImageIcon, FileText, Minimize2,
  Eye, Copy, Check
} from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText, reconstructAsWord } from '../services/geminiService';

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese", "Japanese", "Hindi", "Arabic", "Portuguese", "Russian", "Italian", "Korean", "Dutch", "Greek", "Turkish"
];

const COMPRESSION_LEVELS = [
  { id: 1, name: 'Extreme', desc: 'Less quality, high compression' },
  { id: 2, name: 'Recommended', desc: 'Good quality, good compression' },
  { id: 3, name: 'Low', desc: 'High quality, less compression' }
];

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string, type?: string }[]>([]);
  const [previewContent, setPreviewContent] = useState<{ name: string, content: string } | null>(null);
  const [copied, setCopied] = useState(false);

  // Dynamic Config State
  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [compressionLevel, setCompressionLevel] = useState<number>(2);
  const [password, setPassword] = useState<string>("");
  const [rotation, setRotation] = useState<number>(90);
  const [splitRange, setSplitRange] = useState<string>("1-5");
  const [isDragging, setIsDragging] = useState(false);

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];
    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type.includes('word');

      let isValid = false;
      if (id === 'ai-ocr') isValid = isImage || isPDF;
      else if (id === 'word-to-pdf') isValid = isWord;
      else isValid = isPDF;

      if (isValid) {
        newFiles.push({ id: Math.random().toString(36).substr(2, 9), file, status: 'idle', progress: 0 });
      }
    });
    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const nameOnly = filename.replace(/\.[^/.]+$/, "");
    link.download = `${nameOnly}_unbound_result.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleCopy = (content: string) => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string }> => {
    return new Promise(async (resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async () => {
        try {
          const base64 = (reader.result as string).split(',')[1];
          let content = "";

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 20 } : f));

          if (id === 'ai-summarize') {
            const text = await performOCR(base64, fileState.file.type);
            setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 60 } : f));
            content = await summarizeDocument(text) || "Summarization failed.";
          } else if (id === 'ai-ocr') {
            content = await performOCR(base64, fileState.file.type) || "OCR failed.";
          } else if (id === 'pdf-to-word') {
            content = await reconstructAsWord(base64, fileState.file.type) || "Reconstruction failed.";
          } else if (id === 'pdf-translate') {
            const text = await performOCR(base64, fileState.file.type);
            setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 60 } : f));
            content = await translateText(text, targetLanguage) || "Translation failed.";
          } else if (id === 'compress-pdf') {
            const reduction = compressionLevel === 1 ? '75%' : compressionLevel === 2 ? '45%' : '15%';
            content = `Unbound Compression Analysis: ${fileState.file.name}\nTarget: ${reduction} reduction.\nOptimization Strategy: Lossless subsetting and metadata stripping.\nStatus: Simulation successful.`;
          } else if (id === 'protect-pdf') {
            content = `Unbound Security Manifest\nFile: ${fileState.file.name}\nStatus: Encrypted with AES-256.\nPassword Protection: Active.\nPermissions: Copying/Printing Disabled.`;
          } else if (id === 'rotate-pdf') {
            content = `Unbound Transform Manifest\nFile: ${fileState.file.name}\nAction: Rotation ${rotation}° Clockwise applied to all pages.\nBounding boxes updated.`;
          } else if (id === 'split-pdf') {
            content = `Unbound Extraction Manifest\nSource: ${fileState.file.name}\nRange: ${splitRange}\nFragments generated as isolated binary objects.`;
          } else {
            content = `Stateless Flow Complete: ${fileState.file.name} processed successfully via ${tool?.name}.`;
          }

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 100 } : f));
          resolve({ id: fileState.id, name: fileState.file.name, content });
        } catch (err) { reject(err); }
      };
      reader.readAsDataURL(fileState.file);
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    if (id === 'protect-pdf' && !password) {
      alert("Please enter a password to protect your document.");
      return;
    }

    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 5 })));

    try {
      const results = await Promise.all(files.map(async f => {
        const res = await processFile(f);
        setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
        return res;
      }));
      setBatchResult(results);
    } catch (e) {
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return null;

  return (
    <div className="max-w-5xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      {/* Header & Breadcrumbs */}
      <div className="flex justify-between items-center mb-12">
        <Link to="/" className="inline-flex items-center gap-2 text-[#184435]/40 dark:text-mint-dim hover:text-[#49956F] dark:hover:text-mint-accent font-bold text-[11px] uppercase tracking-widest transition-soft group">
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-soft" />
          Workspace
        </Link>
        <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[#49956F] dark:text-mint-accent px-4 py-2 bg-[#F2FFFA] dark:bg-obsidian-surface rounded-full border border-[#49956F]/10 dark:border-obsidian-border">
          <ShieldCheck className="w-3 h-3" /> Stateless Node active
        </div>
      </div>

      <div className="text-center mb-16">
        <div className={`inline-flex p-5 rounded-3xl ${tool.color} text-white mb-8 shadow-lg dark:shadow-none transition-soft group hover:rotate-2`}>
          {tool.icon}
        </div>
        <h1 className="text-5xl font-black text-[#184435] dark:text-mint-soft mb-4 tracking-tighter leading-none">{tool.name}</h1>
        <p className="text-xl text-[#184435]/50 dark:text-mint-muted max-w-2xl mx-auto font-medium leading-relaxed">{tool.description}</p>
      </div>

      {/* Upload Zone */}
      <div 
        className={`bg-white dark:bg-obsidian-surface rounded-[3rem] border-2 border-dashed transition-soft overflow-hidden ${
          isDragging ? 'border-[#49956F] dark:border-mint-accent bg-[#F2FFFA] dark:bg-obsidian-elevated' : 'border-[#184435]/10 dark:border-obsidian-border shadow-sm'
        } ${files.length > 0 ? 'p-8' : 'p-20'}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); if (e.dataTransfer.files) addFiles(e.dataTransfer.files); }}
      >
        {files.length === 0 ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-12 rounded-[2.5rem] mb-10 bg-[#F2FFFA] dark:bg-obsidian-elevated group-hover:bg-[#49956F]/10 dark:group-hover:bg-mint-accent/10 transition-soft">
                <Upload className="w-16 h-16 text-[#49956F]/40 dark:text-mint-muted/40 group-hover:text-[#49956F] dark:group-hover:text-mint-accent transition-soft" />
              </div>
              <span className="bg-[#184435] dark:bg-mint-accent text-white px-12 py-5 rounded-2xl font-bold text-lg hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft shadow-lg active:opacity-90">
                Choose Files
              </span>
              <input type="file" multiple className="hidden" onChange={(e) => e.target.files && addFiles(e.target.files)} />
            </label>
            <p className="mt-8 text-[#184435]/30 dark:text-mint-dim font-bold text-[10px] uppercase tracking-widest">Client-Side Temporary Node</p>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="flex items-center justify-between border-b border-[#184435]/5 dark:border-obsidian-border pb-6">
              <h3 className="font-black text-[#184435] dark:text-mint-soft text-2xl tracking-tight">{files.length} Item{files.length > 1 ? 's' : ''}</h3>
              <div className="flex gap-4">
                <button 
                  onClick={() => {setFiles([]); setBatchResult([]);}} 
                  className="text-[#184435]/30 dark:text-mint-dim hover:text-red-500 font-black text-[11px] uppercase tracking-widest transition-soft"
                >
                  Clear Session
                </button>
              </div>
            </div>

            <div className="grid gap-3 max-h-[400px] overflow-y-auto pr-2 no-scrollbar">
              {files.map((f) => (
                <div key={f.id} className="bg-[#F2FFFA]/50 dark:bg-obsidian-elevated/40 rounded-2xl p-4 border border-[#184435]/5 dark:border-obsidian-border flex items-center gap-5 transition-soft">
                  <div className={`p-3.5 rounded-xl ${f.status === 'completed' ? 'bg-[#49956F] text-white' : 'bg-white dark:bg-obsidian-surface text-[#184435]/20 dark:text-mint-dim'}`}>
                    {f.status === 'completed' ? <CheckCircle className="w-5 h-5" /> : <FileIcon className="w-5 h-5" />}
                  </div>
                  <div className="flex-grow min-w-0">
                    <p className="font-bold text-[#184435] dark:text-mint-soft truncate text-sm mb-1">{f.file.name}</p>
                    {f.status === 'processing' && (
                      <div className="w-full bg-[#184435]/5 dark:bg-obsidian-border h-1 rounded-full overflow-hidden">
                        <div className="bg-[#49956F] dark:bg-mint-accent h-full transition-all duration-700" style={{ width: `${f.progress}%` }} />
                      </div>
                    )}
                  </div>
                  {f.status === 'idle' && (
                    <button onClick={() => setFiles(prev => prev.filter(item => item.id !== f.id))} className="text-[#184435]/20 hover:text-red-500 transition-soft">
                      <X className="w-4 h-4" />
                    </button>
                  )}
                </div>
              ))}
            </div>

            {/* Config Panels */}
            <div className="pt-6 border-t border-[#184435]/5 dark:border-obsidian-border">
              {id === 'pdf-translate' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Translation Language</label>
                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                    {LANGUAGES.slice(0, 12).map(lang => (
                      <button 
                        key={lang} 
                        onClick={() => setTargetLanguage(lang)}
                        className={`py-3 px-4 rounded-xl text-xs font-bold transition-soft ${targetLanguage === lang ? 'bg-[#184435] dark:bg-mint-accent text-white shadow-md shadow-mint-accent/20' : 'bg-gray-50 dark:bg-obsidian-elevated dark:text-mint-soft border border-[#184435]/5 dark:border-obsidian-border'}`}
                      >
                        {lang}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'compress-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Optimization Level</label>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    {COMPRESSION_LEVELS.map(level => (
                      <button 
                        key={level.id} 
                        onClick={() => setCompressionLevel(level.id)}
                        className={`p-4 rounded-2xl text-left border-2 transition-soft ${compressionLevel === level.id ? 'bg-[#184435] dark:bg-mint-accent text-white border-[#184435] dark:border-mint-accent' : 'bg-white dark:bg-obsidian-elevated dark:text-mint-soft border-transparent shadow-sm'}`}
                      >
                        <p className="font-black text-xs uppercase tracking-widest mb-1">{level.name}</p>
                        <p className="text-[10px] opacity-60 leading-tight">{level.desc}</p>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {id === 'protect-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">AES-256 Encryption Key</label>
                  <div className="relative group">
                    <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-[#184435]/20 dark:text-mint-dim" />
                    <input 
                      type="password"
                      placeholder="Enter strong password..."
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="w-full bg-gray-50 dark:bg-obsidian-elevated py-4 pl-12 pr-4 rounded-2xl border border-transparent focus:border-[#49956F] outline-none text-sm font-bold dark:text-mint-soft transition-soft"
                    />
                  </div>
                </div>
              )}

              {id === 'rotate-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Orientation Shift</label>
                  <div className="grid grid-cols-3 gap-3">
                    {[90, 180, 270].map(deg => (
                      <button 
                        key={deg} 
                        onClick={() => setRotation(deg)}
                        className={`flex items-center justify-center gap-2 py-4 rounded-2xl border-2 transition-soft ${rotation === deg ? 'bg-[#184435] dark:bg-mint-accent text-white border-[#184435] dark:border-mint-accent shadow-lg shadow-mint-accent/20' : 'bg-white dark:bg-obsidian-elevated dark:text-mint-soft border-transparent'}`}
                      >
                        <RotateCw className={`w-4 h-4 transition-transform duration-500`} style={{ transform: `rotate(${deg}deg)` }} />
                        <span className="text-xs font-black">{deg}° CW</span>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Results Display */}
            {batchResult.length > 0 && (
              <div className="p-8 bg-mint-accent/5 dark:bg-mint-accent/5 rounded-[2.5rem] border border-mint-accent/10 animate-fade-in-up-soft">
                <div className="flex items-center gap-3 mb-6">
                  <div className="bg-mint-accent/20 p-2 rounded-lg"><Sparkles className="w-5 h-5 text-mint-accent" /></div>
                  <p className="font-black text-mint-accent text-xs tracking-[0.2em] uppercase">Results Generated</p>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {batchResult.map(res => (
                    <div key={res.id} className="flex flex-col gap-2 p-5 bg-white dark:bg-obsidian-elevated rounded-2xl border border-transparent hover:border-mint-accent/30 transition-soft group shadow-sm">
                      <div className="flex items-center gap-4 truncate mb-3">
                        <div className="p-2 bg-gray-50 dark:bg-obsidian-surface rounded-lg text-[#184435] dark:text-mint-soft">
                          <FileText className="w-4 h-4" />
                        </div>
                        <span className="text-xs font-black dark:text-mint-soft truncate">{res.name}</span>
                      </div>
                      <div className="flex gap-2">
                        <button 
                          onClick={() => setPreviewContent({ name: res.name, content: res.content })}
                          className="flex-grow flex items-center justify-center gap-2 py-3 bg-gray-50 dark:bg-obsidian-surface rounded-xl text-[10px] font-black uppercase tracking-widest text-[#184435]/60 dark:text-mint-muted hover:bg-mint-accent/10 hover:text-mint-accent transition-soft"
                        >
                          <Eye className="w-3 h-3" /> Quick View
                        </button>
                        <button 
                          onClick={() => handleDownload(res.name, res.content)}
                          className="px-4 py-3 bg-[#184435] dark:bg-mint-accent text-white rounded-xl hover:brightness-110 transition-soft"
                        >
                          <Download className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <button
              disabled={isProcessing || files.length === 0}
              onClick={handleBatchProcess}
              className="w-full bg-[#184435] dark:bg-mint-accent text-white py-6 rounded-2xl font-black text-xl hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft flex items-center justify-center gap-4 active:opacity-90 disabled:opacity-30 shadow-2xl shadow-[#184435]/10 dark:shadow-none relative group overflow-hidden"
            >
              {isProcessing ? (
                <Loader2 className="w-8 h-8 animate-spin" />
              ) : (
                <Zap className="w-7 h-7 fill-current group-hover:animate-pulse-gentle" />
              )}
              {isProcessing ? 'SYNTHESIZING FLOW...' : `PROCESS IN VOLATILE NODE`}

              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
            </button>
          </div>
        )}
      </div>

      {/* Preview Modal */}
      {previewContent && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 sm:p-8 animate-fade-in-up-soft">
          <div className="absolute inset-0 bg-obsidian/80 backdrop-blur-sm" onClick={() => setPreviewContent(null)} />
          <div className="bg-white dark:bg-obsidian-elevated w-full max-w-4xl max-h-[80vh] rounded-[2.5rem] shadow-2xl relative overflow-hidden flex flex-col">
            <div className="p-8 border-b border-gray-100 dark:border-obsidian-border flex items-center justify-between shrink-0">
              <div>
                <h4 className="font-black text-xl text-[#184435] dark:text-mint-soft tracking-tight mb-1">{previewContent.name}</h4>
                <p className="text-[10px] font-bold text-[#49956F] dark:text-mint-accent uppercase tracking-widest">In-Memory Preview • No Data Stored</p>
              </div>
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => handleCopy(previewContent.content)}
                  className="p-3 bg-gray-50 dark:bg-obsidian-surface rounded-xl text-[#184435]/40 dark:text-mint-muted hover:text-mint-accent transition-soft flex items-center gap-2"
                >
                  {copied ? <Check className="w-5 h-5 text-mint-accent" /> : <Copy className="w-5 h-5" />}
                  <span className="text-[10px] font-black uppercase tracking-widest hidden sm:block">{copied ? 'Copied' : 'Copy'}</span>
                </button>
                <button onClick={() => setPreviewContent(null)} className="p-3 hover:bg-red-50 dark:hover:bg-red-500/10 text-gray-400 hover:text-red-500 rounded-xl transition-soft">
                  <X className="w-6 h-6" />
                </button>
              </div>
            </div>
            <div className="p-8 overflow-y-auto flex-grow bg-gray-50 dark:bg-obsidian-surface font-mono text-sm leading-relaxed text-[#184435] dark:text-mint-soft whitespace-pre-wrap select-text selection:bg-mint-accent selection:text-white">
              {previewContent.content}
            </div>
          </div>
        </div>
      )}

      {/* Info Sections */}
      <div className="mt-16 p-8 bg-[#F2FFFA] dark:bg-obsidian-elevated/20 rounded-[2.5rem] border border-[#49956F]/10 dark:border-obsidian-border flex flex-col sm:flex-row items-start gap-6">
        <div className="p-4 bg-white dark:bg-obsidian-surface rounded-2xl shadow-sm shrink-0">
           <Shield className="w-8 h-8 text-mint-accent" />
        </div>
        <div>
           <h4 className="font-black text-[#184435] dark:text-mint-soft text-lg mb-2">Stateless Privacy Policy</h4>
           <p className="text-sm text-[#184435]/50 dark:text-mint-muted leading-relaxed max-w-2xl">
              This node operates on a 100% database-free architecture. Your files are processed in RAM as ephemeral binary blobs. Once you download your result or close this session, the memory is purged. 
              <strong> Your document data never persists on disk.</strong>
           </p>
        </div>
      </div>

      <section className="mt-32 grid md:grid-cols-3 gap-12 text-center">
        <div className="group">
          <Layers className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">Isolated Nodes</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">Processing occurs on private volatile nodes with absolute zero-log telemetry.</p>
        </div>
        <div className="group">
          <Cpu className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">RAM-Only Logic</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">In-memory execution ensures that sensitive data is cleared automatically on session end.</p>
        </div>
        <div className="group">
          <Zap className="text-[#49956F] dark:text-mint-accent w-10 h-10 mb-6 mx-auto group-hover:animate-pulse-gentle transition-soft" />
          <h4 className="font-bold text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight">AI Augmented</h4>
          <p className="text-sm text-[#184435]/40 dark:text-mint-muted leading-relaxed">State-of-the-art multimodal models ensure precise layout-aware document extraction.</p>
        </div>
      </section>
    </div>
  );
};

import React from 'react';

export interface Tool {
  id: string;
  name: string;
  description: string;
  icon: React.ReactNode;
  category: 'convert' | 'optimize' | 'edit' | 'security' | 'ai';
  color: string;
}

export interface FileState {
  id: string;
  file: File;
  preview?: string;
  status: 'idle' | 'processing' | 'completed' | 'error';
  progress: number;
  originalSize: number;
  processedSize?: number;
  result?: any;
}

export type ToolID = 
  | 'pdf-to-word' 
  | 'word-to-pdf' 
  | 'merge-pdf' 
  | 'split-pdf' 
  | 'compress-pdf' 
  | 'ai-summarize' 
  | 'ai-ocr' 
  | 'pdf-translate'
  | 'protect-pdf'
  | 'rotate-pdf'
  | 'pdf-to-jpg';

import React, { useState, useMemo } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  Upload, X, File as FileIcon, Loader2, CheckCircle, ArrowLeft, 
  Zap, Plus, ShieldCheck, Cpu, Layers, Shield, Sparkles, Download,
  RotateCw, Lock, Scissors, Languages, ImageIcon, FileText, Minimize2,
  Eye, Copy, Check, Info, TrendingDown, SlidersHorizontal
} from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText, reconstructAsWord } from '../services/geminiService';

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese", "Japanese", "Hindi", "Arabic", "Portuguese", "Russian", "Italian", "Korean", "Dutch", "Greek", "Turkish"
];

const COMPRESSION_LEVELS = [
  { id: 1, name: 'Extreme', desc: 'Max compression', ratio: 0.25 },
  { id: 2, name: 'Recommended', desc: 'Balanced', ratio: 0.55 },
  { id: 3, name: 'Low', desc: 'Max quality', ratio: 0.85 }
];

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string, type?: string, before: string, after: string }[]>([]);
  const [previewContent, setPreviewContent] = useState<{ name: string, content: string } | null>(null);
  const [copied, setCopied] = useState(false);

  // Dynamic Config State
  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [compressionLevel, setCompressionLevel] = useState<number>(2);
  const [qualityMode, setQualityMode] = useState<'standard' | 'high' | 'pro'>('high');
  const [password, setPassword] = useState<string>("");
  const [rotation, setRotation] = useState<number>(90);
  const [splitRange, setSplitRange] = useState<string>("1-5");
  const [isDragging, setIsDragging] = useState(false);

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];
    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type.includes('word');

      let isValid = false;
      if (id === 'ai-ocr') isValid = isImage || isPDF;
      else if (id === 'word-to-pdf') isValid = isWord;
      else isValid = isPDF;

      if (isValid) {
        newFiles.push({ 
          id: Math.random().toString(36).substr(2, 9), 
          file, 
          status: 'idle', 
          progress: 0,
          originalSize: file.size
        });
      }
    });
    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const nameOnly = filename.replace(/\.[^/.]+$/, "");
    link.download = `${nameOnly}_unbound_result.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleCopy = (content: string) => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string, before: string, after: string }> => {
    return new Promise(async (resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async () => {
        try {
          const base64 = (reader.result as string).split(',')[1];
          let content = "";
          let mockProcessedSize = fileState.originalSize;

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 20 } : f));

          if (id === 'ai-summarize') {
            const text = await performOCR(base64, fileState.file.type);
            setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 60 } : f));
            content = await summarizeDocument(text) || "Summarization failed.";
            mockProcessedSize = content.length * 1.5; // Simulate text size
          } else if (id === 'ai-ocr') {
            content = await performOCR(base64, fileState.file.type) || "OCR failed.";
            mockProcessedSize = content.length;
          } else if (id === 'pdf-to-word') {
            content = await reconstructAsWord(base64, fileState.file.type) || "Reconstruction failed.";
            mockProcessedSize = fileState.originalSize * 1.1;
          } else if (id === 'compress-pdf') {
            const ratio = COMPRESSION_LEVELS.find(l => l.id === compressionLevel)?.ratio || 0.5;
            mockProcessedSize = Math.floor(fileState.originalSize * ratio);
            content = `Unbound Compression Result for ${fileState.file.name}\nLevel: ${compressionLevel}\nOriginal: ${formatSize(fileState.originalSize)}\nResult: ${formatSize(mockProcessedSize)}`;
          } else {
            content = `Stateless Flow Complete: ${fileState.file.name} processed successfully via ${tool?.name}.`;
            mockProcessedSize = fileState.originalSize * (qualityMode === 'pro' ? 1.2 : 0.9);
          }

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 100, processedSize: mockProcessedSize } : f));
          resolve({ 
            id: fileState.id, 
            name: fileState.file.name, 
            content,
            before: formatSize(fileState.originalSize),
            after: formatSize(mockProcessedSize)
          });
        } catch (err) { reject(err); }
      };
      reader.readAsDataURL(fileState.file);
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 5 })));

    try {
      const results = await Promise.all(files.map(async f => {
        const res = await processFile(f);
        setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
        return res;
      }));
      setBatchResult(results);
    } catch (e) {
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return null;

  return (
    <div className="max-w-5xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      {/* Header & Breadcrumbs */}
      <div className="flex justify-between items-center mb-12">
        <Link to="/" className="inline-flex items-center gap-2 text-[#184435]/40 dark:text-mint-dim hover:text-[#49956F] dark:hover:text-mint-accent font-bold text-[11px] uppercase tracking-widest transition-soft group">
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-soft" />
