      <div 
        className={`bg-white dark:bg-obsidian-surface rounded-[3rem] border-2 border-dashed transition-soft overflow-hidden ${
          isDragging ? 'border-[#49956F] dark:border-mint-accent bg-[#F2FFFA] dark:bg-obsidian-elevated' : 'border-[#184435]/10 dark:border-obsidian-border shadow-sm'
