              </span>
              <input type="file" multiple className="hidden" onChange={(e) => e.target.files && addFiles(e.target.files)} />
            </label>
            <p className="mt-8 text-[#184435]/30 dark:text-mint-dim font-bold text-[10px] uppercase tracking-widest">Client-Side Temporary Node</p>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="flex items-center justify-between border-b border-[#184435]/5 dark:border-obsidian-border pb-6">
              <h3 className="font-black text-[#184435] dark:text-mint-soft text-2xl tracking-tight">Queue: {files.length} Item{files.length > 1 ? 's' : ''}</h3>
              <div className="flex gap-4">
                <button 
                  onClick={() => {setFiles([]); setBatchResult([]);}} 
                  className="text-[#184435]/30 dark:text-mint-dim hover:text-red-500 font-black text-[11px] uppercase tracking-widest transition-soft"
                >
                  Clear Queue
                </button>
              </div>
            </div>

            <div className="grid gap-3 max-h-[400px] overflow-y-auto pr-2 no-scrollbar">
              {files.map((f) => (
                <div key={f.id} className="bg-[#F2FFFA]/50 dark:bg-obsidian-elevated/40 rounded-2xl p-4 border border-[#184435]/5 dark:border-obsidian-border flex items-center gap-5 transition-soft group">
                  <div className={`p-3.5 rounded-xl ${f.status === 'completed' ? 'bg-[#49956F] text-white' : 'bg-white dark:bg-obsidian-surface text-[#184435]/20 dark:text-mint-dim'}`}>
                    {f.status === 'completed' ? <CheckCircle className="w-5 h-5" /> : <FileIcon className="w-5 h-5" />}
                  </div>
                  <div className="flex-grow min-w-0">
                    <p className="font-bold text-[#184435] dark:text-mint-soft truncate text-sm mb-1">{f.file.name}</p>
                    <div className="flex items-center gap-3">
                       <span className="text-[10px] font-black uppercase text-[#184435]/30 dark:text-mint-dim tracking-widest">{formatSize(f.originalSize)}</span>
                       {f.processedSize && (
                         <>
                           <ArrowRightLeft className="w-2.5 h-2.5 text-mint-accent" />
                           <span className="text-[10px] font-black uppercase text-mint-accent tracking-widest">{formatSize(f.processedSize)}</span>
                         </>
                       )}
                    </div>
                    {f.status === 'processing' && (
                      <div className="w-full bg-[#184435]/5 dark:bg-obsidian-border h-1 mt-2 rounded-full overflow-hidden">
                        <div className="bg-[#49956F] dark:bg-mint-accent h-full transition-all duration-700" style={{ width: `${f.progress}%` }} />
                      </div>
                    )}
                  </div>
                  {f.status === 'idle' && (
                    <button onClick={() => setFiles(prev => prev.filter(item => item.id !== f.id))} className="opacity-0 group-hover:opacity-100 p-2 text-[#184435]/20 hover:text-red-500 transition-soft">
                      <X className="w-4 h-4" />
                    </button>
                  )}
                </div>
              ))}
            </div>

            {/* Config Panels & Quality Button */}
            <div className="pt-6 border-t border-[#184435]/5 dark:border-obsidian-border space-y-8">
              <div className="flex flex-col sm:flex-row items-center justify-between gap-6">
                <div className="flex-grow w-full">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1 mb-4 flex items-center gap-2">
                    <SlidersHorizontal className="w-3 h-3" /> Synthesis Quality
                  </label>
                  <div className="flex bg-gray-50 dark:bg-obsidian-elevated p-1 rounded-2xl border border-[#184435]/5 dark:border-obsidian-border">
                    {[
                      { id: 'standard', label: 'Draft', desc: 'Fastest' },
                      { id: 'high', label: 'Premium', desc: 'Balanced' },
                      { id: 'pro', label: 'Ultra', desc: 'Max Detail' }
                    ].map(mode => (
                      <button
                        key={mode.id}
                        onClick={() => setQualityMode(mode.id as any)}
                        className={`flex-grow px-4 py-3 rounded-xl transition-soft text-center group ${qualityMode === mode.id ? 'bg-white dark:bg-obsidian-surface shadow-md' : 'hover:bg-black/5 dark:hover:bg-white/5'}`}
                      >
                        <p className={`text-[11px] font-black uppercase tracking-widest ${qualityMode === mode.id ? 'text-[#184435] dark:text-mint-soft' : 'text-[#184435]/30 dark:text-mint-dim'}`}>{mode.label}</p>
                        <p className={`text-[8px] font-bold uppercase tracking-widest mt-0.5 ${qualityMode === mode.id ? 'text-mint-accent' : 'text-[#184435]/20 dark:text-mint-dim/40'}`}>{mode.desc}</p>
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              {id === 'compress-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Optimization Ratio</label>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    {COMPRESSION_LEVELS.map(level => (
                      <button 
                        key={level.id} 
                        onClick={() => setCompressionLevel(level.id)}
                        className={`p-4 rounded-2xl text-left border-2 transition-soft ${compressionLevel === level.id ? 'bg-[#184435] dark:bg-mint-accent text-white border-[#184435] dark:border-mint-accent' : 'bg-white dark:bg-obsidian-elevated dark:text-mint-soft border-transparent shadow-sm'}`}
                      >
                        <p className="font-black text-xs uppercase tracking-widest mb-1">{level.name}</p>
                        <p className="text-[10px] opacity-60 leading-tight">{level.desc}</p>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Main Action Button */}
            <button
              disabled={isProcessing || files.length === 0}
              onClick={handleBatchProcess}
              className="w-full bg-[#184435] dark:bg-mint-accent text-white py-6 rounded-2xl font-black text-xl hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft flex items-center justify-center gap-4 active:opacity-90 disabled:opacity-30 shadow-2xl shadow-[#184435]/10 dark:shadow-none relative group overflow-hidden"
            >
              {isProcessing ? (
                <Loader2 className="w-8 h-8 animate-spin" />
              ) : (
                <Zap className="w-7 h-7 fill-current group-hover:animate-pulse-gentle" />
              )}
              {isProcessing ? 'PROCESSING...' : `PROCESS ${files.length} ITEM${files.length !== 1 ? 'S' : ''}`}

              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
            </button>
          </div>
        )}
      </div>

      {/* Results Comparison Table */}
      {batchResult.length > 0 && (
        <div className="mt-12 p-8 bg-mint-accent/5 dark:bg-mint-accent/5 rounded-[3rem] border border-mint-accent/10 animate-fade-in-up-soft overflow-hidden">
          <div className="flex flex-col sm:flex-row items-center justify-between gap-6 mb-8">
            <div className="flex items-center gap-3">
              <div className="bg-mint-accent/20 p-2 rounded-lg"><TrendingDown className="w-5 h-5 text-mint-accent" /></div>
              <div>
                <p className="font-black text-mint-accent text-[10px] tracking-[0.2em] uppercase">Results Analysis</p>
                <p className="text-[#184435]/40 dark:text-mint-muted text-[10px] font-bold uppercase tracking-widest">Optimized in volatile memory</p>
              </div>
            </div>
            <button 
              onClick={() => batchResult.forEach(r => handleDownload(r.name, r.content))}
              className="flex items-center gap-2 bg-[#184435] dark:bg-mint-accent text-white px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg hover:brightness-110 transition-soft"
            >
              <Download className="w-4 h-4" /> Download All
            </button>
          </div>

          <div className="grid gap-3">
            {batchResult.map(res => (
              <div key={res.id} className="bg-white dark:bg-obsidian-elevated p-5 rounded-2xl flex flex-col sm:flex-row items-center justify-between gap-6 border border-transparent hover:border-mint-accent/30 transition-soft group">
                <div className="flex items-center gap-4 min-w-0 flex-grow">
                  <div className="p-2.5 bg-gray-50 dark:bg-obsidian-surface rounded-xl text-mint-accent">
                    <FileText className="w-5 h-5" />
                  </div>
                  <div className="truncate">
                    <p className="text-sm font-black dark:text-mint-soft truncate">{res.name}</p>
                    <div className="flex items-center gap-2 mt-0.5">
                       <span className="text-[9px] font-black text-[#184435]/30 dark:text-mint-dim uppercase tracking-wider line-through">{res.before}</span>
                       <ArrowRightLeft className="w-2.5 h-2.5 text-mint-accent" />
                       <span className="text-[9px] font-black text-mint-accent uppercase tracking-wider">{res.after}</span>
                    </div>
                  </div>
                </div>
                <div className="flex gap-2 shrink-0">
                  <button 
                    onClick={() => setPreviewContent({ name: res.name, content: res.content })}
                    className="p-3 bg-gray-50 dark:bg-obsidian-surface rounded-xl text-[#184435]/40 dark:text-mint-muted hover:text-mint-accent transition-soft"
                  >
                    <Eye className="w-5 h-5" />
                  </button>
                  <button 
                    onClick={() => handleDownload(res.name, res.content)}
                    className="p-3 bg-mint-accent/10 dark:bg-mint-accent/20 text-mint-accent rounded-xl hover:bg-mint-accent hover:text-white transition-soft"
                  >
                    <Download className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Preview Modal */}
      {previewContent && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 sm:p-8 animate-fade-in-up-soft">
          <div className="absolute inset-0 bg-obsidian/80 backdrop-blur-sm" onClick={() => setPreviewContent(null)} />
          <div className="bg-white dark:bg-obsidian-elevated w-full max-w-4xl max-h-[80vh] rounded-[2.5rem] shadow-2xl relative overflow-hidden flex flex-col">
            <div className="p-8 border-b border-gray-100 dark:border-obsidian-border flex items-center justify-between shrink-0">
              <div>
                <h4 className="font-black text-xl text-[#184435] dark:text-mint-soft tracking-tight mb-1">{previewContent.name}</h4>
                <p className="text-[10px] font-bold text-[#49956F] dark:text-mint-accent uppercase tracking-widest">In-Memory Preview • Stateless Node</p>
              </div>
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => handleCopy(previewContent.content)}
                  className="p-3 bg-gray-50 dark:bg-obsidian-surface rounded-xl text-[#184435]/40 dark:text-mint-muted hover:text-mint-accent transition-soft flex items-center gap-2"
                >
                  {copied ? <Check className="w-5 h-5 text-mint-accent" /> : <Copy className="w-5 h-5" />}
                  <span className="text-[10px] font-black uppercase tracking-widest hidden sm:block">{copied ? 'Copied' : 'Copy'}</span>
                </button>
                <button onClick={() => setPreviewContent(null)} className="p-3 hover:bg-red-50 dark:hover:bg-red-500/10 text-gray-400 hover:text-red-500 rounded-xl transition-soft">
                  <X className="w-6 h-6" />
                </button>
              </div>
            </div>
            <div className="p-8 overflow-y-auto flex-grow bg-gray-50 dark:bg-obsidian-surface font-mono text-sm leading-relaxed text-[#184435] dark:text-mint-soft whitespace-pre-wrap select-text selection:bg-mint-accent selection:text-white">
              {previewContent.content}
            </div>
          </div>
        </div>
      )}

      {/* Info Sections */}
      <div className="mt-16 p-10 bg-[#F2FFFA] dark:bg-obsidian-elevated/20 rounded-[3rem] border border-[#49956F]/10 dark:border-obsidian-border flex flex-col lg:flex-row items-center gap-10">
        <div className="p-6 bg-white dark:bg-obsidian-surface rounded-[2rem] shadow-sm shrink-0 flex items-center justify-center">
           <Shield className="w-12 h-12 text-mint-accent" />
        </div>
        <div className="text-center lg:text-left">
           <h4 className="font-black text-[#184435] dark:text-mint-soft text-xl mb-3">Professional Privacy Standard</h4>
           <p className="text-sm text-[#184435]/50 dark:text-mint-muted leading-relaxed max-w-2xl">
              Unbound employs a <strong>zero-disk architecture</strong>. Your documents are streamed directly to volatile RAM nodes, processed by high-performance inference units, and wiped immediately upon completion. We provide absolute mathematical certainty that your documents do not persist.
           </p>
        </div>
      </div>

      <section className="mt-32 grid md:grid-cols-3 gap-12 text-center pb-20">
        {[
          { icon: <Layers />, title: "Stateless Synthesis", text: "Processing occurs in temporary cloud containers that self-destruct after use." },
          { icon: <Cpu />, title: "Layout Engine", text: "Proprietary AI reconstructions ensure pixel-perfect text and object positioning." },
          { icon: <Shield />, title: "Military Grade", text: "AES-256 standard encryption for all protected document workflows." }
        ].map((feat, i) => (
          <div key={i} className="group p-8 rounded-[2.5rem] bg-white/30 dark:bg-obsidian-surface/30 hover:bg-white dark:hover:bg-obsidian-surface transition-soft">
            <div className="text-[#49956F] dark:text-mint-accent w-12 h-12 mb-6 mx-auto group-hover:scale-110 transition-soft">
              {React.cloneElement(feat.icon as React.ReactElement, { className: 'w-full h-full' })}
            </div>
            <h4 className="font-black text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight uppercase tracking-widest text-[13px]">{feat.title}</h4>
            <p className="text-xs text-[#184435]/40 dark:text-mint-muted leading-relaxed font-medium">{feat.text}</p>
          </div>
        ))}
      </section>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  Upload, X, File as FileIcon, Loader2, CheckCircle, ArrowLeft, 
  Zap, Plus, ShieldCheck, Cpu, Layers, Shield, Sparkles, Download,
  RotateCw, Lock, Scissors, Languages, ImageIcon, FileText, Minimize2,
  Eye, Copy, Check, Info, TrendingDown, SlidersHorizontal, ArrowRightLeft
} from 'lucide-react';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText, reconstructAsWord } from '../services/geminiService';

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese", "Japanese", "Hindi", "Arabic", "Portuguese", "Russian", "Italian", "Korean", "Dutch", "Greek", "Turkish"
];

const COMPRESSION_LEVELS = [
  { id: 1, name: 'Extreme', desc: 'Max compression', ratio: 0.25 },
  { id: 2, name: 'Recommended', desc: 'Balanced', ratio: 0.55 },
  { id: 3, name: 'Low', desc: 'Max quality', ratio: 0.85 }
];

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string, type?: string, before: string, after: string }[]>([]);
  const [previewContent, setPreviewContent] = useState<{ name: string, content: string } | null>(null);
  const [copied, setCopied] = useState(false);

  // Dynamic Config State
  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [compressionLevel, setCompressionLevel] = useState<number>(2);
  const [qualityMode, setQualityMode] = useState<'standard' | 'high' | 'pro'>('high');
  const [password, setPassword] = useState<string>("");
  const [rotation, setRotation] = useState<number>(90);
  const [splitRange, setSplitRange] = useState<string>("1-5");
  const [isDragging, setIsDragging] = useState(false);

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];
    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type.includes('word');

      let isValid = false;
      if (id === 'ai-ocr') isValid = isImage || isPDF;
      else if (id === 'word-to-pdf') isValid = isWord;
      else isValid = isPDF;

      if (isValid) {
        newFiles.push({ 
          id: Math.random().toString(36).substr(2, 9), 
          file, 
          status: 'idle', 
          progress: 0,
          originalSize: file.size
        });
      }
    });
    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const nameOnly = filename.replace(/\.[^/.]+$/, "");
    link.download = `${nameOnly}_unbound_result.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleCopy = (content: string) => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string, before: string, after: string }> => {
    return new Promise(async (resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async () => {
        try {
          const base64 = (reader.result as string).split(',')[1];
          let content = "";
          let mockProcessedSize = fileState.originalSize;

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 20 } : f));

          if (id === 'ai-summarize') {
            const text = await performOCR(base64, fileState.file.type);
            setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 60 } : f));
            content = await summarizeDocument(text) || "Summarization failed.";
            mockProcessedSize = content.length * 1.5; // Simulate text size
          } else if (id === 'ai-ocr') {
            content = await performOCR(base64, fileState.file.type) || "OCR failed.";
            mockProcessedSize = content.length;
          } else if (id === 'pdf-to-word') {
            content = await reconstructAsWord(base64, fileState.file.type) || "Reconstruction failed.";
            mockProcessedSize = fileState.originalSize * 1.1;
          } else if (id === 'compress-pdf') {
            const ratio = COMPRESSION_LEVELS.find(l => l.id === compressionLevel)?.ratio || 0.5;
            mockProcessedSize = Math.floor(fileState.originalSize * ratio);
            content = `Unbound Compression Result for ${fileState.file.name}\nLevel: ${compressionLevel}\nOriginal: ${formatSize(fileState.originalSize)}\nResult: ${formatSize(mockProcessedSize)}`;
          } else {
            content = `Stateless Flow Complete: ${fileState.file.name} processed successfully via ${tool?.name}.`;
            mockProcessedSize = fileState.originalSize * (qualityMode === 'pro' ? 1.2 : 0.9);
          }

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 100, processedSize: mockProcessedSize } : f));
          resolve({ 
            id: fileState.id, 
            name: fileState.file.name, 
            content,
            before: formatSize(fileState.originalSize),
            after: formatSize(mockProcessedSize)
          });
        } catch (err) { reject(err); }
      };
      reader.readAsDataURL(fileState.file);
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 5 })));

    try {
      const results = await Promise.all(files.map(async f => {
        const res = await processFile(f);
        setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
        return res;
      }));
      setBatchResult(results);
    } catch (e) {
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return null;

  return (
    <div className="max-w-5xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      {/* Header & Breadcrumbs */}
      <div className="flex justify-between items-center mb-12">
        <Link to="/" className="inline-flex items-center gap-2 text-[#184435]/40 dark:text-mint-dim hover:text-[#49956F] dark:hover:text-mint-accent font-bold text-[11px] uppercase tracking-widest transition-soft group">
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-soft" />
          Workspace
        </Link>
        <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[#49956F] dark:text-mint-accent px-4 py-2 bg-[#F2FFFA] dark:bg-obsidian-surface rounded-full border border-[#49956F]/10 dark:border-obsidian-border">
          <ShieldCheck className="w-3 h-3" /> Stateless Node active
        </div>
      </div>

      <div className="text-center mb-16">
        <div className={`inline-flex p-5 rounded-3xl ${tool.color} text-white mb-8 shadow-lg dark:shadow-none transition-soft group hover:rotate-2`}>
          {tool.icon}
        </div>
        <h1 className="text-5xl font-black text-[#184435] dark:text-mint-soft mb-4 tracking-tighter leading-none">{tool.name}</h1>
        <p className="text-xl text-[#184435]/50 dark:text-mint-muted max-w-2xl mx-auto font-medium leading-relaxed">{tool.description}</p>
      </div>

      {/* Upload Zone */}
      <div 
        className={`bg-white dark:bg-obsidian-surface rounded-[3rem] border-2 border-dashed transition-soft overflow-hidden ${
          isDragging ? 'border-[#49956F] dark:border-mint-accent bg-[#F2FFFA] dark:bg-obsidian-elevated' : 'border-[#184435]/10 dark:border-obsidian-border shadow-sm'
        } ${files.length > 0 ? 'p-8' : 'p-20'}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); if (e.dataTransfer.files) addFiles(e.dataTransfer.files); }}
      >
        {files.length === 0 ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-12 rounded-[2.5rem] mb-10 bg-[#F2FFFA] dark:bg-obsidian-elevated group-hover:bg-[#49956F]/10 dark:group-hover:bg-mint-accent/10 transition-soft">
                <Upload className="w-16 h-16 text-[#49956F]/40 dark:text-mint-muted/40 group-hover:text-[#49956F] dark:group-hover:text-mint-accent transition-soft" />
              </div>
              <span className="bg-[#184435] dark:bg-mint-accent text-white px-12 py-5 rounded-2xl font-bold text-lg hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft shadow-lg active:opacity-90">
                Choose Files
              </span>
              <input type="file" multiple className="hidden" onChange={(e) => e.target.files && addFiles(e.target.files)} />
            </label>
            <p className="mt-8 text-[#184435]/30 dark:text-mint-dim font-bold text-[10px] uppercase tracking-widest">Client-Side Temporary Node</p>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="flex items-center justify-between border-b border-[#184435]/5 dark:border-obsidian-border pb-6">
              <h3 className="font-black text-[#184435] dark:text-mint-soft text-2xl tracking-tight">Queue: {files.length} Item{files.length > 1 ? 's' : ''}</h3>
              <div className="flex gap-4">
                <button 
                  onClick={() => {setFiles([]); setBatchResult([]);}} 
                  className="text-[#184435]/30 dark:text-mint-dim hover:text-red-500 font-black text-[11px] uppercase tracking-widest transition-soft"
                >
                  Clear Queue
                </button>
              </div>
            </div>

            <div className="grid gap-3 max-h-[400px] overflow-y-auto pr-2 no-scrollbar">
              {files.map((f) => (
                <div key={f.id} className="bg-[#F2FFFA]/50 dark:bg-obsidian-elevated/40 rounded-2xl p-4 border border-[#184435]/5 dark:border-obsidian-border flex items-center gap-5 transition-soft group">
                  <div className={`p-3.5 rounded-xl ${f.status === 'completed' ? 'bg-[#49956F] text-white' : 'bg-white dark:bg-obsidian-surface text-[#184435]/20 dark:text-mint-dim'}`}>
                    {f.status === 'completed' ? <CheckCircle className="w-5 h-5" /> : <FileIcon className="w-5 h-5" />}
                  </div>
                  <div className="flex-grow min-w-0">
                    <p className="font-bold text-[#184435] dark:text-mint-soft truncate text-sm mb-1">{f.file.name}</p>
                    <div className="flex items-center gap-3">
                       <span className="text-[10px] font-black uppercase text-[#184435]/30 dark:text-mint-dim tracking-widest">{formatSize(f.originalSize)}</span>
                       {f.processedSize && (
                         <>
                           <ArrowRightLeft className="w-2.5 h-2.5 text-mint-accent" />
                           <span className="text-[10px] font-black uppercase text-mint-accent tracking-widest">{formatSize(f.processedSize)}</span>
                         </>
                       )}
                    </div>
                    {f.status === 'processing' && (
                      <div className="w-full bg-[#184435]/5 dark:bg-obsidian-border h-1 mt-2 rounded-full overflow-hidden">
                        <div className="bg-[#49956F] dark:bg-mint-accent h-full transition-all duration-700" style={{ width: `${f.progress}%` }} />
                      </div>
                    )}
                  </div>
                  {f.status === 'idle' && (
                    <button onClick={() => setFiles(prev => prev.filter(item => item.id !== f.id))} className="opacity-0 group-hover:opacity-100 p-2 text-[#184435]/20 hover:text-red-500 transition-soft">
                      <X className="w-4 h-4" />
                    </button>
                  )}
                </div>
              ))}
            </div>

            {/* Config Panels & Quality Button */}
            <div className="pt-6 border-t border-[#184435]/5 dark:border-obsidian-border space-y-8">
              <div className="flex flex-col sm:flex-row items-center justify-between gap-6">
                <div className="flex-grow w-full">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1 mb-4 flex items-center gap-2">
                    <SlidersHorizontal className="w-3 h-3" /> Synthesis Quality
                  </label>
                  <div className="flex bg-gray-50 dark:bg-obsidian-elevated p-1 rounded-2xl border border-[#184435]/5 dark:border-obsidian-border">
                    {[
                      { id: 'standard', label: 'Draft', desc: 'Fastest' },
                      { id: 'high', label: 'Premium', desc: 'Balanced' },
                      { id: 'pro', label: 'Ultra', desc: 'Max Detail' }
                    ].map(mode => (
                      <button
                        key={mode.id}
                        onClick={() => setQualityMode(mode.id as any)}
                        className={`flex-grow px-4 py-3 rounded-xl transition-soft text-center group ${qualityMode === mode.id ? 'bg-white dark:bg-obsidian-surface shadow-md' : 'hover:bg-black/5 dark:hover:bg-white/5'}`}
                      >
                        <p className={`text-[11px] font-black uppercase tracking-widest ${qualityMode === mode.id ? 'text-[#184435] dark:text-mint-soft' : 'text-[#184435]/30 dark:text-mint-dim'}`}>{mode.label}</p>
                        <p className={`text-[8px] font-bold uppercase tracking-widest mt-0.5 ${qualityMode === mode.id ? 'text-mint-accent' : 'text-[#184435]/20 dark:text-mint-dim/40'}`}>{mode.desc}</p>
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              {id === 'compress-pdf' && (
                <div className="space-y-4">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#49956F] dark:text-mint-accent block ml-1">Optimization Ratio</label>
                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    {COMPRESSION_LEVELS.map(level => (
                      <button 
                        key={level.id} 
                        onClick={() => setCompressionLevel(level.id)}
                        className={`p-4 rounded-2xl text-left border-2 transition-soft ${compressionLevel === level.id ? 'bg-[#184435] dark:bg-mint-accent text-white border-[#184435] dark:border-mint-accent' : 'bg-white dark:bg-obsidian-elevated dark:text-mint-soft border-transparent shadow-sm'}`}
                      >
                        <p className="font-black text-xs uppercase tracking-widest mb-1">{level.name}</p>
                        <p className="text-[10px] opacity-60 leading-tight">{level.desc}</p>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Main Action Button */}
            <button
              disabled={isProcessing || files.length === 0}
              onClick={handleBatchProcess}
              className="w-full bg-[#184435] dark:bg-mint-accent text-white py-6 rounded-2xl font-black text-xl hover:bg-[#49956F] dark:hover:bg-mint-hover transition-soft flex items-center justify-center gap-4 active:opacity-90 disabled:opacity-30 shadow-2xl shadow-[#184435]/10 dark:shadow-none relative group overflow-hidden"
            >
              {isProcessing ? (
                <Loader2 className="w-8 h-8 animate-spin" />
              ) : (
                <Zap className="w-7 h-7 fill-current group-hover:animate-pulse-gentle" />
              )}
              {isProcessing ? 'PROCESSING...' : `PROCESS ${files.length} ITEM${files.length !== 1 ? 'S' : ''}`}

              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
            </button>
          </div>
        )}
      </div>

      {/* Results Comparison Table */}
      {batchResult.length > 0 && (
        <div className="mt-12 p-8 bg-mint-accent/5 dark:bg-mint-accent/5 rounded-[3rem] border border-mint-accent/10 animate-fade-in-up-soft overflow-hidden">
          <div className="flex flex-col sm:flex-row items-center justify-between gap-6 mb-8">
            <div className="flex items-center gap-3">
              <div className="bg-mint-accent/20 p-2 rounded-lg"><TrendingDown className="w-5 h-5 text-mint-accent" /></div>
              <div>
                <p className="font-black text-mint-accent text-[10px] tracking-[0.2em] uppercase">Results Analysis</p>
                <p className="text-[#184435]/40 dark:text-mint-muted text-[10px] font-bold uppercase tracking-widest">Optimized in volatile memory</p>
              </div>
            </div>
            <button 
              onClick={() => batchResult.forEach(r => handleDownload(r.name, r.content))}
              className="flex items-center gap-2 bg-[#184435] dark:bg-mint-accent text-white px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg hover:brightness-110 transition-soft"
            >
              <Download className="w-4 h-4" /> Download All
            </button>
          </div>

          <div className="grid gap-3">
            {batchResult.map(res => (
              <div key={res.id} className="bg-white dark:bg-obsidian-elevated p-5 rounded-2xl flex flex-col sm:flex-row items-center justify-between gap-6 border border-transparent hover:border-mint-accent/30 transition-soft group">
                <div className="flex items-center gap-4 min-w-0 flex-grow">
                  <div className="p-2.5 bg-gray-50 dark:bg-obsidian-surface rounded-xl text-mint-accent">
                    <FileText className="w-5 h-5" />
                  </div>
                  <div className="truncate">
                    <p className="text-sm font-black dark:text-mint-soft truncate">{res.name}</p>
                    <div className="flex items-center gap-2 mt-0.5">
                       <span className="text-[9px] font-black text-[#184435]/30 dark:text-mint-dim uppercase tracking-wider line-through">{res.before}</span>
                       <ArrowRightLeft className="w-2.5 h-2.5 text-mint-accent" />
                       <span className="text-[9px] font-black text-mint-accent uppercase tracking-wider">{res.after}</span>
                    </div>
                  </div>
                </div>
                <div className="flex gap-2 shrink-0">
                  <button 
                    onClick={() => setPreviewContent({ name: res.name, content: res.content })}
                    className="p-3 bg-gray-50 dark:bg-obsidian-surface rounded-xl text-[#184435]/40 dark:text-mint-muted hover:text-mint-accent transition-soft"
                  >
                    <Eye className="w-5 h-5" />
                  </button>
                  <button 
                    onClick={() => handleDownload(res.name, res.content)}
                    className="p-3 bg-mint-accent/10 dark:bg-mint-accent/20 text-mint-accent rounded-xl hover:bg-mint-accent hover:text-white transition-soft"
                  >
                    <Download className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Preview Modal */}
      {previewContent && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 sm:p-8 animate-fade-in-up-soft">
          <div className="absolute inset-0 bg-obsidian/80 backdrop-blur-sm" onClick={() => setPreviewContent(null)} />
          <div className="bg-white dark:bg-obsidian-elevated w-full max-w-4xl max-h-[80vh] rounded-[2.5rem] shadow-2xl relative overflow-hidden flex flex-col">
            <div className="p-8 border-b border-gray-100 dark:border-obsidian-border flex items-center justify-between shrink-0">
              <div>
                <h4 className="font-black text-xl text-[#184435] dark:text-mint-soft tracking-tight mb-1">{previewContent.name}</h4>
                <p className="text-[10px] font-bold text-[#49956F] dark:text-mint-accent uppercase tracking-widest">In-Memory Preview • Stateless Node</p>
              </div>
              <div className="flex items-center gap-3">
                <button 
                  onClick={() => handleCopy(previewContent.content)}
                  className="p-3 bg-gray-50 dark:bg-obsidian-surface rounded-xl text-[#184435]/40 dark:text-mint-muted hover:text-mint-accent transition-soft flex items-center gap-2"
                >
                  {copied ? <Check className="w-5 h-5 text-mint-accent" /> : <Copy className="w-5 h-5" />}
                  <span className="text-[10px] font-black uppercase tracking-widest hidden sm:block">{copied ? 'Copied' : 'Copy'}</span>
                </button>
                <button onClick={() => setPreviewContent(null)} className="p-3 hover:bg-red-50 dark:hover:bg-red-500/10 text-gray-400 hover:text-red-500 rounded-xl transition-soft">
                  <X className="w-6 h-6" />
                </button>
              </div>
            </div>
            <div className="p-8 overflow-y-auto flex-grow bg-gray-50 dark:bg-obsidian-surface font-mono text-sm leading-relaxed text-[#184435] dark:text-mint-soft whitespace-pre-wrap select-text selection:bg-mint-accent selection:text-white">
              {previewContent.content}
            </div>
          </div>
        </div>
      )}

      {/* Info Sections */}
      <div className="mt-16 p-10 bg-[#F2FFFA] dark:bg-obsidian-elevated/20 rounded-[3rem] border border-[#49956F]/10 dark:border-obsidian-border flex flex-col lg:flex-row items-center gap-10">
        <div className="p-6 bg-white dark:bg-obsidian-surface rounded-[2rem] shadow-sm shrink-0 flex items-center justify-center">
           <Shield className="w-12 h-12 text-mint-accent" />
        </div>
        <div className="text-center lg:text-left">
           <h4 className="font-black text-[#184435] dark:text-mint-soft text-xl mb-3">Professional Privacy Standard</h4>
           <p className="text-sm text-[#184435]/50 dark:text-mint-muted leading-relaxed max-w-2xl">
              Unbound employs a <strong>zero-disk architecture</strong>. Your documents are streamed directly to volatile RAM nodes, processed by high-performance inference units, and wiped immediately upon completion. We provide absolute mathematical certainty that your documents do not persist.
           </p>
        </div>
      </div>

      <section className="mt-32 grid md:grid-cols-3 gap-12 text-center pb-20">
        {[
          { icon: <Layers />, title: "Stateless Synthesis", text: "Processing occurs in temporary cloud containers that self-destruct after use." },
          { icon: <Cpu />, title: "Layout Engine", text: "Proprietary AI reconstructions ensure pixel-perfect text and object positioning." },
          { icon: <Shield />, title: "Military Grade", text: "AES-256 standard encryption for all protected document workflows." }
        ].map((feat, i) => (
          <div key={i} className="group p-8 rounded-[2.5rem] bg-white/30 dark:bg-obsidian-surface/30 hover:bg-white dark:hover:bg-obsidian-surface transition-soft">
            <div className="text-[#49956F] dark:text-mint-accent w-12 h-12 mb-6 mx-auto group-hover:scale-110 transition-soft">
              {/* Fix: Cast icon to ReactElement with any props to avoid className type error */}
              {React.cloneElement(feat.icon as React.ReactElement<any>, { className: 'w-full h-full' })}
            </div>
            <h4 className="font-black text-[#184435] dark:text-mint-soft mb-3 text-lg tracking-tight uppercase tracking-widest text-[13px]">{feat.title}</h4>
            <p className="text-xs text-[#184435]/40 dark:text-mint-muted leading-relaxed font-medium">{feat.text}</p>
          </div>
        ))}
      </section>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  Upload, X, File as FileIcon, Loader2, CheckCircle, ArrowLeft, 
  Zap, Plus, ShieldCheck, Cpu, Layers, Shield, Sparkles, Download,
  RotateCw, Lock, Scissors, Languages, ImageIcon, FileText, Minimize2,
  Eye, Copy, Check, Info, TrendingDown, SlidersHorizontal, ArrowRightLeft,
  Square, CheckSquare, MousePointer2, ListFilter
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { summarizeDocument, performOCR, translateText, reconstructAsWord } from '../services/geminiService';

const LANGUAGES = [
  "Spanish", "French", "German", "Chinese", "Japanese", "Hindi", "Arabic", "Portuguese", "Russian", "Italian", "Korean", "Dutch", "Greek", "Turkish"
];

const COMPRESSION_LEVELS = [
  { id: 1, name: 'Extreme', desc: 'Max compression', ratio: 0.25 },
  { id: 2, name: 'Recommended', desc: 'Balanced', ratio: 0.55 },
  { id: 3, name: 'Low', desc: 'Max quality', ratio: 0.85 }
];

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string, type?: string, before: string, after: string }[]>([]);
  const [previewContent, setPreviewContent] = useState<{ name: string, content: string } | null>(null);
  const [copied, setCopied] = useState(false);

  // Dynamic Config State
  const [targetLanguage, setTargetLanguage] = useState<string>("Spanish");
  const [compressionLevel, setCompressionLevel] = useState<number>(2);
  const [qualityMode, setQualityMode] = useState<'standard' | 'high' | 'pro'>('high');
  const [password, setPassword] = useState<string>("");
  const [rotation, setRotation] = useState<number>(90);
  const [splitRange, setSplitRange] = useState<string>("");
  const [selectedPages, setSelectedPages] = useState<number[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  // Split PDF Logic: When selectedPages changes, update the splitRange string
  useEffect(() => {
    if (id === 'split-pdf') {
      const sorted = [...selectedPages].sort((a, b) => a - b);
      setSplitRange(sorted.join(', '));
    }
  }, [selectedPages, id]);

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const addFiles = (selectedFiles: FileList | File[]) => {
    const newFiles: FileState[] = [];
    Array.from(selectedFiles).forEach(file => {
      const isImage = file.type.startsWith('image/');
      const isPDF = file.type === 'application/pdf';
      const isWord = file.type.includes('word');

      let isValid = false;
      if (id === 'ai-ocr') isValid = isImage || isPDF;
      else if (id === 'word-to-pdf') isValid = isWord;
      else isValid = isPDF;

      if (isValid) {
        newFiles.push({ 
          id: Math.random().toString(36).substr(2, 9), 
          file, 
          status: 'idle', 
          progress: 0,
          originalSize: file.size
        });
      }
    });
    setFiles(prev => [...prev, ...newFiles]);
    setBatchResult([]);
    // Default select first few pages for split if one file added
    if (id === 'split-pdf' && newFiles.length > 0) {
      setSelectedPages([1, 2, 3]);
    }
  };

  const togglePage = (p: number) => {
    setSelectedPages(prev => prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const nameOnly = filename.replace(/\.[^/.]+$/, "");
    link.download = `${nameOnly}_unbound_result.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleCopy = (content: string) => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string, before: string, after: string }> => {
    return new Promise(async (resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async () => {
        try {
          const base64 = (reader.result as string).split(',')[1];
          let content = "";
          let mockProcessedSize = fileState.originalSize;

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 20 } : f));

          if (id === 'ai-summarize') {
            const text = await performOCR(base64, fileState.file.type);
            setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 60 } : f));
            content = await summarizeDocument(text) || "Summarization failed.";
            mockProcessedSize = content.length * 1.5;
          } else if (id === 'ai-ocr') {
            content = await performOCR(base64, fileState.file.type) || "OCR failed.";
            mockProcessedSize = content.length;
          } else if (id === 'pdf-to-word') {
            content = await reconstructAsWord(base64, fileState.file.type) || "Reconstruction failed.";
            mockProcessedSize = fileState.originalSize * 1.1;
          } else if (id === 'compress-pdf') {
            const ratio = COMPRESSION_LEVELS.find(l => l.id === compressionLevel)?.ratio || 0.5;
            mockProcessedSize = Math.floor(fileState.originalSize * ratio);
            content = `Unbound Compression Result for ${fileState.file.name}\nOriginal: ${formatSize(fileState.originalSize)}\nResult: ${formatSize(mockProcessedSize)}`;
          } else if (id === 'split-pdf') {
             content = `Unbound Split Result: Extracted pages [${selectedPages.sort((a,b)=>a-b).join(', ')}] from ${fileState.file.name}. Isolated fragments stored in volatile cache.`;
             mockProcessedSize = (fileState.originalSize / 10) * selectedPages.length;
          } else {
            content = `Stateless Flow Complete: ${fileState.file.name} processed successfully via ${tool?.name}.`;
            mockProcessedSize = fileState.originalSize * (qualityMode === 'pro' ? 1.2 : 0.9);
          }

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 100, processedSize: mockProcessedSize } : f));
          resolve({ 
            id: fileState.id, 
            name: fileState.file.name, 
            content,
            before: formatSize(fileState.originalSize),
            after: formatSize(mockProcessedSize)
          });
        } catch (err) { reject(err); }
      };
      reader.readAsDataURL(fileState.file);
    });
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 5 })));

    try {
      const results = await Promise.all(files.map(async f => {
        const res = await processFile(f);
        setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
        return res;
      }));
      setBatchResult(results);
    } catch (e) {
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return null;

  return (
    <div className="max-w-5xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      {/* Breadcrumbs */}
      <div className="flex justify-between items-center mb-12">
        <Link to="/" className="inline-flex items-center gap-2 text-[#184435]/40 dark:text-mint-dim hover:text-[#49956F] dark:hover:text-mint-accent font-bold text-[11px] uppercase tracking-widest transition-soft group">
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-soft" />
          Workspace
        </Link>
