            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-14 rounded-[3rem] mb-10 bg-gray-50 dark:bg-obsidian-elevated group-hover:bg-mint-accent/10 transition-soft">
                <Upload className="w-16 h-16 text-[#184435]/20 dark:text-mint-dim/30 group-hover:text-mint-accent transition-soft" />
              </div>
              <span className="bg-[#184435] dark:bg-mint-accent text-white px-14 py-6 rounded-[1.5rem] font-black text-xl hover:shadow-2xl hover:shadow-mint-accent/20 transition-soft active:scale-95">
                Load PDF into RAM
