      </AnimatePresence>

      {/* Security Assurance */}
      <div className="mt-20 p-12 bg-mint-accent/5 dark:bg-obsidian-elevated/20 rounded-[3.5rem] border border-mint-accent/10 dark:border-obsidian-border flex flex-col lg:flex-row items-center gap-10">
        <div className="p-8 bg-white dark:bg-obsidian-surface rounded-[2.5rem] shadow-xl shrink-0 border border-[#184435]/5">
           <ShieldCheck className="w-14 h-14 text-mint-accent" />
        </div>
        <div className="text-center lg:text-left">
           <h4 className="font-black text-[#184435] dark:text-mint-soft text-2xl mb-3 tracking-tight">Stateless Rendering Pipeline</h4>
           <p className="text-lg text-[#184435]/50 dark:text-mint-muted leading-relaxed max-w-3xl font-medium">
              Document thumbnails are generated using high-fidelity client-side WebAssembly rendering. We strictly enforce a Zero-Disk policy; neither metadata nor visual fragments are ever persisted to a database or cloud storage. 
           </p>
        </div>
      </div>
    </div>
  );
};

