// Set pdf.js worker
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.mjs`;

interface SplitResult {
  id: string;
  name: string;
  pages: { pageNum: number; blob: Blob; url: string }[];
}

const PageThumbnail: React.FC<{ 
  pdfDoc: pdfjsLib.PDFDocumentProxy; 
  pageNum: number; 
  isHovered: boolean;
  scale?: number;
}> = ({ pdfDoc, pageNum, isHovered, scale = 0.3 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    let isMounted = true;
    const renderPage = async () => {
      try {
        const page = await pdfDoc.getPage(pageNum);
        const viewport = page.getViewport({ scale });
        const canvas = canvasRef.current;
        if (!canvas) return;

        const context = canvas.getContext('2d');
        if (!context) return;

        canvas.height = viewport.height;
        canvas.width = viewport.width;

        const renderContext = {
          canvasContext: context,
          viewport: viewport,
        };

        if (isMounted) {
          await page.render(renderContext).promise;
        }
      } catch (err) {
        console.error(`Error rendering page ${pageNum}:`, err);
      }
    };

    renderPage();
    return () => { isMounted = false; };
  }, [pdfDoc, pageNum, scale]);

  return (
    <div className={`w-full h-full flex items-center justify-center transition-all duration-500 overflow-hidden ${isHovered ? 'scale-110' : 'scale-100'}`}>
       <canvas ref={canvasRef} className="max-w-full max-h-full shadow-sm rounded-sm" />
    </div>
  );
};

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [pdfDoc, setPdfDoc] = useState<pdfjsLib.PDFDocumentProxy | null>(null);
  const [numPages, setNumPages] = useState<number>(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [batchResult, setBatchResult] = useState<{ id: string, name: string, content: string, before: string, after: string, blob?: Blob, url?: string }[]>([]);
  const [splitResult, setSplitResult] = useState<SplitResult | null>(null);
  const [previewContent, setPreviewContent] = useState<{ name: string, content: string } | null>(null);
  const [hoveredPage, setHoveredPage] = useState<number | null>(null);
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [splitRange, setSplitRange] = useState<string>("");
  const [selectedPages, setSelectedPages] = useState<number[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => {
    if (id === 'split-pdf') {
      const sorted = [...selectedPages].sort((a, b) => a - b);
      setSplitRange(sorted.join(', '));
    }
  }, [selectedPages, id]);

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const clearCurrentPdf = () => {
    if (pdfDoc) {
      pdfDoc.destroy();
    }
    setPdfDoc(null);
    setNumPages(0);
    setSelectedPages([]);
    setError(null);
    if (splitResult) {
      splitResult.pages.forEach(p => URL.revokeObjectURL(p.url));
      setSplitResult(null);
    }
    batchResult.forEach(res => {
      if (res.url) URL.revokeObjectURL(res.url);
    });
  };

  const loadPdfMetadata = async (file: File) => {
    try {
      const arrayBuffer = await file.arrayBuffer();
      const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
      const doc = await loadingTask.promise;
      setPdfDoc(doc);
      setNumPages(doc.numPages);
      if (id === 'split-pdf') {
        setSelectedPages(Array.from({ length: doc.numPages }, (_, i) => i + 1));
      }
    } catch (err) {
      console.error("PDF loading failed:", err);
      setError("Failed to parse PDF document. It might be corrupted or protected.");
    }
  };

  const addFiles = (selectedFiles: FileList | File[]) => {
    clearCurrentPdf();
    const newFiles: FileState[] = [];
    const filesArray = Array.from(selectedFiles);

    if (id === 'jpg-to-pdf') {
      // Allow multiple images
      filesArray.forEach(file => {
        if (file.type.startsWith('image/')) {
          newFiles.push({
            id: Math.random().toString(36).substr(2, 9),
            file: file,
            status: 'idle',
            progress: 0,
            originalSize: file.size
          });
        }
      });
      if (newFiles.length > 0) {
        setFiles(newFiles);
        setBatchResult([]);
      } else {
        setError("Please select valid image files (JPG, PNG, etc.)");
      }
      return;
    }

    const firstFile = filesArray[0];
    if (!firstFile) return;

    const isPDF = firstFile.type === 'application/pdf';

    if (isPDF) {
      newFiles.push({ 
        id: Math.random().toString(36).substr(2, 9), 
        file: firstFile, 
        status: 'idle', 
        progress: 0,
        originalSize: firstFile.size
      });
      setFiles(newFiles);
      setBatchResult([]);
      loadPdfMetadata(firstFile);
    } else {
      setError("Only PDF documents are supported for this operation.");
    }
  };

  const togglePage = (p: number) => {
    setSelectedPages(prev => prev.includes(p) ? prev.filter(x => x !== p) : [...prev, p]);
  };

  const invertSelection = () => {
    if (numPages === 0) return;
    const all = Array.from({ length: numPages }, (_, i) => i + 1);
    setSelectedPages(prev => all.filter(p => !prev.includes(p)));
  };

  const handleDownloadZip = async () => {
    if (!splitResult) return;
    const zip = new JSZip();
    const baseName = splitResult.name.replace(/\.[^/.]+$/, "");
    splitResult.pages.forEach(p => {
      zip.file(`${baseName}-page-${p.pageNum}.pdf`, p.blob);
    });
    const zipBlob = await zip.generateAsync({ type: 'blob' });
    const url = URL.createObjectURL(zipBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${baseName}-split.zip`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleDownloadIndividually = () => {
    if (!splitResult) return;
    const baseName = splitResult.name.replace(/\.[^/.]+$/, "");
    splitResult.pages.forEach((p, index) => {
      setTimeout(() => {
        const link = document.createElement('a');
        link.href = p.url;
        link.download = `${baseName}-page-${p.pageNum}.pdf`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      }, index * 200);
    });
  };

  const handleDownloadResult = (res: any) => {
    if (res.url) {
      const link = document.createElement('a');
      link.href = res.url;
      link.download = res.name.endsWith('.pdf') ? res.name : `${res.name.replace(/\.[^/.]+$/, "")}.pdf`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } else {
      const blob = new Blob([res.content], { type: 'text/plain' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `${res.name.replace(/\.[^/.]+$/, "")}_result.txt`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    }
  };

  const handleBatchProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setError(null);
    setFiles(prev => prev.map(f => ({ ...f, status: 'processing', progress: 5 })));

    try {
      if (id === 'jpg-to-pdf') {
        const pdfDoc = await PDFDocument.create();
        for (let i = 0; i < files.length; i++) {
          const fileState = files[i];
          const imgBytes = await fileState.file.arrayBuffer();
          let img;
          if (fileState.file.type === 'image/png') {
            img = await pdfDoc.embedPng(imgBytes);
          } else {
            img = await pdfDoc.embedJpg(imgBytes);
          }
          const page = pdfDoc.addPage([img.width, img.height]);
          page.drawImage(img, { x: 0, y: 0, width: img.width, height: img.height });

          const progress = 5 + Math.floor(((i + 1) / files.length) * 95);
          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, status: 'completed', progress: 100 } : f));
        }
        const pdfBytes = await pdfDoc.save();
        const blob = new Blob([pdfBytes], { type: 'application/pdf' });
        const url = URL.createObjectURL(blob);
        setBatchResult([{
          id: 'merged-pdf',
          name: files.length === 1 ? `${files[0].file.name.split('.')[0]}.pdf` : 'converted_images.pdf',
          content: 'PDF synthesis complete.',
          before: formatSize(files.reduce((acc, f) => acc + f.originalSize, 0)),
          after: formatSize(blob.size),
          blob,
          url
        }]);
      } else {
        const results = await Promise.all(files.map(async f => {
          const res = await processFile(f);
          setFiles(prev => prev.map(item => item.id === f.id ? { ...item, status: 'completed', progress: 100 } : item));
          return res;
        }));
        setBatchResult(results);
      }
    } catch (e) {
      console.error(e);
      setError("An error occurred during processing. The file might be too large or complex.");
      setFiles(prev => prev.map(f => ({ ...f, status: 'error', progress: 0 })));
    } finally {
      setIsProcessing(false);
    }
  };

  const processFile = async (fileState: FileState): Promise<{ id: string, name: string, content: string, before: string, after: string, blob?: Blob, url?: string }> => {
    return new Promise(async (resolve, reject) => {
      const reader = new FileReader();
      reader.onload = async () => {
        try {
          const arrayBuffer = reader.result as ArrayBuffer;
          let content = "";
          let mockProcessedSize = fileState.originalSize;
          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 20 } : f));

          if (id === 'split-pdf') {
            const srcDoc = await PDFDocument.load(arrayBuffer);
            const extractedPages: { pageNum: number; blob: Blob; url: string }[] = [];

            for (let i = 0; i < selectedPages.length; i++) {
              const pageNum = selectedPages[i];
              const newPdf = await PDFDocument.create();
              const [copiedPage] = await newPdf.copyPages(srcDoc, [pageNum - 1]);
              newPdf.addPage(copiedPage);
              const pdfBytes = await newPdf.save();
              const blob = new Blob([pdfBytes], { type: 'application/pdf' });
              extractedPages.push({
                pageNum,
                blob,
                url: URL.createObjectURL(blob)
              });
              const progress = 20 + Math.floor((i / selectedPages.length) * 80);
              setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress } : f));
            }
            setSplitResult({ id: fileState.id, name: fileState.file.name, pages: extractedPages });
            content = "Split successful. Binary artifacts buffered.";
            mockProcessedSize = extractedPages.reduce((acc, p) => acc + p.blob.size, 0);
          } else {
            content = `Transformation complete. Output buffered.`;
            mockProcessedSize = fileState.originalSize * 0.95;
          }

          setFiles(prev => prev.map(f => f.id === fileState.id ? { ...f, progress: 100, processedSize: mockProcessedSize } : f));
          resolve({ id: fileState.id, name: fileState.file.name, content, before: formatSize(fileState.originalSize), after: formatSize(mockProcessedSize) });
        } catch (err) { reject(err); }
      };
      reader.readAsArrayBuffer(fileState.file);
    });
  };

  if (!tool) return null;

  return (
    <div className="max-w-6xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      <div className="flex justify-between items-center mb-12">
        <Link to="/" className="inline-flex items-center gap-2 text-noir-text-muted dark:text-noir-text-darkMuted hover:text-at-teal dark:hover:text-at-teal-dark font-bold text-[11px] uppercase tracking-widest transition-soft group">
          <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-soft" />
          Workspace
        </Link>
        <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-at-teal dark:text-at-teal-dark px-4 py-2 bg-at-teal/5 dark:bg-at-teal-dark/10 rounded-full border border-at-teal/10 dark:border-at-teal-dark/20">
          <ShieldCheck className="w-3.5 h-3.5" /> Volatile Session
        </div>
      </div>

      <div className="text-center mb-16">
        <motion.div 
          initial={{ rotate: -10, scale: 0.9 }}
          animate={{ rotate: 0, scale: 1 }}
          className={`inline-flex p-6 rounded-[2rem] ${tool.color} text-white dark:text-noir-bg-dark mb-8 shadow-xl dark:noir-glow-teal transition-soft group cursor-default`}
        >
          {tool.icon}
        </motion.div>
        <h1 className="text-5xl md:text-6xl font-black text-noir-text dark:text-noir-text-dark mb-4 tracking-tighter leading-none">{tool.name}</h1>
        <p className="text-xl text-noir-text-muted dark:text-noir-text-darkMuted max-w-2xl mx-auto font-medium leading-relaxed">{tool.description}</p>
      </div>

      <div 
        className={`bg-noir-surface dark:bg-noir-surface-dark rounded-[3.5rem] border-2 border-dashed transition-soft overflow-hidden ${
          isDragging ? 'border-at-teal dark:border-at-teal-dark bg-at-teal/5' : 'border-noir-text/10 dark:border-noir-surface-elevated shadow-sm'
        } ${files.length > 0 ? 'p-10' : 'p-24'}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { e.preventDefault(); setIsDragging(false); if (e.dataTransfer.files) addFiles(e.dataTransfer.files); }}
      >
        {files.length === 0 ? (
          <div className="flex flex-col items-center">
            <label className="cursor-pointer group flex flex-col items-center">
              <div className="p-14 rounded-[3rem] mb-10 bg-noir-bg dark:bg-noir-surface-elevated group-hover:bg-at-teal/10 transition-soft">
                <Upload className="w-16 h-16 text-noir-text-muted/30 dark:text-noir-text-darkDim/30 group-hover:text-at-teal dark:group-hover:text-at-teal-dark transition-soft" />
              </div>
              <span className="bg-at-teal dark:bg-at-teal-dark text-white dark:text-noir-bg-dark px-14 py-6 rounded-[1.5rem] font-black text-xl hover:shadow-2xl hover:shadow-at-teal/20 transition-soft active:scale-95 noir-glow-teal">
                {id === 'jpg-to-pdf' ? 'Select Images' : 'Select PDF'}
              </span>
              <input type="file" multiple={id === 'jpg-to-pdf'} accept={id === 'jpg-to-pdf' ? "image/*" : "application/pdf"} className="hidden" onChange={(e) => e.target.files && addFiles(e.target.files)} />
            </label>
            {error && (
              <div className="mt-8 flex items-center gap-2 text-red-500 font-bold text-xs uppercase bg-red-500/5 px-4 py-2 rounded-lg border border-red-500/20">
                <AlertTriangle className="w-4 h-4" /> {error}
              </div>
            )}
            <p className="mt-10 text-noir-text-muted/30 dark:text-noir-text-darkDim font-black text-[10px] uppercase tracking-widest">Documents never touch our server</p>
          </div>
        ) : (
          <div className="space-y-12">
            <div className="flex items-center justify-between border-b border-noir-bg dark:border-noir-surface-elevated pb-8">
              <div>
                <h3 className="font-black text-noir-text dark:text-noir-text-dark text-3xl tracking-tight">Active Node</h3>
                <p className="text-sm font-bold text-noir-text-muted dark:text-noir-text-darkMuted uppercase tracking-widest mt-1">
                  {id === 'jpg-to-pdf' ? `${files.length} Image(s)` : `${files[0].file.name} • ${numPages} Page(s)`}
                </p>
              </div>
              <button 
                onClick={() => { setFiles([]); clearCurrentPdf(); setBatchResult([]); }} 
                className="flex items-center gap-2 p-3 rounded-xl bg-at-amber/5 text-at-amber dark:text-at-amber-dark hover:bg-at-amber/10 transition-soft"
              >
                <RefreshCw className="w-5 h-5" />
                <span className="text-[10px] font-black uppercase tracking-widest">Reset Node</span>
              </button>
            </div>

            {id === 'split-pdf' && pdfDoc && (
              <div className="space-y-8 animate-fade-in-up-soft">
                <div className="flex flex-wrap items-center justify-between gap-6 p-6 bg-noir-bg/50 dark:bg-noir-surface-elevated/40 rounded-[2rem]">
                   <div className="flex items-center gap-4">
                      <div className="bg-at-teal/20 p-4 rounded-2xl shadow-lg shadow-at-teal/10">
                         <MousePointer2 className="w-6 h-6 text-at-teal dark:text-at-teal-dark" />
                      </div>
                      <div>
                        <p className="text-[11px] font-black uppercase tracking-[0.2em] text-at-teal dark:text-at-teal-dark">Live Grid Selector</p>
                        <p className="text-sm font-bold text-noir-text-muted dark:text-noir-text-darkMuted">Select pages to extract as individual files</p>
                      </div>
                   </div>
                   <div className="flex items-center gap-2">
                      <button onClick={() => setSelectedPages(Array.from({length: numPages}, (_, i) => i + 1))} className="px-5 py-3 rounded-xl bg-noir-surface dark:bg-noir-surface-elevated text-[10px] font-black uppercase tracking-widest hover:text-at-teal dark:hover:text-at-teal-dark border border-transparent shadow-sm transition-soft">All</button>
                      <button onClick={invertSelection} className="px-5 py-3 rounded-xl bg-noir-surface dark:bg-noir-surface-elevated text-[10px] font-black uppercase tracking-widest hover:text-at-teal dark:hover:text-at-teal-dark border border-transparent shadow-sm transition-soft">Invert</button>
                      <button onClick={() => setSelectedPages([])} className="px-5 py-3 rounded-xl bg-noir-surface dark:bg-noir-surface-elevated text-[10px] font-black uppercase tracking-widest hover:text-red-500 border border-transparent shadow-sm transition-soft">Clear</button>
                   </div>
                </div>

                <div className="relative">
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-6 min-h-[200px]">
                    <AnimatePresence mode='popLayout'>
                      {Array.from({ length: numPages }).map((_, i) => {
                        const pageNum = i + 1;
                        const isSelected = selectedPages.includes(pageNum);
                        const isHovered = hoveredPage === pageNum;

                        return (
                          <motion.div key={`${files[0].id}-page-${pageNum}`} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: Math.min(i * 0.02, 0.5) }} className="relative">
                            <motion.button whileHover={{ y: -5 }} whileTap={{ scale: 0.96 }} onMouseEnter={() => setHoveredPage(pageNum)} onMouseLeave={() => setHoveredPage(null)} onClick={() => togglePage(pageNum)}
                              className={`relative w-full aspect-[1/1.41] rounded-[1.5rem] overflow-hidden transition-all duration-500 border-2 flex flex-col items-center justify-center group shadow-sm z-10 ${
                                isSelected ? 'border-at-teal dark:border-at-teal-dark bg-at-teal/5 shadow-lg shadow-at-teal/10' : 'border-noir-text/5 dark:border-noir-surface-elevated bg-noir-surface dark:bg-noir-surface-elevated'
                              }`}>
                              <div className="absolute top-3 right-3 z-30 drop-shadow-md">
                                {isSelected ? <CheckSquare className="w-6 h-6 text-at-teal dark:text-at-teal-dark fill-noir-surface/90 dark:fill-noir-surface-dark/90" /> : <Square className="w-6 h-6 text-noir-text-muted/20 group-hover:text-at-teal/30" />}
                              </div>
                              <PageThumbnail pdfDoc={pdfDoc} pageNum={pageNum} isHovered={isHovered} />
                              <div className={`absolute bottom-3 text-center px-4 py-1.5 rounded-full text-[9px] font-black tracking-[0.2em] transition-all duration-500 z-30 shadow-md ${isSelected ? 'bg-at-teal dark:bg-at-teal-dark text-white' : 'bg-noir-bg dark:bg-noir-surface text-noir-text-muted dark:text-noir-text-darkMuted'}`}>PAGE {pageNum}</div>
                              <AnimatePresence>{isHovered && <motion.div initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.8 }} className="absolute inset-0 bg-at-teal/10 flex items-center justify-center backdrop-blur-[1px] z-20 pointer-events-none"><ZoomIn className="w-8 h-8 text-at-teal/50" /></motion.div>}</AnimatePresence>
                            </motion.button>
                          </motion.div>
                        );
                      })}
                    </AnimatePresence>
                  </div>
                </div>

                <div className="p-8 bg-at-teal/5 rounded-[2.5rem] border border-at-teal/10 space-y-6">
                  <div className="flex items-center gap-3">
                    <ListFilter className="w-5 h-5 text-at-teal dark:text-at-teal-dark" />
                    <p className="text-[11px] font-black uppercase tracking-[0.2em] text-at-teal dark:text-at-teal-dark">Extraction Mask</p>
                  </div>
                  <div className="relative group">
                    <Scissors className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-noir-text-muted/20" />
