                 <label className="aspect-[1/1.41] bg-noir-bg dark:bg-noir-surface-elevated rounded-xl border-2 border-dashed border-noir-text/10 flex flex-col items-center justify-center cursor-pointer hover:bg-at-teal/5 transition-soft">
