                   <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-10">
                      <div>
                         <div className="inline-flex items-center gap-2 bg-at-teal/20 text-at-teal-dark px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest mb-4"><Sparkles className="w-3.5 h-3.5" /> Workspace Materialized</div>
                         <h2 className="text-4xl font-black tracking-tighter mb-2">Ready for Download</h2>
                         <p className="opacity-60 font-medium">{id === 'split-pdf' ? `Extracted ${splitResult?.pages.length} pages.` : `Processed ${batchResult.length} artifact(s).`}</p>
                      </div>
                      <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
                        {id === 'split-pdf' ? (
                          <>
                            <button onClick={handleDownloadZip} className="w-full sm:w-auto flex items-center justify-center gap-3 px-10 py-5 bg-at-teal dark:bg-at-teal-dark text-white dark:text-noir-bg-dark rounded-2xl font-black text-sm uppercase tracking-widest hover:shadow-xl hover:-translate-y-1 active:translate-y-0 transition-soft">
                              <Archive className="w-5 h-5" /> Download as ZIP
                            </button>
                            <button onClick={handleDownloadIndividually} className="w-full sm:w-auto flex items-center justify-center gap-3 px-10 py-5 bg-white/10 dark:bg-at-amber-dark/10 backdrop-blur-md border border-white/20 dark:border-at-amber-dark/20 text-white dark:text-at-amber-dark rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-white/20 transition-soft">
                              <FileDown className="w-5 h-5" /> Individually
