                        ) : (
                          batchResult.map(res => (
                            <button key={res.id} onClick={() => handleDownloadResult(res)} className="w-full sm:w-auto flex items-center justify-center gap-3 px-10 py-5 bg-at-teal dark:bg-at-teal-dark text-white dark:text-noir-bg-dark rounded-2xl font-black text-sm uppercase tracking-widest hover:shadow-xl hover:-translate-y-1 transition-soft">
                              <Download className="w-5 h-5" /> Download PDF
                            </button>
                          ))
                        )}
                      </div>
                   </div>
                   {id === 'split-pdf' && splitResult && (
                     <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-4 pt-10 border-t border-white/10">
                        {splitResult.pages.map(p => (
                          <div key={p.pageNum} className="flex flex-col items-center gap-2">
                             <a href={p.url} download={`${splitResult.name.replace(/\.[^/.]+$/, "")}-page-${p.pageNum}.pdf`} className="w-full aspect-[1/1.4] bg-white/10 dark:bg-noir-surface-dark rounded-xl flex items-center justify-center group hover:bg-white/20 transition-soft">
                               <FileIcon className="w-6 h-6 opacity-40 group-hover:opacity-100 transition-soft" />
                             </a>
                             <span className="text-[10px] font-black uppercase opacity-50">Page {p.pageNum}</span>
                          </div>
                        ))}
                     </div>
                   )}
                </motion.div>
              )}
            </AnimatePresence>

            {(!splitResult && batchResult.length === 0) && (
              <div className="space-y-4">
                 {isProcessing && (
                   <div className="w-full bg-noir-bg dark:bg-noir-surface-elevated h-2 rounded-full overflow-hidden">
                      <motion.div initial={{ width: 0 }} animate={{ width: `${files[0]?.progress || 0}%` }} className="h-full bg-at-amber dark:bg-at-amber-dark noir-glow-amber" />
                   </div>
                 )}
                 <button disabled={isProcessing || files.length === 0 || (id === 'split-pdf' && selectedPages.length === 0)} onClick={handleBatchProcess}
                  className="w-full bg-at-teal dark:bg-at-teal-dark text-white dark:text-noir-bg-dark py-8 rounded-[2rem] font-black text-2xl hover:shadow-[0_20px_60px_-10px_rgba(63,183,166,0.4)] transition-all duration-500 flex items-center justify-center gap-4 active:scale-[0.98] disabled:opacity-30 relative group overflow-hidden noir-glow-teal">
                  {isProcessing ? <Loader2 className="w-8 h-8 animate-spin" /> : <Zap className="w-8 h-8 fill-current group-hover:animate-pulse" />}
                  {isProcessing ? 'SYNTHESIZING FLOW...' : id === 'split-pdf' ? `SPLIT ${selectedPages.length} PAGES IN RAM` : id === 'jpg-to-pdf' ? `CONVERT ${files.length} IMAGE(S) TO PDF` : `PROCESS IN RAM`}
                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
                </button>
              </div>
            )}
          </div>
        )}
      </div>

      <div className="mt-20 p-12 bg-at-amber/5 dark:bg-noir-surface-elevated/20 rounded-[3.5rem] border border-at-amber/10 dark:border-noir-surface-elevated flex flex-col lg:flex-row items-center gap-10">
        <div className="p-8 bg-noir-surface dark:bg-noir-surface-dark rounded-[2.5rem] shadow-xl shrink-0 border border-noir-text/5 noir-glow-amber">
           <ShieldCheck className="w-14 h-14 text-at-amber dark:text-at-amber-dark" />
        </div>
        <div className="text-center lg:text-left">
           <h4 className="font-black text-noir-text dark:text-noir-text-dark text-2xl mb-3 tracking-tight">Zero-Disk Split Protocol</h4>
           <p className="text-lg text-noir-text-muted dark:text-noir-text-darkMuted leading-relaxed max-w-3xl font-medium">
              Document splitting and conversion is performed using in-memory analysis. Each page is reconstructed as a distinct blob and stored in a temporary session buffer. When you download, the original source is never cloned to permanent storage.
           </p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  Upload, X, File as FileIcon, Loader2, CheckCircle, ArrowLeft, 
  Zap, Plus, ShieldCheck, Cpu, Layers, Shield, Sparkles, Download,
  RotateCw, Lock, Scissors, Languages, ImageIcon, FileText, Minimize2,
  Eye, Copy, Check, Info, TrendingDown, SlidersHorizontal, ArrowRightLeft,
  Square, CheckSquare, MousePointer2, ListFilter, RefreshCw, ZoomIn,
  AlertTriangle, Archive, FileDown
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import * as pdfjsLib from 'pdfjs-dist';
import { PDFDocument } from 'pdf-lib';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import { TOOLS } from '../constants';
