                     className="absolute inset-0 bg-white/10 pointer-events-none"
                   />
                )}
              </button>
            )}
            {error && <div className="p-6 bg-red-500/10 border border-red-500/20 text-red-500 rounded-2xl flex items-center gap-3 text-sm font-bold uppercase tracking-widest animate-shake">
              <AlertTriangle className="w-5 h-5" /> {error}
            </div>}
          </div>
        )}
      </div>

      <div className="mt-20 p-12 bg-at-amber/5 rounded-[3.5rem] border border-at-amber/10 flex flex-col lg:flex-row items-center gap-10">
        <div className="p-8 bg-noir-surface dark:bg-noir-surface-dark rounded-[2.5rem] shadow-xl shrink-0 noir-glow-amber">
           <ShieldCheck className="w-14 h-14 text-at-amber" />
        </div>
        <div className="text-center lg:text-left">
           <h4 className="font-black text-noir-text dark:text-noir-text-dark text-2xl mb-3 tracking-tight leading-tight">Zero-Log Persistence Policy</h4>
           <p className="text-lg text-noir-text-muted dark:text-noir-text-darkMuted leading-relaxed max-w-3xl font-medium">
              Every operation within Unbound Workspace happens in a volatile browser sandbox. We use binary streams for PDF manipulation, ensuring that your data only exists as raw bytes in RAM for the duration of the process. Files are completely purged from memory after your download or when the session ends.
           </p>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

// Use the API key directly from process.env.API_KEY as per Google GenAI SDK guidelines
// Creating instance right before making an API call to ensure latest context
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const summarizeDocument = async (text: string) => {
  const ai = getAI();
  // Using gemini-3-flash-preview for basic text summarization tasks
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Please provide a high-level professional summary of the following document. 
    Focus on key achievements, core competencies, and professional narrative. 
    Use a clean, executive style with bullet points for key takeaways. \n\n${text}`,
    config: {
      temperature: 0.7,
    }
  });
  // Accessing text as a property, not a method
  return response.text;
};

export const performOCR = async (base64Data: string, mimeType: string = 'image/jpeg') => {
  const ai = getAI();
  // Using gemini-3-flash-preview for fast OCR tasks
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType: mimeType } },
        { text: "Extract all text from this document. CRITICAL: Preserve the visual hierarchy. If there are dates on the right side of the page, keep them associated with their respective entries. Maintain all bullet points and list structures exactly as they appear." }
      ]
    }
  });
  // Accessing text as a property, not a method
  return response.text;
};

export const reconstructAsWord = async (base64Data: string, mimeType: string = 'application/pdf') => {
  const ai = getAI();
  // Using gemini-3-pro-preview for complex reasoning and layout reconstruction tasks
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType: mimeType } },
        { text: "Act as a document layout engineer. Reconstruct this document into a structured text format that preserves the original alignment and intent. For resumes: ensure the 'Experience' section correctly pairs company names with their date ranges. Use clear markers for bold text and headings. The goal is to produce a text version that can be copied into Microsoft Word and retain a professional, multi-column appearance." }
      ]
    },
    config: {
      // Setting thinking budget for enhanced reasoning in complex layouts
      thinkingConfig: { thinkingBudget: 4000 }
    }
  });
  // Accessing text as a property, not a method
  return response.text;
};

export const translateText = async (text: string, targetLanguage: string) => {
  const ai = getAI();
  // Using gemini-3-flash-preview for translation tasks
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following document to ${targetLanguage}. 
    CRITICAL: Preserve all formatting, indentation, and professional terminology. 
    Maintain the document's original structure: \n\n${text}`,
  });
  // Accessing text as a property, not a method
  return response.text;
};

