import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
// Add Download icon to imports to resolve the compilation error
import { Upload, X, File as FileIcon, Loader2, ArrowLeft, Zap, RefreshCw, AlertTriangle, Sparkles, CheckCircle2, Archive, FileDown, Download } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import * as pdfjsLib from 'pdfjs-dist';
import JSZip from 'jszip';
import { TOOLS } from '../constants';
import { FileState } from '../types';
import { runToolProcessor } from '../services/toolProcessors';
import { WatermarkPanel, SplitPanel, SecurityPanel, AIConfigPanel } from './toolSettings/SettingsPanels';

pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.mjs`;

export const ToolPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const tool = TOOLS.find(t => t.id === id);

  const [files, setFiles] = useState<FileState[]>([]);
  const [pdfDoc, setPdfDoc] = useState<any>(null);
  const [numPages, setNumPages] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progressMsg, setProgressMsg] = useState('');
  const [batchResult, setBatchResult] = useState<any[]>([]);
  const [splitResult, setSplitResult] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);

  const [config, setConfig] = useState<any>({
    selectedPages: [],
    splitMode: 'individual',
    password: '',
    confirmPassword: '',
    rotateAngle: 90,
    targetLang: 'English',
    watermarkType: 'text',
    watermarkText: 'CONFIDENTIAL',
    watermarkImage: null,
    watermarkOpacity: 0.4,
    watermarkRotation: -45,
    watermarkSize: 60,
    watermarkColor: '#ff0000'
  });

  const clearSession = () => {
    setFiles([]); setPdfDoc(null); setBatchResult([]); setSplitResult(null); setError(null);
  };

  const handleFileUpload = async (e: any) => {
    const uploaded = Array.from(e.target?.files || e) as File[];
    const newFiles = uploaded.map(f => ({ id: Math.random().toString(36).substr(2,9), file: f, status: 'idle', progress: 0, originalSize: f.size } as FileState));
    setFiles(id === 'merge-pdf' || id === 'jpg-to-pdf' ? [...files, ...newFiles] : newFiles);

    if (newFiles[0]?.file.type === 'application/pdf') {
      const doc = await pdfjsLib.getDocument(await newFiles[0].file.arrayBuffer()).promise;
      setPdfDoc(doc);
      setNumPages(doc.numPages);
      setConfig({ ...config, selectedPages: Array.from({length: doc.numPages}, (_,i)=>i+1)});
    }
  };

  const startPipeline = async () => {
    setIsProcessing(true); setError(null);
    try {
      const results = await runToolProcessor({
        id: id!, files, config, 
        updateStatus: (fid, stat, prog) => setFiles(prev => prev.map(f => f.id === fid ? {...f, status: stat as any, progress: prog} : f)),
        setCurrentMsg: setProgressMsg
      });

      if (results && 'type' in results && results.type === 'split-result') {
        setSplitResult(results);
      } else {
        setBatchResult(results as any[]);
      }
    } catch (e: any) {
      setError(e.message || "Pipeline failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return null;

  return (
    <div className="max-w-6xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      <Link to="/" className="inline-flex items-center gap-2 text-noir-text-muted hover:text-at-teal font-bold text-[11px] uppercase tracking-widest mb-12"><ArrowLeft className="w-4 h-4" /> Workspace</Link>
      <div className="text-center mb-16">
        <div className={`inline-flex p-6 rounded-[2rem] ${tool.color} text-white mb-8 shadow-xl`}>{tool.icon}</div>
        <h1 className="text-5xl font-black text-noir-text dark:text-noir-text-dark mb-4 tracking-tighter">{tool.name}</h1>
        <p className="text-lg text-noir-text-muted dark:text-noir-text-darkMuted max-w-2xl mx-auto">{tool.description}</p>
      </div>

      <div className="bg-noir-surface dark:bg-noir-surface-dark rounded-[3.5rem] border-2 border-dashed border-noir-text/10 p-10 shadow-sm">
        {files.length === 0 ? (
          <label className="cursor-pointer group flex flex-col items-center py-20">
            <div className="p-12 rounded-[2.5rem] mb-8 bg-noir-bg dark:bg-noir-surface-elevated group-hover:bg-at-teal/10 transition-all"><Upload className="w-12 h-12 text-noir-text-muted/30 group-hover:text-at-teal" /></div>
            <span className="bg-at-teal text-white px-12 py-5 rounded-2xl font-black text-lg shadow-lg">Load Fragments</span>
            <input type="file" multiple className="hidden" onChange={handleFileUpload} />
          </label>
        ) : (
          <div className="space-y-12">
            <div className="flex justify-between items-center border-b border-noir-bg pb-6">
               <h3 className="font-black text-2xl tracking-tight">{files.length} Fragments Loaded</h3>
               <button onClick={clearSession} className="text-at-amber font-black text-[10px] uppercase tracking-widest flex items-center gap-2"><RefreshCw className="w-4 h-4" /> Wipe Memory</button>
            </div>

            <div className="grid lg:grid-cols-3 gap-10">
              <div className="lg:col-span-2 space-y-6">
                {id === 'split-pdf' && pdfDoc && <SplitPanel config={config} setConfig={setConfig} pdfDoc={pdfDoc} numPages={numPages} />}
                {id === 'watermark-pdf' && <WatermarkPanel config={config} setConfig={setConfig} />}
                {id === 'protect-pdf' && <SecurityPanel config={config} setConfig={setConfig} />}
                {['ai-summarize', 'pdf-translate', 'ai-ocr'].includes(id!) && <AIConfigPanel config={config} setConfig={setConfig} id={id} />}
              </div>
              <div className="bg-noir-bg dark:bg-noir-surface-elevated p-6 rounded-3xl h-fit">
                <h4 className="text-[10px] font-black uppercase text-at-teal tracking-widest mb-4">Pipeline Status</h4>
                {files.map(f => (
                  <div key={f.id} className="flex items-center gap-3 mb-3">
                    <FileIcon className="w-4 h-4 text-at-teal" />
                    <span className="text-xs font-bold truncate flex-1">{f.file.name}</span>
                    {f.status === 'completed' && <CheckCircle2 className="w-4 h-4 text-green-500" />}
                  </div>
                ))}
              </div>
            </div>

            {(batchResult.length > 0 || splitResult) ? (
              <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="p-10 bg-noir-text dark:bg-noir-surface-elevated rounded-[2.5rem] text-white flex flex-col md:flex-row items-center justify-between gap-8">
                 <div className="text-left">
                   <h2 className="text-3xl font-black tracking-tighter mb-2">Synthesis Materialized</h2>
                   <p className="text-white/60 text-sm">Fragments are ready for local retrieval.</p>
                 </div>
                 <button className="bg-at-teal text-noir-bg-dark px-10 py-5 rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl flex items-center gap-2">
                   <Download className="w-5 h-5" /> Download Result
                 </button>
              </motion.div>
            ) : (
              <button disabled={isProcessing} onClick={startPipeline} className="w-full bg-at-teal py-8 rounded-[2rem] text-white font-black text-2xl shadow-xl flex items-center justify-center gap-4 hover:brightness-105 transition-all">
                {isProcessing ? <><Loader2 className="w-8 h-8 animate-spin" /> {progressMsg}</> : <><Zap className="w-8 h-8" /> Process Node</>}
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

