    watermarkColor: '#ff0000'
  });

  const clearSession = () => {
    setFiles([]); setPdfDoc(null); setBatchResult([]); setSplitResult(null); setError(null);
  };

  const handleFileUpload = async (e: any) => {
    const uploaded = Array.from(e.target?.files || e) as File[];
    const newFiles = uploaded.map(f => ({ id: Math.random().toString(36).substr(2,9), file: f, status: 'idle', progress: 0, originalSize: f.size } as FileState));
    setFiles(id === 'merge-pdf' || id === 'jpg-to-pdf' ? [...files, ...newFiles] : newFiles);

    if (newFiles[0]?.file.type === 'application/pdf') {
      const doc = await pdfjsLib.getDocument(await newFiles[0].file.arrayBuffer()).promise;
      setPdfDoc(doc);
      setNumPages(doc.numPages);
      setConfig({ ...config, selectedPages: Array.from({length: doc.numPages}, (_,i)=>i+1)});
    }
  };

  const startPipeline = async () => {
    setIsProcessing(true); setError(null);
    try {
      const results = await runToolProcessor({
        id: id!, files, config, 
        updateStatus: (fid, stat, prog) => setFiles(prev => prev.map(f => f.id === fid ? {...f, status: stat as any, progress: prog} : f)),
        setCurrentMsg: setProgressMsg
      });

      if (results && 'type' in results && results.type === 'split-result') {
        setSplitResult(results);
      } else {
        setBatchResult(results as any[]);
      }
    } catch (e: any) {
      setError(e.message || "Something went wrong. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  if (!tool) return null;

  return (
    <div className="max-w-6xl mx-auto px-4 py-16 animate-fade-in-up-soft">
      <Link to="/" className="inline-flex items-center gap-2 text-noir-text-muted hover:text-at-teal font-bold text-[11px] uppercase tracking-widest mb-12"><ArrowLeft className="w-4 h-4" /> Back to Home</Link>
      <div className="text-center mb-16">
        <div className={`inline-flex p-6 rounded-[2rem] ${tool.color} text-white mb-8 shadow-xl`}>{tool.icon}</div>
        <h1 className="text-5xl font-black text-noir-text dark:text-noir-text-dark mb-4 tracking-tighter">{tool.name}</h1>
        <p className="text-lg text-noir-text-muted dark:text-noir-text-darkMuted max-w-2xl mx-auto">{tool.description}</p>
      </div>

      <div className="bg-noir-surface dark:bg-noir-surface-dark rounded-[3.5rem] border-2 border-dashed border-noir-text/10 p-10 shadow-sm">
        {files.length === 0 ? (
          <label className="cursor-pointer group flex flex-col items-center py-20">
            <div className="p-12 rounded-[2.5rem] mb-8 bg-noir-bg dark:bg-noir-surface-elevated group-hover:bg-at-teal/10 transition-all"><Upload className="w-12 h-12 text-noir-text-muted/30 group-hover:text-at-teal" /></div>
            <span className="bg-at-teal text-white px-12 py-5 rounded-2xl font-black text-lg shadow-lg">Upload Files</span>
            <input type="file" multiple className="hidden" onChange={handleFileUpload} />
          </label>
        ) : (
          <div className="space-y-12">
            <div className="flex justify-between items-center border-b border-noir-bg pb-6">
               <h3 className="font-black text-2xl tracking-tight">{files.length} {files.length === 1 ? 'File' : 'Files'} Uploaded</h3>
               <button onClick={clearSession} className="text-at-amber font-black text-[10px] uppercase tracking-widest flex items-center gap-2"><RefreshCw className="w-4 h-4" /> Clear All</button>
            </div>

            <div className="grid lg:grid-cols-3 gap-10">
              <div className="lg:col-span-2 space-y-6">
                {id === 'split-pdf' && pdfDoc && <SplitPanel config={config} setConfig={setConfig} pdfDoc={pdfDoc} numPages={numPages} />}
                {id === 'watermark-pdf' && <WatermarkPanel config={config} setConfig={setConfig} />}
                {id === 'protect-pdf' && <SecurityPanel config={config} setConfig={setConfig} />}
                {['ai-summarize', 'pdf-translate', 'ai-ocr'].includes(id!) && <AIConfigPanel config={config} setConfig={setConfig} id={id} />}
              </div>
              <div className="bg-noir-bg dark:bg-noir-surface-elevated p-6 rounded-3xl h-fit">
                <h4 className="text-[10px] font-black uppercase text-at-teal tracking-widest mb-4">Processing Status</h4>
                {files.map(f => (
                  <div key={f.id} className="flex items-center gap-3 mb-3">
                    <FileIcon className="w-4 h-4 text-at-teal" />
                    <span className="text-xs font-bold truncate flex-1">{f.file.name}</span>
                    {f.status === 'completed' && <CheckCircle2 className="w-4 h-4 text-green-500" />}
                  </div>
                ))}
              </div>
            </div>

            {(batchResult.length > 0 || splitResult) ? (
              <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="p-10 bg-noir-text dark:bg-noir-surface-elevated rounded-[2.5rem] text-white flex flex-col md:flex-row items-center justify-between gap-8">
                 <div className="text-left">
                   <h2 className="text-3xl font-black tracking-tighter mb-2">Files are Ready</h2>
                   <p className="text-white/60 text-sm">Download your processed files below.</p>
                 </div>
                 <button className="bg-at-teal text-noir-bg-dark px-10 py-5 rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl flex items-center gap-2">
                   <Download className="w-5 h-5" /> Download Result
                 </button>
              </motion.div>
            ) : (
              <button disabled={isProcessing} onClick={startPipeline} className="w-full bg-at-teal py-8 rounded-[2rem] text-white font-black text-2xl shadow-xl flex items-center justify-center gap-4 hover:brightness-105 transition-all">
                {isProcessing ? <><Loader2 className="w-8 h-8 animate-spin" /> {progressMsg}</> : <><Zap className="w-8 h-8" /> Convert</>}
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import { PDFDocument, degrees, StandardFonts, rgb } from 'pdf-lib';
import * as pdfjsLib from 'pdfjs-dist';
import JSZip from 'jszip';
import { Document, Packer, Paragraph, TextRun, HeadingLevel } from 'docx';
import pptxgen from 'pptxgenjs';
import { reconstructAsWord, summarizeDocument, performOCR, translateText, scanBarcodes, extractTableData, extractJSON } from './geminiService';

export interface ProcessorParams {
  id: string;
  files: any[];
  config: any;
  updateStatus: (id: string, status: string, progress: number) => void;
  setCurrentMsg: (msg: string) => void;
}

const parseTextToDocxChildren = (text: string) => {
  const lines = text.split('\n');
  return lines.map(line => {
    const trimmed = line.trim();
    if (trimmed.startsWith('# ')) return new Paragraph({ text: trimmed.replace('# ', ''), heading: HeadingLevel.HEADING_1 });
    if (trimmed.startsWith('## ')) return new Paragraph({ text: trimmed.replace('## ', ''), heading: HeadingLevel.HEADING_2 });
    if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) return new Paragraph({ children: [new TextRun(trimmed.replace(/^[*|-]\s/, ''))], bullet: { level: 0 } });
    return new Paragraph({ children: [new TextRun(line)] });
  });
};

const hexToRgb = (hex: string) => {
  const r = parseInt(hex.slice(1, 3), 16) / 255;
  const g = parseInt(hex.slice(3, 5), 16) / 255;
  const b = parseInt(hex.slice(5, 7), 16) / 255;
  return rgb(r, g, b);
};

export const runToolProcessor = async (params: ProcessorParams) => {
  const { id, files, config, updateStatus, setCurrentMsg } = params;
  const results: any[] = [];

  // Handle Multi-file Merging Tools First
  if (id === 'merge-pdf') {
    setCurrentMsg("Merging files...");
    const mergedPdf = await PDFDocument.create();
    for (let i = 0; i < files.length; i++) {
      const f = files[i];
      updateStatus(f.id, 'processing', ((i + 1) / files.length) * 100);
      const donor = await PDFDocument.load(await f.file.arrayBuffer());
      const donorPages = await mergedPdf.copyPages(donor, donor.getPageIndices());
      donorPages.forEach(p => mergedPdf.addPage(p));
    }
    const bytes = await mergedPdf.save();
    const blob = new Blob([bytes], { type: 'application/pdf' });
    return [{ id: 'merged', name: 'merged.pdf', blob, url: URL.createObjectURL(blob) }];
  }

  if (id === 'jpg-to-pdf') {
    setCurrentMsg("Creating PDF...");
    const merged = await PDFDocument.create();
    for (let i = 0; i < files.length; i++) {
      const f = files[i];
      updateStatus(f.id, 'processing', ((i + 1) / files.length) * 100);
      const imgBytes = await f.file.arrayBuffer();
      const img = f.file.type === 'image/png' ? await merged.embedPng(imgBytes) : await merged.embedJpg(imgBytes);
      const page = merged.addPage([img.width, img.height]);
      page.drawImage(img, { x: 0, y: 0, width: img.width, height: img.height });
    }
    const bytes = await merged.save();
    const blob = new Blob([bytes], { type: 'application/pdf' });
    return [{ id: 'combined', name: 'combined.pdf', blob, url: URL.createObjectURL(blob) }];
  }

  // Handle Single-file Parallel Processing
  for (let i = 0; i < files.length; i++) {
    const f = files[i];
    setCurrentMsg(`Processing: ${f.file.name}`);
    updateStatus(f.id, 'processing', 20);
    const fileBuffer = await f.file.arrayBuffer();
    const base64 = btoa(new Uint8Array(fileBuffer).reduce((d, b) => d + String.fromCharCode(b), ''));

    let res: any = { id: f.id, name: f.file.name };

    switch (id) {
      case 'pdf-to-word':
        const wordText = await reconstructAsWord(base64, 'application/pdf');
        const docObj = new Document({ sections: [{ children: parseTextToDocxChildren(wordText) }] });
        const buffer = await Packer.toBuffer(docObj);
        res.blob = new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' });
        res.name = f.file.name.replace('.pdf', '.docx');
        break;

      case 'split-pdf':
        const splitSrc = await PDFDocument.load(fileBuffer);
        const pages: any[] = [];
        if (config.splitMode === 'individual') {
          for (const pNum of config.selectedPages) {
            const newPdf = await PDFDocument.create();
            const [copied] = await newPdf.copyPages(splitSrc, [pNum - 1]);
            newPdf.addPage(copied);
            const bytes = await newPdf.save();
            const blob = new Blob([bytes], { type: 'application/pdf' });
            pages.push({ pageNum: pNum, blob, url: URL.createObjectURL(blob) });
          }
          return { type: 'split-result', pages, name: f.file.name };
        } else {
          const newPdf = await PDFDocument.create();
          const copied = await newPdf.copyPages(splitSrc, config.selectedPages.map((p: number) => p - 1));
          copied.forEach(p => newPdf.addPage(p));
          const bytes = await newPdf.save();
          res.blob = new Blob([bytes], { type: 'application/pdf' });
          res.name = f.file.name.replace('.pdf', '_extracted.pdf');
        }
        break;

      case 'watermark-pdf':
        const wmDoc = await PDFDocument.load(fileBuffer);
        const wmPages = wmDoc.getPages();
        const font = await wmDoc.embedFont(StandardFonts.HelveticaBold);
        let embeddedImg: any = null;
        if (config.watermarkType === 'image' && config.watermarkImage) {
           const binary = atob(config.watermarkImage.split(',')[1]);
           const bytes = new Uint8Array(binary.length);
           for (let j = 0; j < binary.length; j++) bytes[j] = binary.charCodeAt(j);
           embeddedImg = config.watermarkImage.includes('image/png') ? await wmDoc.embedPng(bytes) : await wmDoc.embedJpg(bytes);
        }

        config.selectedPages.forEach((pIdx: number) => {
          const page = wmPages[pIdx - 1];
          const { width, height } = page.getSize();
          if (config.watermarkType === 'text') {
            const tw = font.widthOfTextAtSize(config.watermarkText, config.watermarkSize);
            page.drawText(config.watermarkText, {
              x: width / 2 - tw / 2, y: height / 2,
              size: config.watermarkSize, font, color: hexToRgb(config.watermarkColor),
              opacity: config.watermarkOpacity, rotate: degrees(config.watermarkRotation)
            });
          } else if (embeddedImg) {
            const scale = config.watermarkSize / 100;
            const iw = embeddedImg.width * scale;
            const ih = embeddedImg.height * scale;
            page.drawImage(embeddedImg, {
              x: width / 2 - iw / 2, y: height / 2 - ih / 2,
              width: iw, height: ih, opacity: config.watermarkOpacity, rotate: degrees(config.watermarkRotation)
            });
          }
        });
        const wmBytes = await wmDoc.save();
        res.blob = new Blob([wmBytes], { type: 'application/pdf' });
        res.name = f.file.name.replace('.pdf', '_watermarked.pdf');
        break;

      case 'ai-summarize':
        const summText = await performOCR(base64, 'application/pdf');
        const summary = await summarizeDocument(summText);
        res.blob = new Blob([summary], { type: 'text/markdown' });
        res.name = f.file.name.replace('.pdf', '_summary.md');
        break;

      case 'rotate-pdf':
        const rotDoc = await PDFDocument.load(fileBuffer);
        config.selectedPages.forEach((pIdx: number) => {
          const p = rotDoc.getPages()[pIdx - 1];
          p.setRotation(degrees((p.getRotation().angle + config.rotateAngle) % 360));
        });
        const rotBytes = await rotDoc.save();
        res.blob = new Blob([rotBytes], { type: 'application/pdf' });
        break;

      default:
        res.content = "Not supported yet.";
    }

    if (res.blob) res.url = URL.createObjectURL(res.blob);
    results.push(res);
    updateStatus(f.id, 'completed', 100);
  }

  return results;
};

import React, { useRef, useEffect } from 'react';
