import React, { useState, useEffect, useRef } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Layers, Menu, X, ChevronDown, 
  FileImage, Sun, Moon, ShieldCheck, Cpu
} from 'lucide-react';

export const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [activeMenu, setActiveMenu] = useState<'convert' | 'all' | null>(null);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return document.documentElement.classList.contains('dark') ? 'dark' : 'light';
    }
    return 'light';
  });
  const menuRef = useRef<HTMLDivElement>(null);
  const location = useLocation();

  useEffect(() => {
    window.scrollTo({ top: 0, left: 0, behavior: 'instant' });
  }, [location.pathname]);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setActiveMenu(null);
      }
    };
    window.addEventListener('scroll', handleScroll);
    window.addEventListener('click', handleClickOutside);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('click', handleClickOutside);
    };
  }, []);

  useEffect(() => {
    setActiveMenu(null);
    setIsMobileMenuOpen(false);
  }, [location.pathname]);

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    if (newTheme === 'dark') {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  };

  const DropdownItem = ({ to, label, icon: Icon }: { to: string, label: string, icon: any }) => (
    <Link 
      to={to} 
      className="flex items-center gap-4 px-5 py-4 rounded-2xl hover:bg-at-teal/10 transition-all group/item anime-card-hover"
    >
      <div className="text-noir-text-muted dark:text-noir-text-darkMuted group-hover/item:text-at-teal dark:group-hover/item:text-at-teal-dark group-hover/item:scale-110 transition-all">
        <Icon className="w-6 h-6 stroke-[1.5]" />
      </div>
      <span className="text-[14px] font-black text-noir-text dark:text-noir-text-dark leading-tight">{label}</span>
    </Link>
  );

  const NavButton = ({ label, to, onClick, isActive, hasChevron }: { label: string, to?: string, onClick?: (e: React.MouseEvent) => void, isActive?: boolean, hasChevron?: boolean }) => {
    const content = (
      <button
        onClick={onClick}
        className={`relative flex items-center gap-2 px-4 py-2.5 text-[12px] font-black uppercase tracking-[0.2em] transition-all group ${
          isActive ? 'text-at-teal' : 'text-noir-text dark:text-noir-text-dark hover:text-at-teal'
        }`}
      >
        {label}
        {hasChevron && <ChevronDown className={`w-4 h-4 transition-transform duration-500 ${isActive ? 'rotate-180' : ''}`} />}
        <motion.span 
          initial={false}
          animate={{ width: isActive ? '100%' : '0%' }}
          className="absolute bottom-0 left-0 h-[3px] bg-at-teal rounded-full" 
        />
        {!isActive && <span className="absolute bottom-0 left-0 h-[3px] bg-at-teal/20 w-0 group-hover:w-full transition-all rounded-full" />}
      </button>
    );
    return to ? <Link to={to}>{content}</Link> : content;
  };

  return (
    <div className="min-h-screen flex flex-col selection:bg-at-teal selection:text-white dark:bg-noir-bg-dark font-sans">
      <header 
        ref={menuRef}
        className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-500 ${
          scrolled 
          ? 'bg-white/90 dark:bg-noir-bg-dark/90 backdrop-blur-xl border-b-2 border-noir-bg dark:border-noir-surface-elevated py-3' 
          : 'bg-transparent py-6'
        }`}
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between">
            <Link to="/" className="flex items-center gap-3 group shrink-0 active:scale-95 transition-all">
              <div className="bg-noir-text dark:bg-at-teal-dark p-2.5 rounded-2xl group-hover:rotate-12 transition-all noir-glow-teal">
                <Layers className="text-white dark:text-noir-bg-dark w-6 h-6" />
              </div>
              <span className="text-2xl font-black text-noir-text dark:text-noir-text-dark tracking-tighter">Unbound</span>
            </Link>

            <nav className="hidden lg:flex items-center gap-6">
              <NavButton label="MERGE" to="/tool/merge-pdf" />
              <NavButton label="SPLIT" to="/tool/split-pdf" />
              <NavButton label="COMPRESS" to="/tool/compress-pdf" />
              <div className="relative">
                <NavButton 
                  label="CONVERT" 
                  hasChevron 
                  isActive={activeMenu === 'convert'} 
                  onClick={(e) => {
                    e.stopPropagation();
                    setActiveMenu(activeMenu === 'convert' ? null : 'convert');
                  }} 
                />
                <AnimatePresence>
                  {activeMenu === 'convert' && (
                    <motion.div 
                      initial={{ opacity: 0, y: 10, scale: 0.95 }}
                      animate={{ opacity: 1, y: 0, scale: 1 }}
                      exit={{ opacity: 0, y: 10, scale: 0.95 }}
                      className="absolute top-full left-1/2 -translate-x-1/2 mt-6 w-[320px] glass-panel border-2 border-noir-bg dark:border-noir-surface-elevated shadow-[0_20px_50px_rgba(0,0,0,0.15)] rounded-[2.5rem] p-8 z-[110]"
                    >
                      <div className="space-y-1">
                        <div className="text-[11px] font-black text-at-teal uppercase tracking-[0.3em] mb-4 pl-5">Image Processing</div>
                        <DropdownItem to="/tool/jpg-to-pdf" label="Image to PDF" icon={FileImage} />
                        <DropdownItem to="/tool/pdf-to-jpg" label="PDF to Image" icon={FileImage} />
