                <ShieldCheck className="w-4 h-4 text-at-teal" />
                <span className="text-[10px] font-black uppercase tracking-[0.2em] text-at-teal">Secure Sync</span>
              </div>
              <button 
                onClick={toggleTheme}
                className="p-3 rounded-2xl text-noir-text dark:text-noir-text-dark hover:bg-at-teal/10 transition-all group active:scale-90"
              >
                {theme === 'light' ? <Moon className="w-6 h-6 group-hover:-rotate-12 transition-all" /> : <Sun className="w-6 h-6 group-hover:rotate-12 transition-all" />}
              </button>
              <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="lg:hidden text-noir-text dark:text-noir-text-dark p-2.5 rounded-2xl transition-all">
                {isMobileMenuOpen ? <X className="w-7 h-7" /> : <Menu className="w-7 h-7" />}
              </button>
            </div>
          </div>
        </div>
      </header>
      <div className="h-[90px]" />
      <main className="flex-grow">{children}</main>
