  const handleDownload = async () => {
    if (splitResult) {
      const zip = new JSZip();
      const folder = zip.folder("extracted_pages");
      splitResult.pages.forEach((p: any) => {
        folder?.file(`page_${p.pageNum}.pdf`, p.blob);
      });
      const content = await zip.generateAsync({ type: 'blob' });
