export const PageThumbnail: React.FC<{ 
  pdfDoc: any; 
  pageNum: number; 
  isSelected?: boolean;
  onToggle?: () => void;
}> = ({ pdfDoc, pageNum, isSelected, onToggle }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    let isMounted = true;
    const render = async () => {
      const page = await pdfDoc.getPage(pageNum);
      const vp = page.getViewport({ scale: 0.25 });
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.height = vp.height; canvas.width = vp.width;
      if (isMounted) await page.render({ canvasContext: ctx, viewport: vp, canvas }).promise;
    };
    render();
    return () => { isMounted = false; };
  }, [pdfDoc, pageNum]);

  return (
    <div onClick={onToggle} className={`relative cursor-pointer rounded-xl overflow-hidden border-2 transition-all ${isSelected ? 'border-theme-primary ring-2 ring-theme-primary/20' : 'border-transparent hover:border-theme-primary/20'}`}>
       <canvas ref={canvasRef} className="w-full h-auto" />
       {isSelected && <div className="absolute top-2 right-2 bg-theme-primary text-theme-bg p-1 rounded-full"><CheckCircle2 className="w-3 h-3" /></div>}
       <div className="bg-theme-bg/50 py-1 text-[9px] font-black text-center text-theme-text">Page {pageNum}</div>
    </div>
  );
};

