  const clearSession = () => {
    setFiles([]); setPdfDoc(null); setBatchResult([]); setSplitResult(null); setError(null);
  };

  const removeFile = (fid: string) => {
    setFiles(prev => {
      const filtered = prev.filter(f => f.id !== fid);
      if (filtered.length === 0) clearSession();
      return filtered;
    });
